JOURNALINSTANCE = {
    [63] = {"The Deadmines", "It is said that the treasury of Stormwind was once filled a third over from the riches mined in the Deadmines, but after the terrible events of the First War the mine was abandoned. For many years thieves gave it a wide berth, frightened by rumors of ghosts, until at last these dark labyrinths were seized by the Defias Brotherhood - a band of former laborers who chose to turn to a life of crime. They turned the mine into a base for carrying out subversive operations against Stormwind.", "interface\\encounterjournal\\ui-ej-dungeonbutton-deadmines.blp", "interface\\lfgframe\\lfgicon-deadmines.blp", "interface\\encounterjournal\\ui-ej-background-deadmines.blp", "interface\\encounterjournal\\ui-ej-lorebg-deadmines.blp", 36, 1581, 9, 0, 63, 886},
    [64] = {"Shadowfang Keep", "On the southern slopes of Silverpine Forest rises Shadowfang Keep, casting a grim shadow over the village of Pyrewood. Evil roams among the ruins, which serve as a refuge for the mad mage Arugal and his worgen. The restless souls of Baron Silverlaine and Commander Springvale thirst for vengeance for the seizure of the keep and the slaughter of their people.", "interface\\encounterjournal\\ui-ej-dungeonbutton-shadowfangkeep.blp", "interface\\lfgframe\\lfgicon-shadowfangkeep.blp", "interface\\encounterjournal\\ui-ej-background-shadowfangkeep.blp", "interface\\encounterjournal\\ui-ej-lorebg-shadowfangkeep.blp", 33, 0, 5, 0, 64, 891},
    [76] = {"Zul'Gurub", "Zul'Gurub was once the capital of the Gurubashi tribe, who reigned unchallenged in the boundless southern jungles. It was here that the Hexxer Jin'do summoned into Azeroth the cruel and bloodthirsty spirit - Hakkar the Soulflayer. And of late this place has become the center of a new alliance between the Zandalari and the Gurubashi, who dream of recreating a unified troll empire.", "interface\\encounterjournal\\ui-ej-dungeonbutton-zulgurub.blp", "interface\\lfgframe\\lfgicon-zulgurub.blp", "interface\\encounterjournal\\ui-ej-background-zulgurub.blp", "interface\\encounterjournal\\ui-ej-lorebg-zulgurub.blp", 309, 0, 3, 16, 76, 0},
    [77] = {"Zul'Aman", "The echoes of an old enmity can still be heard in the ancient capital of the Amani tribe, Zul'Aman. The trolls of the tribe answered the call of their warlord, and now Zul'jin is on his way to restoring the empire's former glory. The trolls of the united tribes thirst to reclaim their lands and avenge old grievances.", "interface\\encounterjournal\\ui-ej-dungeonbutton-zulaman.blp", "interface\\lfgframe\\lfgicon-zulaman.blp", "interface\\encounterjournal\\ui-ej-background-zulaman.blp", "interface\\encounterjournal\\ui-ej-lorebg-zulaman.blp", 568, 3508, 4, 16, 77, 866},
    [227] = {"Blackfathom Deeps", "Blackfathom Deeps, a shrine to the night elf goddess Elune, was long thought lost. According to rumor, the Great Sundering destroyed the temple and it sank into the depths of the sea. After many centuries, members of the Twilight's Hammer cult, driven to madness by nightmares and ghostly voices, came to this place. They sacrificed countless innocent souls, and their reward was a new task: to guard one of the most precious creations of the Old Gods until it gathers strength and unleashes its dark might upon the world.", "interface\\encounterjournal\\ui-ej-dungeonbutton-blackfathomdeeps.blp", "interface\\lfgframe\\lfgicon-blackfathomdeeps.blp", "interface\\encounterjournal\\ui-ej-background-blackfathomdeeps.blp", "interface\\encounterjournal\\ui-ej-lorebg-blackfathomdeeps.blp", 48, 0, 15, 0, 227, 873},
    [228] = {"Blackrock Depths", "Blackrock Depths is home to the Dark Iron dwarves, led by Emperor Dagran Thaurissan. Like his predecessors, Dagran serves the relentless lord of flame Ragnaros, who was summoned into this world hundreds of years ago. The mighty and unpredictable fire elementals have drawn the servants of the Twilight's Hammer cult to this mountain realm. Now, together with the servants of Ragnaros, they draw the dwarves into ever more dangerous ventures, capable of dooming all of Azeroth to destruction.", "interface\\encounterjournal\\ui-ej-dungeonbutton-blackrockdepths.blp", "interface\\lfgframe\\lfgicon-blackrockdepths.blp", "interface\\encounterjournal\\ui-ej-background-blackrockdepths.blp", "interface\\encounterjournal\\ui-ej-lorebg-blackrockdepths.blp", 230, 0, 1, 0, 228, 880},
    [229] = {"Lower Blackrock Spire", "A stunning fortress carved into the fiery heart of Blackrock Mountain, it served for centuries as a model of the Dark Iron clan's might. But not long ago the black dragon Nefarian and his brood seized the upper tiers of the fortress and unleashed a brutal war against the dwarves. The dragons' armies found an ally in Warchief Rend Blackhand and his 'Horde', and now their combined forces hold sway over Blackrock Spire, conducting experiments meant to swell their ranks and plotting the destruction of the Dark Iron dwarves.", "interface\\encounterjournal\\ui-ej-dungeonbutton-blackrockspire.blp", "interface\\lfgframe\\lfgicon-blackrockspire.blp", "interface\\encounterjournal\\ui-ej-background-blackrockspire.blp", "interface\\encounterjournal\\ui-ej-lorebg-blackrockspire.blp", 229, 0, 16, 0, 229, 882},
    [230] = {"Dire Maul", "Once the great city of Eldre'Thalas, which guarded many secrets of the Kaldorei, was destroyed. Now it has become an abode of dark, malevolent forces. An uneasy peace has settled between the warring clans that once fought to the death for control of the energy of Dire Maul. Now they must content themselves with the sources of power within their own territories, and are in no hurry to seize the whole city.", "interface\\encounterjournal\\ui-ej-dungeonbutton-diremaul.blp", "interface\\lfgframe\\lfgicon-diremaul.blp", "interface\\encounterjournal\\ui-ej-background-diremaul.blp", "interface\\encounterjournal\\ui-ej-lorebg-diremaul.blp", 429, 0, 3, 0, 230, 879},
    [231] = {"Gnomeregan", "The city of Gnomeregan, built deep within Dun Morogh, was a vivid testament to the wit and ingenuity of the gnomes. But when troggs invaded the capital, Sicco Thermaplugg betrayed the High Tinker, and Gnomeregan was exposed to radiation, killing most of its inhabitants. The surviving gnomes fled in haste, but vowed to return - and to reclaim their home.", "interface\\encounterjournal\\ui-ej-dungeonbutton-gnomeregan.blp", "interface\\lfgframe\\lfgicon-gnomeregan.blp", "interface\\encounterjournal\\ui-ej-background-gnomeregan.blp", "interface\\encounterjournal\\ui-ej-lorebg-gnomeregan.blp", 90, 0, 2, 0, 231, 875},
    [232] = {"Maraudon", "Legend says that the savage race of centaurs traces its origins to Zaetar, son of Cenarius, and Theradras, princess of the earth elementals. No sooner had these merciless creatures come into the world than they slew their own father. It is said that Theradras, maddened by grief, imprisoned her beloved's soul within Maraudon, and that after this event corruption consumed the cavern. Now these caverns are filled to the brim with malevolent centaur spirits and ferocious elementals.", "interface\\encounterjournal\\ui-ej-dungeonbutton-maraudon.blp", "interface\\lfgframe\\lfgicon-maraudon.blp", "interface\\encounterjournal\\ui-ej-background-maraudon.blp", "interface\\encounterjournal\\ui-ej-lorebg-maraudon.blp", 349, 0, 8, 0, 232, 884},
    [233] = {"Razorfen Kraul", "According to legend, where the demigod Agamaggan fell, thorny vines grew from his blood. Of late, scouts have repeatedly encountered the undead in these lands, and there are fears that the Scourge intends to invade Kalimdor.", "interface\\encounterjournal\\ui-ej-dungeonbutton-razorfendowns.blp", "interface\\lfgframe\\lfgicon-razorfendowns.blp", "interface\\encounterjournal\\ui-ej-background-razorfendowns.blp", "interface\\encounterjournal\\ui-ej-lorebg-razorfendowns.blp", 129, 0, 6, 0, 233, 887},
    [234] = {"Razorfen Downs", "According to legend, where the demigod Agamaggan fell, thorny vines grew from his blood. Within the vastest tangle of giant vines, quilboar have settled. They call themselves the Razorfen, and revere Agamaggan's final resting place as a sacred site.", "interface\\encounterjournal\\ui-ej-dungeonbutton-razorfenkraul.blp", "interface\\lfgframe\\lfgicon-razorfenkraul.blp", "interface\\encounterjournal\\ui-ej-background-razorfenkraul.blp", "interface\\encounterjournal\\ui-ej-lorebg-razorfenkraul.blp", 47, 0, 7, 0, 234, 888},
    [236] = {"Stratholme", "Stratholme was a true jewel of northern Lordaeron, but now all remember only its devastating fall. It was here that Prince Arthas once disobeyed his mentor, the noble paladin Uther the Lightbringer, and slaughtered hundreds of townsfolk supposedly infected with the plague of undeath. Since then death, betrayal, and despair have reigned in the city.", "interface\\encounterjournal\\ui-ej-dungeonbutton-stratholme.blp", "interface\\lfgframe\\lfgicon-stratholme.blp", "interface\\encounterjournal\\ui-ej-background-stratholme.blp", "interface\\encounterjournal\\ui-ej-lorebg-stratholme.blp", 329, 0, 19, 0, 236, 892},
    [237] = {"The Temple of Atal'Hakkar", "Thousands of years ago the Gurubashi empire was mired in civil war, started by a sect of priests - the Atal'ai, who wished to summon into Azeroth an avatar of the blood god Hakkar the Soulflayer, whom they worshipped. The Gurubashi exiled the Atal'ai to the Swamp of Sorrows, where they built the Temple of Atal'Hakkar. Ysera, Aspect of the green dragonflight, sank the temple into the swamp and left guardians there, charged with ensuring that the summoning rituals would never be repeated.", "interface\\encounterjournal\\ui-ej-dungeonbutton-sunkentemple.blp", "interface\\lfgframe\\lfgicon-sunkentemple.blp", "interface\\encounterjournal\\ui-ej-background-sunkentemple.blp", "interface\\encounterjournal\\ui-ej-lorebg-sunkentemple.blp", 109, 0, 22, 0, 237, 687},
    [238] = {"The Stockade", "Deep beneath the sewers of Stormwind lies a maximum-security prison. Order in this cesspit, full of dangerous repeat offenders, is kept by warden Thelwater. Quite recently the prisoners staged a riot and dealt with the guards. Since then, utter hell has reigned in the underground prison.", "interface\\encounterjournal\\ui-ej-dungeonbutton-thestockade.blp", "interface\\lfgframe\\lfgicon-stormwindstockades.blp", "interface\\encounterjournal\\ui-ej-background-thestockade.blp", "interface\\encounterjournal\\ui-ej-lorebg-thestockade.blp", 34, 0, 20, 0, 238, 874},
    [239] = {"Uldaman", "Uldaman is an ancient underground vault of the titans. It is said they wished to conduct an experiment there, but it failed, and so the titans abandoned the city and began work on a new project related to the origin of the dwarves. Rumors of untold riches containing secret knowledge have drawn treasure hunters into the depths of Uldaman. But uncovering its secrets is no easy task - Uldaman is guarded by stone keepers, wild troggs, and Dark Iron invaders. Other dangers also lie in wait for the traveler in the forgotten city...", "interface\\encounterjournal\\ui-ej-dungeonbutton-uldaman.blp", "interface\\lfgframe\\lfgicon-uldaman.blp", "interface\\encounterjournal\\ui-ej-background-uldaman.blp", "interface\\encounterjournal\\ui-ej-lorebg-uldaman.blp", 70, 0, 21, 0, 239, 876},
    [240] = {"Wailing Caverns", "Many years ago the renowned night elf druid Naralex descended into the dark Wailing Caverns with his companions. The caverns owe their name to the weeping sounds that accompany the steam escaping to the surface. He intended to use the underground springs to restore the Barrens to their former fertility, but no sooner had he plunged into the Emerald Dream than his beautiful vision turned into a horrific nightmare. Since that very time a terrible curse has hung over this place.", "interface\\encounterjournal\\ui-ej-dungeonbutton-wailingcaverns.blp", "interface\\lfgframe\\lfgicon-wailingcaverns.blp", "interface\\encounterjournal\\ui-ej-background-wailingcaverns.blp", "interface\\encounterjournal\\ui-ej-lorebg-wailingcaverns.blp", 43, 0, 18, 0, 240, 749},
    [241] = {"Zul'Farrak", "The Sandfury tribe zealously guarded Zul'Farrak, once the jewel of Tanaris. But their zeal did not save them, and gradually most of the lands had to be ceded to conquerors. Now the inhabitants of Zul'Farrak labor to create a monstrous army of dead trolls, which is to seize the surrounding territories. And it is also said that deep within the city an ancient being slumbers - and if it awakens, a rain of blood will pour over Tanaris.", "interface\\encounterjournal\\ui-ej-dungeonbutton-zulfarrak.blp", "interface\\lfgframe\\lfgicon-zulfarak.blp", "interface\\encounterjournal\\ui-ej-background-zulfarrak.blp", "interface\\encounterjournal\\ui-ej-lorebg-zulfarrak.blp", 209, 0, 4, 0, 241, 871},
    [247] = {"Auchenai Crypts", "To the draenei exiles, death seemed an unpleasant and unseemly consequence of life. And so the draenei concealed their dead in the underground necropolis of Auchindoun. This labyrinth of wonders sprawls beneath the very Terokkar Forest.", "interface\\encounterjournal\\ui-ej-dungeonbutton-auchindoun.blp", "interface\\lfgframe\\lfgicon-auchindoun.blp", "interface\\encounterjournal\\ui-ej-background-auchindoun.blp", "interface\\encounterjournal\\ui-ej-lorebg-auchindoun.blp", 558, 0, 2, 0, 247, 722},
    [248] = {"Hellfire Ramparts", "The nearly impregnable Hellfire Citadel, located in the very center of the peninsula of the same name in Outland, served as a staging ground for the Horde's forces during the First and Second Wars.", "interface\\encounterjournal\\ui-ej-dungeonbutton-hellfirecitadel.blp", "interface\\lfgframe\\lfgicon-hellfirecitadel.blp", "interface\\encounterjournal\\ui-ej-background-hellfirecitadel.blp", "interface\\encounterjournal\\ui-ej-lorebg-hellfirecitadel.blp", 543, 0, 3, 0, 248, 848},
    [250] = {"The Mana-Tombs", "To the draenei exiles, death seemed an unpleasant and unseemly consequence of life. And so the draenei concealed their dead in the underground necropolis of Auchindoun. This labyrinth of wonders sprawls beneath the very Terokkar Forest.", "interface\\encounterjournal\\ui-ej-dungeonbutton-auchindoun.blp", "interface\\lfgframe\\lfgicon-auchindoun.blp", "interface\\encounterjournal\\ui-ej-background-auchindoun.blp", "interface\\encounterjournal\\ui-ej-lorebg-auchindoun.blp", 557, 0, 5, 1, 250, 842},
    [252] = {"Sethekk Halls", "To the draenei exiles, death seemed an unpleasant and unseemly consequence of life. And so the draenei concealed their dead in the underground necropolis of Auchindoun. This labyrinth of wonders sprawls beneath the very Terokkar Forest.", "interface\\encounterjournal\\ui-ej-dungeonbutton-auchindoun.blp", "interface\\lfgframe\\lfgicon-auchindoun.blp", "interface\\encounterjournal\\ui-ej-background-auchindoun.blp", "interface\\encounterjournal\\ui-ej-lorebg-auchindoun.blp", 556, 0, 11, 0, 252, 833},
    [253] = {"Shadow Labyrinth", "To the draenei exiles, death seemed an unpleasant and unseemly consequence of life. And so the draenei concealed their dead in the underground necropolis of Auchindoun. This labyrinth of wonders sprawls beneath the very Terokkar Forest.", "interface\\encounterjournal\\ui-ej-dungeonbutton-auchindoun.blp", "interface\\lfgframe\\lfgicon-auchindoun.blp", "interface\\encounterjournal\\ui-ej-background-auchindoun.blp", "interface\\encounterjournal\\ui-ej-lorebg-auchindoun.blp", 555, 0, 13, 0, 253, 834},
    [254] = {"The Arcatraz", "The mighty Tempest Keep was built by the mysterious naaru: sentient beings of pure energy and the sworn enemies of the Burning Legion. This fortress not only serves as a naaru stronghold, but is also equipped with technology for crossing into other dimensions, allowing it to move to a new location in the blink of an eye.", "interface\\encounterjournal\\ui-ej-dungeonbutton-tempestkeep.blp", "interface\\lfgframe\\lfgicon-tempestkeep.blp", "interface\\encounterjournal\\ui-ej-background-tempestkeep.blp", "interface\\encounterjournal\\ui-ej-lorebg-tempestkeep.blp", 552, 0, 1, 1, 254, 841},
    [256] = {"The Blood Furnace", "The nearly impregnable Hellfire Citadel, located in the very center of the peninsula of the same name in Outland, served as a staging ground for the Horde's forces during the First and Second Wars.", "interface\\encounterjournal\\ui-ej-dungeonbutton-hellfirecitadel.blp", "interface\\lfgframe\\lfgicon-hellfirecitadel.blp", "interface\\encounterjournal\\ui-ej-background-hellfirecitadel.blp", "interface\\encounterjournal\\ui-ej-lorebg-hellfirecitadel.blp", 542, 0, 6, 0, 256, 835},
    [257] = {"The Botanica", "The mighty Tempest Keep was built by the mysterious naaru: sentient beings of pure energy and the sworn enemies of the Burning Legion. This fortress not only serves as a naaru stronghold, but is also equipped with technology for crossing into other dimensions, allowing it to move to a new location in the blink of an eye.", "interface\\encounterjournal\\ui-ej-dungeonbutton-tempestkeep.blp", "interface\\lfgframe\\lfgicon-tempestkeep.blp", "interface\\encounterjournal\\ui-ej-background-tempestkeep.blp", "interface\\encounterjournal\\ui-ej-lorebg-tempestkeep.blp", 553, 0, 4, 0, 257, 839},
    [258] = {"The Mechanar", "The mighty Tempest Keep was built by the mysterious naaru: sentient beings of pure energy and the sworn enemies of the Burning Legion. This fortress not only serves as a naaru stronghold, but is also equipped with technology for crossing into other dimensions, allowing it to move to a new location in the blink of an eye.", "interface\\encounterjournal\\ui-ej-dungeonbutton-tempestkeep.blp", "interface\\lfgframe\\lfgicon-tempestkeep.blp", "interface\\encounterjournal\\ui-ej-background-tempestkeep.blp", "interface\\encounterjournal\\ui-ej-lorebg-tempestkeep.blp", 554, 0, 7, 0, 258, 840},
    [259] = {"The Shattered Halls", "The nearly impregnable Hellfire Citadel, located in the very center of the peninsula of the same name in Outland, served as a staging ground for the Horde's forces during the First and Second Wars.", "interface\\encounterjournal\\ui-ej-dungeonbutton-hellfirecitadel.blp", "interface\\lfgframe\\lfgicon-hellfirecitadel.blp", "interface\\encounterjournal\\ui-ej-background-hellfirecitadel.blp", "interface\\encounterjournal\\ui-ej-lorebg-hellfirecitadel.blp", 540, 0, 10, 1, 259, 843},
    [260] = {"The Underbog", "Deep within Zangarmarsh lies the captured Coilfang Reservoir, ruled by the naga. This reservoir, with its gigantic pipes and valves, would seem capable of holding armies, but its purpose is not military at all.", "interface\\encounterjournal\\ui-ej-dungeonbutton-coilfangreservoir.blp", "interface\\lfgframe\\lfgicon-coilfang.blp", "interface\\encounterjournal\\ui-ej-background-coilfangreservoir.blp", "interface\\encounterjournal\\ui-ej-lorebg-coilfangreservoir.blp", 547, 0, 15, 1, 260, 838},
    [261] = {"The Steamvault", "Deep within Zangarmarsh lies the captured Coilfang Reservoir, ruled by the naga. This reservoir, with its gigantic pipes and valves, would seem capable of holding armies, but its purpose is not military at all.", "interface\\encounterjournal\\ui-ej-dungeonbutton-coilfangreservoir.blp", "interface\\lfgframe\\lfgicon-coilfang.blp", "interface\\encounterjournal\\ui-ej-background-coilfangreservoir.blp", "interface\\encounterjournal\\ui-ej-lorebg-coilfangreservoir.blp", 545, 0, 9, 0, 261, 837},
    [262] = {"The Slave Pens", "Deep within Zangarmarsh lies the captured Coilfang Reservoir, ruled by the naga. This reservoir, with its gigantic pipes and valves, would seem capable of holding armies, but its purpose is not military at all.", "interface\\encounterjournal\\ui-ej-dungeonbutton-coilfangreservoir.blp", "interface\\lfgframe\\lfgicon-coilfang.blp", "interface\\encounterjournal\\ui-ej-background-coilfangreservoir.blp", "interface\\encounterjournal\\ui-ej-lorebg-coilfangreservoir.blp", 546, 0, 8, 0, 262, 836},
    [271] = {"Ahn'kahet: The Old Kingdom", "The empire of Azjol-Nerub was at the height of its power when the armies of the Lich King arrived in Northrend. Despite fierce resistance, the forces of the Scourge managed to seize the underground realm and slaughter its inhabitants, the nerubians. Scorched by years of war and left desolate, the vast empire is divided into two fronts.", "interface\\encounterjournal\\ui-ej-dungeonbutton-ahnkahettheoldkingdom.blp", "interface\\lfgframe\\lfgicon-ahnkalet.blp", "interface\\encounterjournal\\ui-ej-background-ahnkahettheoldkingdom.blp", "interface\\encounterjournal\\ui-ej-lorebg-ahnkahettheoldkingdom.blp", 619, 0, 3, 1, 271, 522},
    [272] = {"Azjol-Nerub", "The empire of Azjol-Nerub was at the height of its power when the armies of the Lich King arrived in Northrend. Despite fierce resistance, the forces of the Scourge managed to seize the underground realm and slaughter its inhabitants, the nerubians. Scorched by years of war and left desolate, the vast empire is divided into two fronts.", "interface\\encounterjournal\\ui-ej-dungeonbutton-azjolnerub.blp", "interface\\lfgframe\\lfgicon-azjolnerub.blp", "interface\\encounterjournal\\ui-ej-background-azjolnerub.blp", "interface\\encounterjournal\\ui-ej-lorebg-azjolnerub.blp", 601, 0, 3, 0, 272, 533},
    [273] = {"Drak'Tharon Keep", "Drak'Tharon Keep, located on the edge of the kingdom of Zul'Drak, once served as a powerful outpost of the Drakkari. But as a result of the Scourge's invasion, the keep fell under the power of the Lich King. Its fallen defenders were raised into undeath. Now they push deeper into the lands of the Drakkari.", "interface\\encounterjournal\\ui-ej-dungeonbutton-draktharonkeep.blp", "interface\\lfgframe\\lfgicon-draktharon.blp", "interface\\encounterjournal\\ui-ej-background-draktharonkeep.blp", "interface\\encounterjournal\\ui-ej-lorebg-draktharonkeep.blp", 600, 0, 8, 0, 273, 534},
    [274] = {"Gundrak", "The trolls of Zul'Drak needed at all costs to save their kingdom from destruction, and so they rose up against their Old Gods. The deities of the wild became sources of inexhaustible power, and their blood became the chief weapon against the army of the Lich King, in whose ranks trolls also stood. Heroes have already set out into these troubled lands to battle the savage Drakkari and their mad prophets.", "interface\\encounterjournal\\ui-ej-dungeonbutton-gundrak.blp", "interface\\lfgframe\\lfgicon-gundrak.blp", "interface\\encounterjournal\\ui-ej-background-gundrak.blp", "interface\\encounterjournal\\ui-ej-lorebg-gundrak.blp", 604, 0, 5, 1, 274, 530},
    [275] = {"Halls of Lightning", "As they departed Azeroth, the titans entrusted the protection of Ulduar, the mysterious city hidden among the peaks of the Storm Peaks, to their finest defenders. The first among his brethren was named the keeper Loken, but upon realizing the power the titans had left behind, he succumbed to darkness and plunged the city into the abyss of chaos.", "interface\\encounterjournal\\ui-ej-dungeonbutton-hallsoflightning.blp", "interface\\lfgframe\\lfgicon-hallsoflightning.blp", "interface\\encounterjournal\\ui-ej-background-hallsoflightning.blp", "interface\\encounterjournal\\ui-ej-lorebg-hallsoflightning.blp", 602, 0, 15, 1, 275, 525},
    [276] = {"Halls of Reflection", "The confrontation between the defenders of Azeroth and the army of the Lich King has continued for long years. In that time many heroes have fallen, and after death they were forced to join the monstrous army of undead. In the course of this tireless struggle, Tirion Fordring of the Argent Vanguard joined forces with the Knights of the Ebon Blade under the command of Darion Mograine. Now this united army, known as the Ashen Verdict, prepares to storm Icecrown Citadel.", "interface\\encounterjournal\\ui-ej-dungeonbutton-hallsofreflection.blp", "interface\\lfgframe\\lfgicon-hallsofreflection.blp", "interface\\encounterjournal\\ui-ej-background-hallsofreflection.blp", "interface\\encounterjournal\\ui-ej-lorebg-hallsofreflection.blp", 668, 0, 6, 0, 276, 603},
    [277] = {"Halls of Stone", "As they departed Azeroth, the titans entrusted the protection of Ulduar, the mysterious city hidden among the peaks of the Storm Peaks, to their finest defenders. The first among his brethren was named the keeper Loken, but upon realizing the power the titans had left behind, he succumbed to darkness and plunged the city into the abyss of chaos.", "interface\\encounterjournal\\ui-ej-dungeonbutton-hallsofstone.blp", "interface\\lfgframe\\lfgicon-hallsofstone.blp", "interface\\encounterjournal\\ui-ej-background-hallsofstone.blp", "interface\\encounterjournal\\ui-ej-lorebg-hallsofstone.blp", 599, 0, 14, 0, 277, 526},
    [278] = {"The Pit of Saron", "The confrontation between the defenders of Azeroth and the army of the Lich King has continued for long years. In that time many heroes have fallen, and after death they were forced to join the monstrous army of undead. In the course of this tireless struggle, Tirion Fordring of the Argent Vanguard joined forces with the Knights of the Ebon Blade under the command of Darion Mograine. Now this united army, known as the Ashen Verdict, prepares to storm Icecrown Citadel.", "interface\\encounterjournal\\ui-ej-dungeonbutton-pitofsaron.blp", "interface\\lfgframe\\lfgicon-pitofsaron.blp", "interface\\encounterjournal\\ui-ej-background-pitofsaron.blp", "interface\\encounterjournal\\ui-ej-lorebg-pitofsaron.blp", 658, 0, 16, 1, 278, 602},
    [280] = {"The Forge of Souls", "The confrontation between the defenders of Azeroth and the army of the Lich King has continued for long years. In that time many heroes have fallen, and after death they were forced to join the monstrous army of undead. In the course of this tireless struggle, Tirion Fordring of the Argent Vanguard joined forces with the Knights of the Ebon Blade under the command of Darion Mograine. Now this united army, known as the Ashen Verdict, prepares to storm Icecrown Citadel.", "interface\\encounterjournal\\ui-ej-dungeonbutton-theforgeofsouls.blp", "interface\\lfgframe\\lfgicon-theforgeofsouls.blp", "interface\\encounterjournal\\ui-ej-background-theforgeofsouls.blp", "interface\\encounterjournal\\ui-ej-lorebg-theforgeofsouls.blp", 632, 0, 10, 0, 280, 601},
    [281] = {"The Nexus", "Malygos, Aspect of the blue dragonflight, set out to regain control over the forces of magic. He began a fierce struggle to sever the bond between mortals and the arcane energy of Azeroth. Now the blue dragons channel the energy flows of the entire world to the Nexus, the gigantic lair of Malygos.", "interface\\encounterjournal\\ui-ej-dungeonbutton-thenexus.blp", "interface\\lfgframe\\lfgicon-thenexus.blp", "interface\\encounterjournal\\ui-ej-background-thenexus.blp", "interface\\encounterjournal\\ui-ej-lorebg-thenexus.blp", 576, 0, 11, 1, 281, 520},
    [282] = {"The Oculus", "Malygos, Aspect of the blue dragonflight, set out to regain control over the forces of magic. He began a fierce struggle to sever the bond between mortals and the arcane energy of Azeroth. Now the blue dragons channel the energy flows of the entire world to the Nexus, the gigantic lair of Malygos.", "interface\\encounterjournal\\ui-ej-dungeonbutton-theoculus.blp", "interface\\lfgframe\\lfgicon-theoculus.blp", "interface\\encounterjournal\\ui-ej-background-theoculus.blp", "interface\\encounterjournal\\ui-ej-lorebg-theoculus.blp", 578, 0, 12, 0, 282, 528},
    [283] = {"The Violet Hold", "The graceful spires and magic-filled streets of Dalaran are as beautiful as ever, but within the mighty walls of the Violet Hold an unclean power is imprisoned. From ancient times the hold has held captive all those who threatened the city's well-being. The Kirin Tor keep an unrelenting watch over the prison's inmates. A sudden assault has cast doubt on the impregnability of the hold's walls and placed the citizens in danger.", "interface\\encounterjournal\\ui-ej-dungeonbutton-violethold.blp", "interface\\lfgframe\\lfgicon-theviolethold.blp", "interface\\encounterjournal\\ui-ej-background-violethold.blp", "interface\\encounterjournal\\ui-ej-lorebg-violethold.blp", 608, 0, 2, 0, 283, 536},
    [285] = {"Utgarde Keep", "For a long time Utgarde Keep was thought abandoned. It was merely a monument to a perished civilization that vanished among the cliffs of the Howling Fjord. But recently something has awakened the keep's slumbering inhabitants - the vrykul.", "interface\\encounterjournal\\ui-ej-dungeonbutton-utgardekeep.blp", "interface\\lfgframe\\lfgicon-utgarde.blp", "interface\\encounterjournal\\ui-ej-background-utgardekeep.blp", "interface\\encounterjournal\\ui-ej-lorebg-utgardekeep.blp", 574, 0, 9, 0, 285, 523},
    [286] = {"Utgarde Pinnacle", "For a long time Utgarde Keep was thought abandoned. It was merely a monument to a perished civilization that vanished among the cliffs of the Howling Fjord. But recently something has awakened the keep's slumbering inhabitants - the vrykul.", "interface\\encounterjournal\\ui-ej-dungeonbutton-utgardepinnacle.blp", "interface\\lfgframe\\lfgicon-utgardepinnacle.blp", "interface\\encounterjournal\\ui-ej-background-utgardepinnacle.blp", "interface\\encounterjournal\\ui-ej-lorebg-utgardepinnacle.blp", 575, 0, 4, 1, 286, 524},
    [741] = {"Molten Core", "Deep within Blackrock Mountain lies the Molten Core. It was here, in the heart of Blackrock Mountain, unable to cope with the civil war among the dwarves, that Emperor Thaurissan brought into our world the Firelord - Ragnaros. Although the Firelord cannot stray far from the blazing Core, it is said that the dwarves of the Dark Iron clan are under the sway of his spirit-servants, who are gathering an army of creatures of living stone. The lake of fire in which Ragnaros slumbers serves as a gate to the realm of the fire elementals, through which malevolent elemental spirits make their way into our world. First among Ragnaros's minions is Majordomo Executus. This cunning humanoid is the only one who can rouse the Firelord from his slumber.", "interface\\encounterjournal\\ui-ej-dungeonbutton-moltencore.blp", "interface\\lfgframe\\lfgicon-moltencore.blp", "interface\\encounterjournal\\ui-ej-background-moltencore.blp", "interface\\encounterjournal\\ui-ej-lorebg-moltencore.blp", 409, 0, 1, 16, 741, 877},
    [742] = {"Blackwing Lair", "Blackwing Lair is located at the very summit of Blackrock Spire. This majestic spire, hewn from ancient stone, was built to a dragon's design, and now within its dark halls Deathwing's eldest son - Nefarian - conducts his nightmarish experiments. He controls mighty creatures like puppets and crossbreeds the offspring of the various dragonflights. The results of his labors are horrifying, and if he succeeds, he will be able to bring even more sinister plans to life. But the lord of Blackrock Mountain is no simple researcher, but a mighty dragon ensconced in a well-fortified lair. Can mortals dare to challenge him? ", "interface\\encounterjournal\\ui-ej-dungeonbutton-blackwinglair.blp", "interface\\lfgframe\\lfgicon-blackwinglair.blp", "interface\\encounterjournal\\ui-ej-background-blackwinglair.blp", "interface\\encounterjournal\\ui-ej-lorebg-blackwinglair.blp", 469, 0, 2, 16, 742, 885},
    [743] = {"Ruins of Ahn'Qiraj", "In the final hours of the War of the Shifting Sands, the combined forces of the night elves and the four dragonflights fought their way to the very heart of the qiraji empire, to the city of Ahn'Qiraj. But at the very gates they met with resistance from the silithid unlike any seen before. In the end, they failed to fully defeat the silithid and their qiraji masters. They were sealed behind a magical barrier, and the cursed city was left lying in ruins. A thousand years have passed since then, but the qiraji forces have not slept. New enemies have emerged from the hives, and the ruins of Ahn'Qiraj once again teem with silithid and qiraji. So that Azeroth does not fall under another blow from the qiraji army, the looming threat must be eliminated. ", "interface\\encounterjournal\\ui-ej-dungeonbutton-ruinsofahnqiraj.blp", "interface\\lfgframe\\lfgicon-aqruins.blp", "interface\\encounterjournal\\ui-ej-background-ruinsofahnqiraj.blp", "interface\\encounterjournal\\ui-ej-lorebg-ruinsofahnqiraj.blp", 509, 0, 4, 16, 743, 881},
    [744] = {"Temple of Ahn'Qiraj", "At the heart of Ahn'Qiraj lies the ancient temple district. Built in time immemorial, it calls to mind unnameable gods and serves as a vast incubator for the qiraji army. For a thousand years now, since the day the War of the Shifting Sands ended, the Twin Emperors have been imprisoned within their own temple. They are barely held by a magical barrier raised by the bronze dragon Anachronos and the night elves. The Scepter of the Shifting Sands has been restored, and the seal is broken, and the path into the inner sanctum of Ahn'Qiraj is open. Among the teeming silithid beyond the Temple of Ahn'Qiraj, the qiraji legions prepare for invasion. They must be stopped at any cost, before the insectoid armies fall upon Kalimdor once more and a second War of the Shifting Sands begins! ", "interface\\encounterjournal\\ui-ej-dungeonbutton-templeofahnqiraj.blp", "interface\\lfgframe\\lfgicon-aqtemple.blp", "interface\\encounterjournal\\ui-ej-background-templeofahnqiraj.blp", "interface\\encounterjournal\\ui-ej-lorebg-templeofahnqiraj.blp", 531, 0, 5, 16, 744, 893},
    [745] = {"Karazhan", "Karazhan, also known as the Tower of Medivh, is in essence an abandoned magical tower located in Deadwind Pass, beneath the place where all the ley lines of the world of Azeroth converge. The tower is famous for its last master - Medivh, the last Guardian of the order of Tirisfal. After Medivh was slain by Khadgar, Lothar, and Garona, the tower closed itself off from the outside world. But recently Karazhan has awakened - something dark has taken up residence in the tower, restless spirits and demons now walk its halls... and even the presence of Medivh himself can still be felt, even decades after his death. ", "interface\\encounterjournal\\ui-ej-dungeonbutton-karazhan.blp", "interface\\lfgframe\\lfgicon-karazhan.blp", "interface\\encounterjournal\\ui-ej-background-karazhan.blp", "interface\\encounterjournal\\ui-ej-lorebg-karazhan.blp", 532, 0, 1, 16, 745, 867},
    [746] = {"Gruul's Lair", "When the cunning dragon Aspect Deathwing learned of the Dark Portal and Draenor, he never doubted for a moment that the draenei would scarcely dare ever to defy the black dragons. And so he hid clutches of eggs all over the world. In Blade's Edge Mountains he left a very weak guard over a clutch - and paid for it cruelly. The dragon guardians were attacked by gronn, the inhabitants of Blade's Edge. Their leader Gruul impaled all the guardians upon the peaks of the cliffs. Today the Blade's Edge ogres revere Gruul the Dragonkiller as a god. His mighty sons run rampant both at home in the mountains and on the plains of Nagrand. Gruul is incredibly strong and experienced in battle, and should he take it into his head to attack the Horde or the Alliance in Outland, he would become an exceedingly dangerous foe. ", "interface\\encounterjournal\\ui-ej-dungeonbutton-gruulslair.blp", "interface\\lfgframe\\lfgicon-gruulslair.blp", "interface\\encounterjournal\\ui-ej-background-gruulslair.blp", "interface\\encounterjournal\\ui-ej-lorebg-gruulslair.blp", 565, 0, 2, 16, 746, 864},
    [747] = {"Magtheridon's Lair", "The vanquished pit lord was left alive and imprisoned within Hellfire Citadel. Bound in iron chains and the bonds of magic, he hovers on the brink of life and death, while Illidan's subjects each day drain the accursed blood from his veins. Upon this blood a whole new army has been raised - the savage Fel orcs. And to put a stop to it, Magtheridon must be destroyed.", "interface\\encounterjournal\\ui-ej-dungeonbutton-magtheridonslair.blp", "interface\\lfgframe\\lfgicon-hellfirecitadelraid.blp", "interface\\encounterjournal\\ui-ej-background-magtheridonslair.blp", "interface\\encounterjournal\\ui-ej-lorebg-magtheridonslair.blp", 544, 0, 3, 16, 747, 865},
    [748] = {"Serpentshrine Cavern", "Whoever rules the waters commands all of Outland. This lesson Lady Vashj, the devoted ally and confidante of Illidan Stormrage, learned in service to her lord. Soon after the Third War, when Illidan turned to the naga for aid, a detachment led by Lady Vashj answered his call. She followed Illidan with all the fervor of blind devotion. Now the sorceress has settled in Serpentshrine Cavern and watches attentively from there over the course of operations in Coilfang. Vashj is far more suited to the waters of the Reservoir than to the cold stone prison of the Black Temple. Here she can oversee her subjects and personally direct the draining of Zangarmarsh.", "interface\\encounterjournal\\ui-ej-dungeonbutton-coilfangreservoir.blp", "interface\\lfgframe\\lfgicon-serpentshrinecavern.blp", "interface\\encounterjournal\\ui-ej-background-coilfangreservoir.blp", "interface\\encounterjournal\\ui-ej-lorebg-coilfangreservoir.blp", 548, 0, 5, 16, 748, 862},
    [749] = {"The Eye", "Outland has become the chief front in the battle against the Burning Legion, and the naaru made use of Tempest Keep to reach the shattered planet. But after the landing, the keep was occupied by Prince Kael'thas and his army of blood elves. They quickly took control of its satellite ships as well. Now the prince, driven by obscure aims, seeks to unravel the technology of the naaru in order to master the chaos energy of the Netherstorm itself.", "interface\\encounterjournal\\ui-ej-dungeonbutton-tempestkeep.blp", "interface\\lfgframe\\lfgicon-tempestkeep.blp", "interface\\encounterjournal\\ui-ej-background-tempestkeep.blp", "interface\\encounterjournal\\ui-ej-lorebg-tempestkeep.blp", 550, 0, 6, 16, 749, 861},
    [753] = {"Vault of Archavon", "Above the frozen Dragonblight and the inhospitable, desolate Borean Tundra rises a plateau that the inhabitants of Northrend have named the Wintergrasp. For centuries it remained undisturbed, and the icy winds swept freely, howling, between the ancient fortifications built by the titans. Yet the abundance of the land's gifts and the strategic position of the titans' fortifications turned Wintergrasp into the chief battleground between the Horde and the Alliance. Moreover, rumors persist that beneath the fortress of Wintergrasp dwells an ancient titan. One can only imagine what riches lie hidden in this treasure vault... ", "interface\\encounterjournal\\ui-ej-dungeonbutton-vaultofarchavon.blp", "interface\\lfgframe\\lfgicon-vaultofarchavon.blp", "interface\\encounterjournal\\ui-ej-background-vaultofarchavon.blp", "interface\\encounterjournal\\ui-ej-lorebg-vaultofarchavon.blp", 624, 0, 2, 16, 753, 532},
    [754] = {"Naxxramas", "Naxxramas, filled with new power, has appeared once again over the war-torn Dragonblight, and once again it is commanded by Kel'Thuzad, who hides within the icy heart of the citadel. His host has laid siege to Wintergarde Keep, but the war against the Scourge grows ever more fierce. The fall of Naxxramas could turn the tide of the battle against the Lich King, while defeat could herald his victory. ", "interface\\encounterjournal\\ui-ej-dungeonbutton-naxxramas.blp", "interface\\lfgframe\\lfgicon-naxxramas.blp", "interface\\encounterjournal\\ui-ej-background-naxxramas.blp", "interface\\encounterjournal\\ui-ej-lorebg-naxxramas.blp", 533, 0, 3, 16, 754, 535},
    [755] = {"The Obsidian Sanctum", "During the Nexus War, Alexstrasza the Life-Binder, leader of the red dragonflight, charged her offspring to learn of any danger that might lurk within the Wyrmrest Accord. The red dragons quickly discovered a nest of twilight dragon eggs, corrupt creations of Deathwing the Destroyer, hidden within the black dragonflight's Obsidian Sanctum. The red dragons, exhausted by the struggle against the Scourge and the blue dragons, did not dare to move openly against the Obsidian Sanctum, fearing still greater losses among their allies. Instead Alexstrasza's consort Korialstrasz reported the twilight dragon eggs to his allies - the Six of Dalaran - in the hope that brave heroes would cleanse the sanctum of Deathwing's twilight children.", "interface\\encounterjournal\\ui-ej-dungeonbutton-obsidiansanctum.blp", "interface\\lfgframe\\lfgicon-chamberofaspects.blp", "interface\\encounterjournal\\ui-ej-background-obsidiansanctum.blp", "interface\\encounterjournal\\ui-ej-lorebg-obsidiansanctum.blp", 615, 0, 4, 16, 755, 531},
    [756] = {"The Eye of Eternity", "To decide what to do about the reckless Malygos, Alexstrasza and the other dragons resolved to hold council at Wyrmrest Temple. Those gathered had to agree that the Spell-Weaver could no longer be saved. With the aid of the red dragons, the heroes of Azeroth will be able to do what once seemed impossible: to battle Malygos in the Eye of Eternity. Victory over Malygos may save Azeroth, but it will inevitably herald the dawn of a new age: the world will be flooded with magical energy, and there will be no dragon with the strength to control it. The death of Malygos threatens to bring disaster not only to the dragonflights, but to the whole world. ", "interface\\encounterjournal\\ui-ej-dungeonbutton-eyeofeternity.blp", "interface\\lfgframe\\lfgicon-malygos.blp", "interface\\encounterjournal\\ui-ej-background-eyeofeternity.blp", "interface\\encounterjournal\\ui-ej-lorebg-eyeofeternity.blp", 616, 0, 7, 16, 756, 527},
    [757] = {"Trial of the Champion", "The Trial of the Champion is a tournament of the Alliance and the Horde, meant to select the finest champions, so that they, at the head of the forces of the Ashen Verdict, might penetrate into the very heart of the Scourge - Icecrown Citadel. But only the strongest warriors can pass the trial. They must endure battles against monsters, other warriors, and the mighty servants of the Lich King.", "interface\\encounterjournal\\ui-ej-dungeonbutton-trialofthecrusader.blp", "interface\\lfgframe\\lfgicon-argentraid.blp", "interface\\encounterjournal\\ui-ej-background-trialofthecrusader.blp", "interface\\encounterjournal\\ui-ej-lorebg-trialofthecrusader.blp", 649, 0, 7, 16, 757, 543},
    [758] = {"Icecrown Citadel", "Icecrown Citadel is a vast fortress of the Scourge and the last stronghold of the Lich King. Located in the frozen wastes of Icecrown in Northrend, the Citadel was raised around the Frozen Throne, which held the spirit of Ner'zhul until Arthas Menethil became the new Lich King. Within this fortress, forged of saronite, the most powerful and loathsome minions of the Scourge have gathered - a vast army of the living dead that stands guard over the Lich King against those who seek to destroy him. The fate of the world depends on the victory or defeat of the heroes laying siege to this citadel.", "interface\\encounterjournal\\ui-ej-dungeonbutton-icecrowncitadel.blp", "interface\\lfgframe\\lfgicon-icecrowncitadel.blp", "interface\\encounterjournal\\ui-ej-background-icecrowncitadel.blp", "interface\\encounterjournal\\ui-ej-lorebg-icecrowncitadel.blp", 631, 0, 9, 16, 758, 604},
    [760] = {"Onyxia's Lair", "Of Onyxia it is known that nothing pleases her so much as to corrupt mortals by meddling in their political affairs. And so there is a belief that she often takes human form and appears wherever some tangled situation between the races is being decided: she clouds the minds of those she speaks with and goads them into acting at her bidding. It is even sometimes said that Onyxia once happened to pass herself off as a member of House Prestor - as her father did in his time. When Onyxia has no concern for the affairs of mortals, she shelters in a fiery underground lair in the Dragon's land, in a deathly-looking swamp in the Dustwallow Marsh. There she is guarded by her kin - those of the treacherous black dragonflight who survived.", "interface\\encounterjournal\\ui-ej-dungeonbutton-onyxia.blp", "interface\\lfgframe\\lfgicon-onyxiaencounter.blp", "interface\\encounterjournal\\ui-ej-background-onyxiaslair.blp", "interface\\encounterjournal\\ui-ej-lorebg-onxyiaslair.blp", 249, 0, 8, 16, 760, 718},
    [761] = {"The Ruby Sanctum", "After the clutch of twilight dragon eggs was discovered in the Obsidian Sanctum, Korialstrasz asked the Six to send adventurers to destroy them. This was done quickly and without undue fuss. And although everything settled down in time, for inexplicable reasons contact with the guardians of the Ruby Sanctum was lost. The gatekeepers who stood at the portal were found slain, and the magical stones - destroyed. The current state of the Ruby Sanctum is unknown, and even less is known of those who attacked it, since the number of black dragons in Northrend is far too small for such an assault. What force, then, has dared to attack this stronghold of the red dragons, and how were they able to slip past the guards unnoticed?", "interface\\encounterjournal\\ui-ej-dungeonbutton-rubysanctum.blp", "interface\\lfgframe\\lfgicon-rubysanctum.blp", "interface\\encounterjournal\\ui-ej-background-rubysanctum.blp", "interface\\encounterjournal\\ui-ej-lorebg-rubysanctum.blp", 724, 0, 12, 16, 761, 609},
    [762] = {"Ragefire Chasm", "Ragefire Chasm lies deep beneath Orgrimmar. Its volcanic caverns were once held by savage troggs, until the dreadful cultists of the Searing Blade came there. The cultists summoned a fearsome creature into this world, whose name is Taragaman the Hungerer. With the help of his might, it is rumored, they wish to break out of the cavern and seize Orgrimmar. To aid them, they have also called the satyr Bazzalan into their ranks, who will command the army of cultists.", "interface\\encounterjournal\\UI-EJ-DUNGEONBUTTON-RagefireChasm.blp", "interface\\lfgframe\\lfgicon-RAGEFIRECHASM.blp", "interface\\encounterjournal\\ui-ej-background-ragefirechasm.blp", "interface\\encounterjournal\\ui-ej-lorebg-ragefirechasm.blp", 389, 0, 17, 0, 762, 680},
    [763] = {"Scarlet Monastery - Graveyard", "The Graveyard of the Scarlet Monastery is part of the Scarlet Monastery. The Graveyard, the leftmost entrance, is the simplest and smallest. The mobs are almost entirely undead, and, unlike most cases, the majority of them are not elite.", "interface\\encounterjournal\\UI-EJ-DUNGEONBUTTON-ScarletMonastery.blp", "interface\\lfgframe\\lfgicon-SCARLETMONASTERY.blp", "interface\\encounterjournal\\ui-ej-background-ScarletMonastery.blp", "interface\\encounterjournal\\ui-ej-lorebg-ScarletMonastery", 189, 10360, 10, 0, 763, 889},
    [764] = {"Scarlet Monastery - Cathedral", "The Scarlet Monastery was once a proud bastion of the Lordaeron priesthood, a center for learning and enlightenment. However, with the appearance of the Scourge's undead during the Third War, the peaceful monastery was turned into a stronghold of the fanatical Scarlet Crusade. Under the leadership of the Scarlet Crusade and Whitemane, the members of the Crusade became ever more aggressive in their battle against the Scourge. Their grip on reality slipped, and over time Whitemane and her followers no longer trusted anyone who had not taken part in their own crusade, considering them tainted. Because of this, a great number of innocent men and women were tortured and ultimately killed.", "interface\\encounterjournal\\UI-EJ-DUNGEONBUTTON-ScarletMonastery.blp", "interface\\lfgframe\\lfgicon-SCARLETMONASTERY.blp", "interface\\encounterjournal\\ui-ej-background-ScarletMonastery.blp", "interface\\encounterjournal\\ui-ej-lorebg-ScarletMonastery.blp", 190, 10361, 11, 0, 764, 940},
    [765] = {"Scarlet Monastery - Library", "The Library of the Scarlet Monastery holds ancient knowledge, all the known spells of the mages of the Kirin Tor; when the fanatics seized the Monastery, very dangerous knowledge fell into their hands. In the Library the mightiest mage of the Scarlet Crusade, Doan, studies this knowledge in order to direct all his power against the undead and against all non-human races.", "interface\\encounterjournal\\UI-EJ-DUNGEONBUTTON-ScarletHalls.blp", "interface\\lfgframe\\lfgicon-ScarletHalls.blp", "interface\\encounterjournal\\ui-ej-background-ScarletHalls.blp", "interface\\encounterjournal\\ui-ej-lorebg-ScarletHalls.blp", 191, 10362, 12, 0, 765, 938},
    [766] = {"Scarlet Monastery - Armory", "The most ferocious fighters, who repelled every assault on the monastery in these dark times, take part in training a new army in the Armory of the Scarlet Monastery. The soldiers of the new army are united by a boundless hatred of the undead, and they are prepared to make any sacrifice for the victory of the order.", "interface\\encounterjournal\\UI-EJ-DUNGEONBUTTON-ScarletHalls.blp", "interface\\lfgframe\\lfgicon-ScarletHalls.blp", "interface\\encounterjournal\\ui-ej-background-ScarletHalls.blp", "interface\\encounterjournal\\ui-ej-lorebg-ScarletHalls.blp", 192, 10363, 13, 0, 766, 939},
    [767] = {"Scholomance", "Hidden among the eerie crypts beneath Caer Darrow, Scholomance is widely known in the circles of those who seek to gain mastery over death. The post of headmaster of the necrotic sciences is held by the Darkmaster Gandling, as the most cruel and cunning practitioner of necromancy.", "interface\\encounterjournal\\UI-EJ-DUNGEONBUTTON-Scholomance.blp", "interface\\lfgframe\\LFGICON-SCHOLOMANCE.BLP", "interface\\encounterjournal\\UI-EJ-BACKGROUND-Scholomance.blp", "interface\\encounterjournal\\UI-EJ-LOREBG-Scholomance.blp", 289, 0, 14, 0, 767, 890},
    [771] = {"Ulduar", "For thousands of years mortals did not disturb Ulduar, far from their cares and struggles. Nevertheless, since its recent discovery, many have wondered what the structure's original purpose might have been. Some thought it a city built to proclaim the glory of its creators. Some thought it a vault containing countless treasures, perhaps even relics of the mighty Titans themselves. Such suppositions were mistaken. Beyond the gates of Ulduar there is no city, no treasure vault, no final answer to the riddles of the Titans. All that awaits those who dare to set foot in Ulduar is a horror that even the titans cannot, and will not, destroy, an evil that they merely... contain.", "interface\\encounterjournal\\UI-EJ-DUNGEONBUTTON-Ulduar.blp", "interface\\lfgframe\\UI-LFG-BACKGROUND-ULDUAR.BLP", "interface\\encounterjournal\\UI-EJ-BACKGROUND-Ulduar.blp", "interface\\encounterjournal\\UI-EJ-LOREBG-Ulduar.blp", 603, 0, 6, 16, 771, 529},
}
JOURNALENCOUNTER = {
    [63] = {
        {89, "Rhahk'Zor", [[ Ogres are an extremely amusing folk. Immense physical might, and an extremely... simple mind allowed VanCleef to hire Rhahk'Zor as a bodyguard, paying for his 'labor' only upon presentation of the heads of trespassers. ]], 0.365270, 0.612275, 1, 886, 2010, 63, -1, 0, 1},
        {90, "Sneed's Shredder", [[ When the unknown engineer Sneed was still toiling for the benefit of the Bilgewater Cartel, he received from the Defias Brotherhood an offer of a sum he could not have earned in a lifetime. The goblin hastily accepted it and renounced his former masters... Then again, any clever goblin would have done the same. ]], 0.501996, 0.868264, 1, 886, 2020, 63, -1, 0, 2},
        {91, "Gilnid", [[ In the creation of mechanical constructs, Gilnid has no equal. Amoral even by goblin standards, Gilnid was banished from the Bay when one of his mad experiments spun out of control in the city market. Gilnid takes no interest in politics, and he plays no part in the Brotherhood's decisions, but the Brotherhood sponsors his experiments and provides him with spare parts. VanCleef's respect for his mad talents knows no bounds. ]], 0.124751, 0.758982, 2, 886, 20009, 63, -1, 0, 3},
        {92, "Captain Greenskin", [[ Greenskin, a pirate to the marrow of his bones, was hired by Edwin VanCleef, who needed a crew for the monstrous juggernaut. Greenskin and his crew will fight to the death, for commanding such a ship is the very limit of their dreams. ]], 0.604791, 0.387724, 2, 886, 2044, 63, -1, 0, 4},
        {95, "Edwin VanCleef", [[ Edwin VanCleef started out as a cat burglar in the city of Stormwind, his specialty being the bypassing of mechanical defenses. After the city's destruction by the Horde, he trained, as the eldest son of his father, in stonework and was among the first to offer his services in rebuilding the ruined capital. He was also among the first to demand payment for his services and to be cast out of the city for it. VanCleef gathered a band of builders and engineers of all stripes who found themselves in the squalid pit outside the gates of Stormwind, and founded the Defias Brotherhood. ]], 0.654691, 0.402695, 2, 886, 2060, 63, -1, 0, 6},
        {11637, "Mr. Smite", [[ Mr. Smite is the first mate of Captain Greenskin. He enjoys toying with his victims, making them believe they can win, while gradually bringing ever more deadly weapons to bear. ]], 0.560000, 0.264000, 2, 886, 20872, 63, -1, 0, 5},
    },
    [64] = {
        {96, "Rethilgore", [[ Razorclaw the Butcher was entrusted with guarding the prisoners of Shadowfang Keep, and he intends to justify that trust with faithful service. Beyond the fury and physical might shared by all worgen, Razorclaw possesses a dark ability - the draining of life forces. ]], 0.664671, 0.732036, 1, 891, 2107, 64, -1, 0, 1},
        {97, "Baron Silverlaine", [[ Baron Silverlaine was once the master of the keep seized by Arugal's worgen. Now his restless spirit is guarded by the wolf-men who tore him apart, and woe to any who dare intrude upon his domain. ]], 0.304392, 0.773952, 2, 891, 2118, 64, -1, 0, 2},
        {98, "Commander Springvale", [[ The ghost of a loyal soldier, Commander Springvale, roams the council chamber, ready at any moment to unleash his unholy might upon the invaders and avenge the death of his lord - Baron Silverlaine. ]], 0.280439, 0.597305, 1, 891, 2137, 64, -1, 0, 3},
        {99, "Fenrus the Devourer", [[ An enormous black wolf, Arugal's pet and guardian, possessed of monstrous strength and endowed with venomous saliva, dwells on the upper floors of Arugal's tower, in the library. Woe to the adventurer who catches the eye of this beast. ]], 0.544910, 0.537425, 0, 891, 2156, 64, -1, 0, 4},
        {100, "Archmage Arugal", [[ Once Arugal was a member of the Kirin Tor in Dalaran. However, after the Scourge invaded Dalaran and destroyed it, and many fallen mages were raised as undead to fill the Scourge with new power, Arugal fled to Shadowfang Keep, around which the village of Pyrewood was nestled. Disregarding the warnings, he loosed the curse of the worgen upon these lands, which he bitterly regretted later. Driven mad by guilt over what had happened, Arugal embraced the worgen as his children and locked himself away in Shadowfang Keep. ]], 0.684632, 0.335329, 0, 891, 2164, 64, -1, 0, 5},
    },
    [76] = {
        {175, "High Priest Venoxis", [[ Venoxis was sent to slay Hakkar, but was enslaved by the cruel spirit, and then slain by the heroes of Azeroth. Through the efforts of Hakkar's minions he was returned from the spirit world and set once more to guard Zul'Gurub, where venomous serpents now serve him. ]], 0.509980, 0.537425, 0, 793, 2793, 76, -1, 0, 1},
        {176, "Bloodlord Mandokir", [[ Bloodlord Mandokir is a ferocious warrior who commands the Gurubashi warriors. Seated upon his raptor, he watches over his servants as they attain their martial mastery, and woe to any of them who fail to justify the Bloodlord's trust - he will be instantly beheaded by Mandokir himself. ]], 0.604791, 0.799401, 0, 793, 2610, 76, -1, 0, 2},
        {177, "Edge of Madness - Gri'lek", [[ Among the rebellious spirits of the Edge of Madness are Gri'lek, a sinister troll whom the loa stripped of his powers of regeneration; Renataki, the infamous mutilator-warrior; Hazza'rah, a seer tormented by visions of the future; and Wushoolay, a mighty fighter filled with the power of storms. ]], 0.599801, 0.462575, 0, 793, 2504, 76, -1, 0, 3},
        {178, "Edge of Madness - Hazza'rah", [[ Among the rebellious spirits of the Edge of Madness are Gri'lek, a sinister troll whom the loa stripped of his powers of regeneration; Renataki, the infamous mutilator-warrior; Hazza'rah, a seer tormented by visions of the future; and Wushoolay, a mighty fighter filled with the power of storms. ]], 0.636700, 0.462575, 0, 793, 2495, 76, -1, 0, 4},
        {179, "Edge of Madness - Renataki", [[ Among the rebellious spirits of the Edge of Madness are Gri'lek, a sinister troll whom the loa stripped of his powers of regeneration; Renataki, the infamous mutilator-warrior; Hazza'rah, a seer tormented by visions of the future; and Wushoolay, a mighty fighter filled with the power of storms. ]], 0.599801, 0.514970, 0, 793, 2501, 76, -1, 0, 5},
        {180, "Edge of Madness - Wushoolay", [[ Among the rebellious spirits of the Edge of Madness are Gri'lek, a sinister troll whom the loa stripped of his powers of regeneration; Renataki, the infamous mutilator-warrior; Hazza'rah, a seer tormented by visions of the future; and Wushoolay, a mighty fighter filled with the power of storms. ]], 0.601905, 0.414711, 0, 793, 2498, 76, -1, 0, 6},
        {181, "High Priestess Arlokk", [[ Arlokk is a high priestess, the chosen of the panther loa Bethekk. Following an agreement recently struck between the Gurubashi and Zandalari tribes, Arlokk has loosed her savage pets upon the unsuspecting denizens of the surrounding lands. ]], 0.480040, 0.200599, 0, 793, 2693, 76, -1, 0, 7},
        {184, "Hexxer Jin'do", [[ Necromancers are, as a rule, grim and reclusive sorts, but the master of curses Jin'do has gone far beyond that mold. In his halls beside the altar of seething blood, in Zul'Gurub, an eternal revelry goes on - the dead dance, raised by his will, alongside the necromancer himself. But do not let the image of a madman deceive you - Jin'do is a dangerous foe, and without doubt a mighty sorcerer. ]], 0.317338, 0.245509, 0, 793, 2508, 76, -1, 0, 8},
        {185, "Hakkar the Soulflayer", [[ Hakkar the Soulflayer - a cruel and bloodthirsty spirit - resolved to come to the aid of the trolls. Revealing to the Gurubashi the secrets of blood, he helped them seize most of Stranglethorn Vale and several islands of the South Seas. But for his aid Hakkar demanded a very dear price. Now he has been summoned into this world again, and he sits in Zul'Gurub, gathering strength and awaiting his hour. ]], 0.485030, 0.395210, 0, 793, 2899, 76, -1, 0, 9},
    },
    [77] = {
        {186, "Akil'zon", [[ Akil'zon, formerly a shaman of the Amani tribe, possesses a supernatural gift for commanding the element of air. His abilities drew the attention of the Hex Lord Malacrass, who found in him a worthy vessel for the spirit of the eagle god. ]], 0.355290, 0.230539, 0, 781, 2521, 77, 1, 0, 1},
        {187, "Nalorakk", [[ The Hex Lord Malacrass deemed Nalorakk, renowned for his untamable fury and savage strength, the ideal vessel for the essence of the bear god. ]], 0.405190, 0.773993, 0, 781, 2867, 77, 1, 0, 2},
        {188, "Jan'alai", [[ Dragonhawks are swift predators that tear their prey to pieces with razor-sharp talons. Jan'alai, one of the most skilled raiders of the Amani tribe, prized these qualities highly and even devised similar techniques for his own attacks. ]], 0.554891, 0.709581, 0, 781, 2621, 77, 1, 0, 3},
        {189, "Halazzi", [[ Azeroth's lynxes are untamable hunters that rake their prey with claws and rend it with fangs. The Hex Lord Malacrass reckoned that the essence of the lynx god was worth placing into the body of one of the tribe's most skilled hunters. ]], 0.584831, 0.238024, 0, 781, 2804, 77, 1, 0, 4},
        {190, "Hex Lord Malacrass", [[ It is rumored that the most terrible witch doctor of the Amani tribe, the Hex Lord Malacrass, accomplished the impossible and bound the essences of several mighty animal gods into the bodies of his defenders... while reserving for himself the most sinister essence of all. ]], 0.714572, 0.529940, 0, 781, 2706, 77, 1, 0, 5},
        {191, "Zul'jin", [[ Zul'jin, a legend, a one-armed troll whom even the mightiest of his kind cannot hope to defeat in battle. Having made the rebirth of the Amani empire the purpose of his existence, he gathers the warriors of his tribe in Zul'Aman and seeks ways to acquire new powers. Upon him is laid the great mission - to restore the tribe's former glory. The Amani empire is reborn for vengeance... ]], 0.904193, 0.529940, 0, 781, 2875, 77, 1, 0, 6},
        {11001, "Sacrifices", [[ Several adventurers and explorers from Harrison's party have been captured by the Amani trolls. If they are rescued in time, before they are sacrificed, they will surely reward their rescuers. ]], 0.000000, 0.000000, 0, 781, 12371, 77, 1, 0, 7},
    },
    [227] = {
        {368, "Ghamoo-ra", [[ When the Twilight's Hammer cult arrived in these lands, its followers captured one of the last peaceful denizens of the temple of Elune. For long years the cultists tormented the giant turtle, ravaging its body and soul, until the poor creature went mad. The cultists named the beast Ghamoo-ra, and now they strive to harness its fury to defend their lair. ]], 0.333333, 0.606870, 1, 873, 20010, 227, -1, 0, 1},
        {426, "Gelihast", [[ Hearing the call of the Old Gods, Gelihast answered it, hewing his way by force into the Blackfathom Deeps and slaying a dozen unsuspecting acolytes of the Twilight's Hammer cult with his two swords. The cult, shaken by his cruelty and ferocity, allowed him to remain, and Gelihast built his own altar to offer sacrifices and receive blessings from the sinister powers dwelling in the temple's ruins. ]], 0.543284, 0.564179, 1, 873, 20011, 227, -1, 0, 3},
        {436, "Lady Sarevess", [[ The Twilight's Hammer cult set aside for Lady Sarevess her own cavern in the Blackfathom Deeps, constantly bringing her living beings as sacrifices. The cult's followers hoped that her rituals and research would grant them magical protection, allowing them to worship the terrible hydra dwelling in the deeps while avoiding becoming its meal. ]], 0.111940, 0.389552, 1, 873, 9476, 227, -1, 0, 2},
        {437, "Twilight Lord Kelris", [[ When the cult's followers discovered a strange three-headed creature in the depths of the Blackfathom Deeps, the twilight lord Kelris decided that this hydra was a herald of the Old Gods' return... and his chance to attain immortality. Kelris personally watched over the hydra's growth, and even fed it his own subjects to sate its endless hunger. ]], 0.523880, 0.808209, 2, 873, 9507, 227, -1, 0, 7},
        {444, "Aku'mai", [[ Aku'mai - the embodiment of ancient evil - is endowed with a small portion of the Old Gods' power. The three-headed hydra strikes terror into all with its mindless bloodlust and its passion for devouring living flesh, but the Twilight's Hammer cult reveres Aku'mai as a herald that the Old Gods will soon return. ]], 0.855224, 0.864179, 2, 873, 9442, 227, -1, 0, 8},
        {447, "Old Serra'kis", [[ Many of the creatures that swam beneath the ruins of the Altar of the Moon were killed and devoured after the Twilight's Hammer cult settled in the ruins, but none could ever catch the largest crawler, and those who tried inevitably perished. Old Serra'kis is a dangerous beast, and woe to whoever falls into its jaws. ]], 0.586567, 0.308955, 3, 873, 20012, 227, -1, 0, 5},
    },
    [228] = {
        {369, "High Interrogator Gerstahn", [[ Verek's mistress... no. Gerstahn, a follower of the Twilight's Hammer cult, prefers only the very best: exotic food, expensive clothing, and gem-encrusted instruments of torture. Day and night the prison cells of the Dark Iron clan ring with the agonized screams of her captives. Gerstahn proudly calls these blood-curdling sounds her symphony of screams, and never misses a chance to add yet another voice to her composition. ]], 0.474044, 0.922131, 1, 880, 4630, 228, -1, 0, 1},
        {370, "Lord Roccor", [[ Lord Roccor despises the baseness and treachery of the other fire elementals. So as not to serve alongside them in the Molten Core, he deliberately enraged the Firelord. Roccor's risky gambit succeeded: he was banished from the core and sent to guard the Depths of Blackrock Mountain alone. ]], 0.556011, 0.670082, 1, 880, 4472, 228, -1, 0, 2},
        {371, "Houndmaster Grebmar", [[ Many years ago an orphaned dwarf began breeding guard dogs and companion hounds. Now Houndmaster Grebmar treats his hounds like members of his family. When the houndmaster and his faithful friends are not patrolling the Blackrock Depths, he treats them to the finest Dark Iron ale from the Grim Guzzler. ]], 0.535002, 0.573466, 1, 880, 4626, 228, -1, 0, 3},
        {372, "Ring of Law", [[ For crimes committed against the dwarves of the Dark Iron clan, there is but one punishment - death. Ancient tradition demands that the guilty pay for their deeds in blood in the Ring of Law, fighting against savage beasts brought from all over Azeroth. To this day it is not known for certain whether anyone has ever survived this brutal battle. ]], 0.497785, 0.645796, 1, 880, 4547, 228, -1, 0, 4},
        {373, "Pyromancer Loregrain", [[ Once a respected Shadowforge geomancer, Grizzle for unknown reasons joined the Twilight's Hammer cult. In the Blackrock Depths he became interested in the work of the renowned Dark Iron architect - Franclorn Forgewright. The reason for so unusual an interest is unclear, but Grizzle remains loyal to the cult and stands ready to fight its enemies. ]], 0.549180, 0.948770, 2, 880, 4496, 228, -1, 0, 5},
        {374, "Lord Incendius", [[ Baron Geddon taught Scorch... no. Baron Geddon taught the Bael'Gar to properly use its destructive powers, but the baron hardly suspected that his protege would attain such terrifying success. Fearing that the Bael'Gar might try to overthrow him, Geddon dispatched the blazing elemental from the Molten Core to guard the legendary Black Anvil, which belonged to the Dark Iron clan. ]], 0.564208, 0.311475, 1, 880, 4476, 228, -1, 0, 6},
        {375, "Warder Stilgiss", [[ After long years of faithful service to Emperor Thaurissan, the cunning mage Pyromancer Loregrain was entrusted with guarding the clan's treasury in the Black Vault. His good friend, the houndmaster Grebmar, marked the occasion by gifting him one of his vicious hounds - Verek. The mage found a use for the gift. Verek stayed constantly at his side, to terrify any who might try to steal the treasury. ]], 0.602459, 0.659836, 2, 880, 4386, 228, -1, 0, 7},
        {376, "Fineous Darkvire", [[ High Interrogator Gerstahn... no. Lord Incendius... no. The High Architect Phineas Darkstone gained his title by passing off the ideas of more talented stonemasons as his own. His ignorance and treachery brought his predecessor Franclorn Forgewright back from the dead. The ghost of the former high architect wishes to take from Darkstone his incredibly powerful hammer, the Ironfel, before tragedy can strike. ]], 0.635246, 0.211066, 1, 880, 4538, 228, -1, 0, 8},
        {377, "Bael'Gar", [[ Along the Dark Iron road wanders the enormous fire giant Bael'Gor - a testament to the dwarves' craftsmanship. He is imprisoned in the depths of Blackrock Mountain. Ragnaros found this giant in the Firelands and set him to guard the sealed doors at one end of the road. According to legend, only the Firelord and the elders of the Dark Iron clan know what lies beyond these mysterious gates. ]], 0.251366, 0.534836, 1, 880, 4532, 228, -1, 0, 9},
        {378, "General Angerforge", [[ Having devoted his entire life to scholarly pursuits, General Angerforge became an expert on dwarven military history and tactics. Recently he angered Emperor Dagran Thaurissan by writing a scandalous treatise on the causes of his clan's defeats in past military conflicts. But aside from this political misstep, Angerforge is loyal to the Dark Iron clan to the marrow of his bones. He will fight to the last, defending his people and his emperor. ]], 0.363388, 0.823770, 2, 880, 4508, 228, -1, 0, 10},
        {379, "Golem Lord Argelmach", [[ Argelmach began creating golems in his own image and likeness out of an obsession with immortality. It is rumored that he has also taken up dark magic, and that his creations may serve as a vessel for his soul should his body be destroyed. ]], 0.364754, 0.651639, 2, 880, 4501, 228, -1, 0, 11},
        {380, "Hurley Blackbreath", [[ To say that Plugger Spazzring is a regular at the Grim Guzzler is to say nothing at all. In more than ten years this drunkard has left the tavern but once, to steal the top-secret recipe for Thunderbrew Lager. By some strange twist of fate, Plugger sobered up just enough to brew the beer himself, and now he claims it has granted him incredible strength and courage. ]], 0.505668, 0.704778, 2, 880, 4494, 228, -1, 0, 12},
        {381, "Phalanx", [[ Until recently, drunken brawls in the Grim Guzzler were an everyday affair. The tavernkeeper Hurley Blackbreath was helped to deal with this problem by the mighty bouncer golem Phalanx. Its task is to keep order in the establishment and to eject rowdy patrons, cooling their ardor with its fists. ]], 0.458206, 0.564745, 2, 880, 4504, 228, -1, 0, 13},
        {383, "Plugger Spazzring", [[ They say that in the Grim Guzzler everyone knows your name. The tavern owes this spirit of camaraderie to the efforts of Hurley Blackbreath - a leper gnome who began a new life in the Blackrock Depths after the fall of Gnomeregan. Although he was once a warlock, Hurley takes great pride in his work as an innkeeper and sees to it that his customers' mugs are always full. ]], 0.477220, 0.657122, 2, 880, 4485, 228, -1, 0, 15},
        {384, "Ambassador Flamelash", [[ For faithful service to Ragnaros, Fineous Darkvire... no. For faithful service to Ragnaros, the Ambassador Flamelash was appointed ambassador to the Dark Iron clan. This corrupt creature at first despised its dwarven allies, but in time it came to respect their lust for destruction. As a sign of solidarity, Flamelash guards the Hall of the Crafting - a place sacred to the dwarves, in which they perfect their weapons. ]], 0.538251, 0.485656, 2, 880, 4482, 228, -1, 0, 16},
        {385, "The Seven", [[ Many centuries ago the sorcerer-thane Thaurissan and his seven mightiest companions of the Dark Iron clan summoned Ragnaros into Azeroth by mistake and doomed the entire clan to slavery. The seven perished during the ritual, and their cursed souls wander the depths of Blackrock Mountain. They are doomed to serve eternally their master - the new lord of the Dark Iron clan. ]], 0.538251, 0.247951, 2, 880, 4471, 228, -1, 0, 17},
        {386, "Magmus", [[ Ambassador Flamelash charged the fire giant Magmus with guarding the throne room of Emperor Dagran Thaurissan, but even this did not free the ruler of the Dark Iron clan from his fear. Fearing assassins, the Emperor placed under Magmus's command the fire-breathing statues that stand at the entrance to the imperial chambers. ]], 0.796448, 0.118852, 2, 880, 4480, 228, -1, 0, 18},
        {387, "Emperor Dagran Thaurissan", [[ Emperor Dagran Thaurissan rules together with Princess Moira of the rival Bronzebeard clan. Debate rages over whether he enchanted the princess or whether she knowingly married him. Be that as it may, Thaurissan's reign bodes a grim future for the clan. While he lives, the Dark Iron clan serves Ragnaros and poses a serious threat to the kingdoms of Azeroth. ]], 0.909836, 0.118852, 2, 880, 4645, 228, -1, 0, 19},
    },
    [229] = {
        {11577, "Pyroguard Emberseer", [[ A mighty fire elemental held captive in the upper reaches of Blackrock Spire, the Pyroguard Emberseer was the prisoner of several sorcerers. However, when the sorcerers came out of their trance and were destroyed, the Coal Seer would break free and try to destroy everything around it. Passage to the rest of the spire was only granted once Pyroguard Emberseer had been dealt with. ]], 0.303000, 0.273000, 6, 882, 20232, 229, -1, 0, 2},
        {11578, "Solakar Flamewreath", [[ Solakar Flamewreath will be spawned at the end of the 'Fire of the Fathers' event in the rookery of Upper Blackrock Spire. The 'Fire of the Fathers' event can be a problem for the unprepared, and many groups choose to skip it. The event that triggers it begins with the use of the column on the left side of the Rookery, surrounded by eggs and elite drakes. ]], 0.377000, 0.375000, 6, 882, 20238, 229, -1, 0, 2},
        {11579, "Warchief Rend Blackhand", [[ After the Horde was defeated in the Second War, Rend Blackhand, son of the first warchief, led the remnants of his clan to Blackrock Spire and fought the Dark Iron dwarves for possession of the citadel. Rend allied his orcs with Nefarian and his flight of black dragons, who shattered the dwarves and drove them from the upper reaches of Blackrock Mountain. ]], 0.485000, 0.255000, 7, 882, 20241, 229, -1, 0, 2},
        {11580, "The Beast", [[ The Beast is a hound boss to be found in the Furnace in Upper Blackrock Spire. This minion of Ragnaros was captured by Nefarian's forces, tortured for their amusement, and then retrained to guard the spire from intruders. One such intruder, Finkle Einhorn, was swallowed whole by the Beast in the pits on the Firelands. Protected by his lava suit, the gnome remained in the Beast's belly for some time. ]], 0.644000, 0.305000, 7, 882, 20251, 229, -1, 0, 2},
        {11581, "Lord Valthalak", [[ Lord Valthalak is a boss - a dragonkin who is summoned in Upper Blackrock Spire in the Furnace by means of the Brazier of Summoning. He is the final boss in the Dungeon Set 2 quest line. ]], 0.617000, 0.437000, 7, 882, 20254, 229, -1, 0, 2},
        {11582, "Gorosh the Dervish", [[ Goraluk Anvilcrack is a named orc of Blackrock, dwelling in Upper Blackrock Spire. His loot is related to blacksmithing. He sold his soul to the Satyr Lorax, but broke the deal and fled with the Blank Runeblade Scabbard. ]], 0.288000, 0.258000, 7, 882, 20258, 229, -1, 0, 2},
        {11583, "Grizzle", [[ Jed Runewatcher is a rare orc in Upper Blackrock Spire. He may roam in Goraluk Anvilcrack's room or in the Furnace (near the Beast). Jed Runewatcher is a member of the Blackhand Legion. The Blackhand Legion is a unit under Dal'rend Blackhand. ]], 0.393000, 0.258000, 7, 882, 20261, 229, -1, 0, 2},
        {11584, "General Drakkisath", [[ General Drakkisath was a black dragon, ruler of Nefarian's dragon armies, Nefarian being the son of Deathwing. From the summit of Upper Blackrock Spire he directed his troops in their war to drive the Dark Iron dwarves from the depths of Blackrock Mountain. His personal weapon was the Blackblade of Shahram. ]], 0.350000, 0.497000, 7, 882, 20264, 229, -1, 0, 2},
        {388, "War Master Voone", [[ War Master Voone... no. Highlord Omokk rules his ogres with an iron fist. Many vassals have challenged him to single combat in hopes of taking his place, but all have perished before landing a single blow. This unbroken luck of Omokk's has given rise to rumors that the chief is protected by dark magic. ]], 0.386612, 0.590164, 3, 882, 4523, 229, -1, 0, 1},
        {389, "Mother Smolderweb", [[ Mother Smolderweb... no. Mor Grayhoof... no. Vosh'gajin is renowned among the trolls for her beauty and her hypnotic powers. She has mastered the craft of the dark hunters to perfection and casts curses and hexes with ease, but she also commands healing spells. ]], 0.553279, 0.692623, 2, 882, 4525, 229, -1, 0, 2},
        {390, "Quartermaster Zigris", [[ During the Second War, War Master Voone led small bands on dangerous missions deep into elven territory. The cunning troll joined the false Horde not because he shared Blackhand's stance, but because he wanted to become its chief strategist. To Voone, the false Horde is a sacrifice of war, and so it pleases him so to defeat a foe of superior strength. ]], 0.524590, 0.545082, 1, 882, 4527, 229, -1, 0, 3},
        {391, "Halycon", [[ Hundreds of years ago the picks of the Dark Iron dwarves awoke Mother Smolderweb in her underground lair. The giant spider broke free. Since then her brood has never ceased to grow, flooding Blackrock Spire, so that even Blackhand's orcs avoid venturing into her territory. ]], 0.620736, 0.741415, 2, 882, 4543, 229, -1, 0, 4},
        {392, "Gizrul the Slavener", [[ Quartermaster Zigris... no. Deathwail... no. The Crystal Fang... no. The Bannok Grimaxe... no. Highlord Omokk... Deathwail is the true leader of the ogres of Blackrock Spire. He granted his lackey, Omokk, dark power over the ogres beneath him. Omokk became enamored of the power granted to him and ruthlessly slays all who stand against him. ]], 0.454918, 0.557377, 4, 882, 4552, 229, -1, 0, 5},
        {393, "Overlord Wyrmthalak", [[ The orc hunter Quartermaster Zigris became known for hunting down refugees from Stormwind at the end of the First War and driving them like beasts. He hates the oppressive cramped corridors of Blackrock Spire and believes that one fine day he will hunt again under the open sky. ]], 0.539617, 0.844263, 5, 882, 4568, 229, -1, 0, 6},
        {394, "Zevrim Thornhoof", [[ Halycon can take pride in her pedigree - among her ancestors were only the most loyal and ferocious worgs. Over the years she has spent in Blackrock Mountain she has produced numerous offspring. It is rumored that Halycon is a demon, given as a gift to Rend Blackhand by one of the pit lords of the Burning Legion. ]], 0.379781, 0.840164, 5, 882, 4572, 229, -1, 0, 7},
        {395, "Hydrospawn", [[ Few of the Dark Horde have seen the unsociable and unpredictable Gizrul. He appears only when summoned by his mate, Halycon. These two monsters have sired the largest and fiercest worgs known in all the history of the orcs. ]], 0.394808, 0.793032, 5, 882, 4584, 229, -1, 0, 8},
        {396, "Lethtendris", [[ Urok Doomhowl... no. Pyroguard Emberseer... no. Gyth oversees the readying of the lower Blackrock Spire's forces for an assault on the Dark Iron dwarves. He feels no affection for the false Horde and its savage soldiers, and will not spare Blackhand's troops in defense of his master - Nefarian. ]], 0.575137, 0.600410, 6, 882, 4587, 229, -1, 0, 9},
    },
    [230] = {
        {402, "Alzzin the Wildshaper", [[ Zevrim Thornhoof, who desperately wished to demonstrate his power to the Burning Legion, told his masters that he could enslave the unyielding ancients who still dwelt in the Dire Maul. When his own strength proved insufficient, Thornhoof began to draw upon the energy of other living beings, slaying them upon a sacrificial altar and stealing their energy at the moment of their final breath. ]], 0.575137, 0.743852, 0, 879, 4655, 230, -1, 0, 1},
        {403, "Tendris Warpwood", [[ When the satyr Zevrim Thornhoof tried to gain control over the elementals of the Dire Maul, he focused his efforts on the Hydrospawn, which lived peacefully in a pool by the altar. When Zevrim began performing his loathsome rituals of sacrifice, the elemental lost its peace and began attacking Zevrim's servants. For many years Zevrim used the energy of his victims to drive the Hydrospawn into a state of unbridled fury and, slowly but surely, bent the elemental to his will. ]], 0.536885, 0.715164, 0, 879, 5004, 230, -1, 0, 2},
        {404, "Illyanna Ravenoak", [[ The dark energy of the Dire Maul drew Lethtendris, who hoped to slake her endless thirst for the knowledge of dark magic. Using the sinews and ligaments of creatures offered in sacrifice, she wove a web that allowed her to draw the corrupted energy from the eastern wing. She joyfully discovered that the web she had created allowed her to amass vast reserves of incredible power, enough to destroy all her enemies. ]], 0.438525, 0.481557, 0, 879, 4994, 230, -1, 0, 3},
        {405, "Magister Kalendris", [[ Alzzin the Wildshaper had always simply wished to corrupt all of Feralas, but he could achieve no results until he found the altar of Eldre'Thalas in the Dire Maul. Using the power of the enslaved ancients, Alzzin channeled all the life force of the forests surrounding the city into his lair, which allowed him to wield it as he saw fit. ]], 0.566940, 0.288934, 0, 879, 4921, 230, -1, 0, 4},
        {406, "Immol'thar", [[ Tendris Warpwood was a devoted defender of Eldre'Thalas, his fate inextricably bound to that of the city. After the Sundering rocked these lands, he remained loyal to the city, but the corruption that has crept into the ruins over the past ten thousand years has nonetheless taken hold of him. ]], 0.336066, 0.536885, 2, 879, 4913, 230, -1, 0, 5},
        {407, "Prince Tortheldrin", [[ Illyanna Ravenoak, together with her faithful companion Ferra, was once reckoned one of the finest huntresses of Prince Tortheldrin, but she later refused to slay her friends at his command. As punishment for her disobedience, the prince slew Illyanna and her bear and used his demonic skills to bind their souls to their bodies, and now they are doomed to defend the Dire Maul forever in the guise of undead. ]], 0.203552, 0.776640, 2, 879, 4906, 230, -1, 0, 6},
        {408, "Guard Mol'dar", [[ When Prince Tortheldrin ordered the slaughter of most of his subjects, the task of carrying out that order fell to his most loyal lieutenants. Magister Kalendris slew many an unsuspecting Shen'dralar, but one of the doomed elves dealt him a mortal wound. Even after death the spirit of Kalendris roams the Dire Maul, defending Tortheldrin's rule. ]], 0.338798, 0.450820, 0, 879, 4836, 230, -1, 0, 7},
        {409, "Stomper Kreeg", [[ In a desperate attempt to reclaim the power and immortality lost when the Well of Eternity was destroyed, the Shen'dralar summoned and trapped, by means of a force field, a demon in the western wing of the Dire Maul. They used the energy of the dread abyss to amplify their spells. Immol'thar lay motionless for nearly 10,000 years. All that time it waited for the hour when it would gain its freedom and tear to pieces those who had imprisoned it. ]], 0.349727, 0.575820, 0, 879, 4822, 230, -1, 0, 8},
        {410, "Guard Fengus", [[ After the destruction of the Well of Eternity, Prince Tortheldrin retained control over the surviving Shen'dralar by imprisoning a demon in the ruins of Eldre'Thalas and allowing his subjects to feed on its might. The demonic power clouded Tortheldrin's mind and, when the creature grew weak, the prince ordered many of his vassals slain, so that only he and his most fanatical followers could continue to draw upon the energy of the fel. ]], 0.622951, 0.231557, 0, 879, 4752, 230, -1, 0, 9},
        {411, "Guard Slip'kik", [[ The ogre Guard Mol'dar is one of the guardsmen of the Gordok clan. He is convinced that the king gifted him a pair of enchanted gauntlets that allowed him to become arm-wrestling champion six years running. In truth, King Gordok simply threw those gauntlets away, and Mol'dar was the first to find them. ]], 0.695355, 0.760246, 1, 879, 4740, 230, -1, 0, 10},
        {412, "Captain Kromcrush", [[ More than once have hired assassins met their death by accidentally jostling Stomper Kreeg's beer mug. While on duty he often gets drunk and falls asleep, but nothing drives the ogre into a frenzy faster than the sound of his precious beer spilling onto the stone floor. ]], 0.612022, 0.692623, 1, 879, 4734, 230, -1, 0, 11},
        {413, "Cho'Rush the Observer", [[ Ever since Cho'Rush the Observer told him he would meet his future wife while on duty, Guard Fengus has patrolled the lands of King Gordok almost without pause. ]], 0.494536, 0.780738, 1, 879, 4725, 230, -1, 0, 12},
        {414, "King Gordok", [[ Some believe that Guard Slip'kik is simply being cautious, but in truth, on top of that, he is also lazy. Rather than openly challenge King Gordok, Slip'kik tinkers with traps and fiddles with old, broken magical contraptions in the hope that one day he might overthrow the king without any effort at all. ]], 0.266393, 0.571721, 1, 879, 4716, 230, -1, 0, 13},
        {415, "Crowd Pummeler 9-60", [[ Captain Kromcrush is considered very short-tempered even by ogre standards. The slightest hint of an insult to the captain or to King Gordok is enough to set him off. He is quick to deal out punishment, but he has even less patience for those who spread rumors about his long-ago dalliance with a gnoll. ]], 0.318306, 0.506148, 1, 879, 4705, 230, -1, 0, 14},
        {416, "Grubbis", [[ Cho'Rush usually tried to take no one's side, but when Ulrok rose to power, it was already clear that no one could deal with Cho'Rush. The king swiftly made him his chief advisor, reckoning that two heads are better than one. ]], 0.319542, 0.303693, 1, 879, 4673, 230, -1, 0, 15},
        {417, "Viscous Fallout", [[ To rule the ogres of Gordok, one need only declare oneself their king... And then destroy all who disagree. King Gordok, who was then merely Ulrok, seized power by convincing the twelve strongest warriors to attack the king. Most of those who took part in that slaughter died or were wounded, and Ulrok easily slew the exhausted king. To this day the ogres of Gordok still try to speak only in whispers of the 'Day of Blood'. ]], 0.319544, 0.229482, 1, 879, 4666, 230, -1, 0, 16},
    },
    [231] = {
        {418, "'Electrocutioner 6000'", [[ In the heyday of Gnomeregan, gnomes competed with one another by staging battles between their inventions. Engineer Osborne the Tinkerer created an unbeatable robot, earning a reputation as one of the finest mechanics. Sicco Thermaplugg stole his blueprints and built the robot on a giant scale. The robot was set loose, and it caused so much destruction that the authorities punished the wholly innocent Osborne. And Crowd Pummeler 9-60 remains to this day one of Thermaplugg's favorite (and stolen) inventions. ]], 0.431694, 0.883197, 0, 691, 4670, 231, -1, 0, 4},
        {419, "Mekgineer Thermaplugg", [[ According to Thermaplugg's design, the radioactive gas was meant to kill the gnomes and enrage the troggs. The plan worked, but the gas had an unexpected effect on one trogg. Grubbis began to grow. This was a side effect Sicco never anticipated, but he was not one to waste a valuable (and dangerous) specimen. And so the giant trogg now roams the tunnels of Gnomeregan accompanied by his faithful pet - the basilisk Chomper. The basilisk's nose helps find gas leaks, mushrooms, and unwelcome guests. ]], 0.778688, 0.670082, 1, 875, 4690, 231, -1, 0, 1},
        {420, "Noxxion", [[ Of Gnomeregan's once elegant and intricate water supply system, only radiation-tainted, murky streams remain today. The water elemental that lived in the gnomish reservoir was contaminated and lost its natural form. It roams the halls of Gnomeregan, consumed by hatred, like a living embodiment of Thermaplugg's vile treachery. ]], 0.759563, 0.465164, 2, 875, 4691, 231, -1, 0, 2},
        {421, "Razorlash", [[ Engineer Thermaplugg is not known for his patience. Rather than conduct meticulous tests of newly invented equipment for efficiency and safety, he puts his inventions straight to use and moves on to new projects. The 'Electrocutioner 6000', this electricity-supercharged mechanotank, was the engineer's first attempt to use current as a weapon. Lieutenant Thomas 'Sparkfizzle' Crank, the sole survivor of all those who tried to pilot the 'Electrocutioner', is honored among the leper gnomes as a hero. ]], 0.243169, 0.684426, 2, 875, 4692, 231, -1, 0, 3},
        {422, "Tinkerer Gizlock", [[ A murderer, a traitor, and the self-styled king of the gnomes - that is who Engineer Thermaplugg is, ruling unchallenged over the radiation-tainted halls of Gnomeregan. His subjects are the numerous and vicious leper gnomes, deranged just enough to defend their king from any intrusion from the outside world. What makes Thermaplugg especially dangerous is his madness. He is obsessed with a passion for destroying everything around him, undeterred even by fear for his own life. Not for nothing do even the wild beasts fear Thermaplugg. ]], 0.311475, 0.303279, 0, 875, 4702, 231, -1, 0, 5},
    },
    [232] = {
        {423, "Lord Vyletongue", [[ Noxxion is a living embodiment of corruption. Theradras commanded her ally Lord Vyletongue to create this loathsome elemental, that it might serve as a trusty servant and ease her loneliness. Noxxion spreads its poisonous secretions across those parts of Maraudon that have not yet fallen under the princess's pernicious influence. ]], 0.362022, 0.098361, 1, 884, 4709, 232, -1, 0, 1},
        {424, "Celebras the Cursed", [[ Razorlash was created to accompany Noxxion in Maraudon. In time this creature became one of the princess's most beloved servants. Razorlash tirelessly roams the caverns alongside Noxxion, using its thorny tendrils to destroy any vegetation untouched by corruption. ]], 0.166667, 0.344262, 1, 884, 4713, 232, -1, 0, 2},
        {425, "Landslide", [[ Tinkerer Gizlock and five other treasure hunters set out for Maraudon to mine the crystals there, for which merchants offered fortunes. But their plans were not to be realized - the satyrs slew all but Gizlock. The goblin, trapped in the caverns of Maraudon and having lost his mind, now believes himself the new ruler of the underground world. ]], 0.484000, 0.685000, 2, 884, 4721, 232, -1, 0, 3},
        {427, "Rotgrip", [[ The satyr lord Vyletongue descended into the depths of Maraudon upon hearing of the corruption that had stricken it. At first Princess Theradras regarded the cunning demon with suspicion, but he proved his loyalty by creating for her a host of servants, such as Noxxion and Razorlash. ]], 0.378415, 0.704918, 1, 884, 4730, 232, -1, 0, 4},
        {428, "Princess Theradras", [[ Upon learning of the tragic fate of his uncle, the noble Celebras swore to free the spirit of Zaetar. But the keeper of the grove was not ready for the horrors that awaited him in the shadow-infested corridors of Maraudon. The dark energy that saturated this place quickly got the better of Celebras, filling his heart with uncontrollable fury. ]], 0.245902, 0.143443, 2, 884, 4745, 232, -1, 0, 5},
        {429, "Amnennar the Coldbringer", [[ For years the ancient mountain giant named Landslide cultivated beautiful crystals in Maraudon, but then Theradras enslaved him. The once-great giant now drags out a slave's existence, bowing to his new mistress. ]], 0.408470, 0.487705, 2, 884, 4749, 232, -1, 0, 6},
        {430, "Tuten'kash", [[ It is rumored that Rotgrip has dwelt in the underground waters of Maraudon for many thousands of years. The famed dwarven hunter Hemet Nesingwary once declared this beast impossible to find, and scores of trackers set out in search of this legendary creature. None of them returned. ]], 0.413934, 0.817623, 2, 884, 4757, 232, -1, 0, 7},
        {431, "Glutton", [[ The earth elemental Princess Theradras, the only daughter of Therazane the Stonemother, dwells in the inner sanctum of Maraudon. The princess, fallen under the influence of the Old Gods, has turned her home into an abode of corruption and suffering. Some believe that her power is inextricably bound to the spirit of her dead beloved - Zaetar. If this is true, then freeing the dead keeper of the grove is perhaps the only chance to cleanse Maraudon. ]], 0.258197, 0.788934, 2, 884, 4759, 232, -1, 0, 8},
    },
    [233] = {
        {1141, "Plaguemaw the Rotting", [[ The lich Amnennar was one of the most fearsome members of the Scourge. He took part in the assault on Mount Hyjal during the Third War. Later the Lich King ordered his servant to remain in Kalimdor and set about expanding the Scourge's influence. The heroes of the Horde and the Alliance must stop the cunning lich, and bring at least relative peace to Razorfen Downs. ]], 0.455090, 0.582335, 0, 887, 9484, 233, -1, 0, 5},
        {1142, "Mordresh Fire Eye", [[ The arachnomancers of the Death's Head tribe take great pride in having, after many fruitless attempts, finally created a reliable guardian for Amnennar. His name is Tuten'kash. The resurrected nerubian will engage in battle with anyone who summons him by striking the gong three times. ]], 0.589820, 0.342815, 0, 887, 9491, 233, -1, 0, 1},
        {1143, "Ragglesnout", [[ Glutton, one of Amnennar's new creations, is an attempt to recreate Tartek the Ferocious, who was considered the finest abomination ever made. Tartek slew many a quillboar, but in the end he fell. Oozing bile, pus, and other revolting fluids, Glutton guards Razorfen Downs, and his hunger is insatiable. ]], 0.345310, 0.664671, 0, 887, 9496, 233, -1, 0, 3},
        {1146, "Agathelos the Raging", [[ The only one of his tribe to escape the embrace of undeath, Ragglesnout hides in Razorfen Downs, and at times he is impossible to find. An adept of dark magic, Ragglesnout will attack any foe without hesitation, and that battle will be no easy one. ]], 0.430140, 0.627246, 0, 760, 9527, 233, -1, 0, 4},
        {433, "Death Speaker Jargba", [[ Resorting to necromancy, Amnennar managed to rekindle the flame in the soul of Mordresh Fire Eye and raise him from the dead. Mordresh, who in his former life was a shaman, commands the elements through unholy magic. He incinerates all who might thwart the plans of the Frostbringer. ]], 0.860656, 0.467213, 0, 887, 4767, 233, -1, 0, 2},
    },
    [234] = {
        {11638, "Aggem Thorncurse", [[ The quillboar consider the reading of stones and crystals the highest form of shamanism. Roogug served the quillboar people for many years, slowly mastering the magical arts. Now he fulfills the role of the quillboar's chief geomancer. ]], 0.648000, 0.421000, 0, 888, 20876, 234, -1, 0, 0},
        {11639, "Overlord Ramtusk", [[ Agathelos is a colossal armored boar, roughly twice the size of an ordinary thunder lizard, and grew larger still when enraged. He was kept in a short tunnel guarded by several quillboar who maintained a field to lock the monstrous creature away. Considering that the god and progenitor of the quillboar - Agamaggan, the titanic boar - such an animal as Agathelos holds great spiritual significance. ]], 0.079000, 0.685000, 0, 888, 20879, 234, -1, 0, 4},
        {895, "Blind Hunter", [[ The death's-head heralds of the Death's Head tribe serve two functions: spreading propaganda and applying measures of persuasion to those who refuse to submit to Charlga Razorflank and her mysterious new allies. Jagba is prized among the death's-head heralds for his ability to control the minds of dissenters and force them to accept the will of the leaders. ]], 0.872328, 0.410829, 0, 888, 20013, 234, -1, 0, 2},
        {896, "Charlga Razorflank", [[ Shamanism is an inseparable part of quillboar society, and the tribe's finest shaman bears the title of Prophet of Agamaggan. Calling upon the power of their demigod ancestor, the prophets can summon boar spirits to aid them in battle, just as ordinary shamans summon wolf spirits. ]], 0.807336, 0.517180, 0, 888, 8646, 234, -1, 0, 1},
        {899, "Cannon Master Willey", [[ The commander of the Death's Head tribe's forces, Overlord Ramtusk, is a quillboar still sturdy despite his age, on whose thick hide one can see the scars earned in battles against centaurs, harpies, orcs, and even tauren. The seasoned Ramtusk confidently commands his army, never letting his age get the better of him. Defeating him would surely deal a serious blow to the Death's Head tribe. ]], 0.574939, 0.305955, 0, 888, 8660, 234, -1, 0, 3},
        {900, "Timmy the Cruel", [[ From the depths of dark caverns has come a monstrous creature that for long years lived far from the rest of the world. This giant bat tirelessly devours the flesh of the boar named Agathelos the Raging, which once drew dark energy from bat guano. ]], 0.089397, 0.548399, 0, 888, 20015, 234, -1, 0, 4},
        {901, "The Unforgiven", [[ The leader of the Death's Head and Razorfen tribes, Charlga Razorflank, known as 'the Hag', rose to power swiftly and decisively. Her aim is to resurrect the demigod Agamaggan, but the dark and cruel rituals that Charlga conducts with her minions run counter to the nobility and the teachings of the Ancient. ]], 0.219597, 0.311669, 0, 888, 20017, 234, -1, 0, 5},
    },
    [236] = {
        {443, "Postmaster Malown", [[ During the Culling of Stratholme, thousands of people were slain whose only crime was to find themselves in a doomed city. One such victim was the wandering minstrel and flutist Forresten. He continues to wander the city, unable to reconcile himself to his tragic fate. ]], 0.605191, 0.313524, 1, 892, 4794, 236, -1, 0, 1},
        {445, "Stonespine", [[ Timmison was infamous for his bloodlust on the field of battle. Some supposed that the cause of this sadism was to be sought in Timmison's childhood, when he was constantly bullied. After he was reborn in the form of a Scourge monster, these memories torment him constantly, compelling him to answer to the name he once hated: Timmy. ]], 0.499999, 0.178279, 1, 892, 4799, 236, -1, 0, 2},
        {446, "Cannon Master Willey", [[ Balnazzar greatly enjoyed encouraging the destructive abilities of Cannon Master Willey, calling his servant the Crusher of Hopes. The dreadlord sees the irony in the fact that Willey and the other Scarlet Crusaders, who so hated the undead, became the very same after death. ]], 0.047814, 0.506148, 1, 892, 4807, 236, -1, 0, 4},
        {448, "Instructor Galford", [[ In his time, Archivist Galford took pride in caring for the order's most precious documents. But as he lay dying, he watched in horror as his precious tomes were reduced to ash. Balnazzar used these terrible memories to imbue his servant with a fury that Galford never possessed in life. ]], 0.277323, 0.754099, 1, 892, 4808, 236, -1, 0, 5},
        {449, "Balnazzar", [[ Balnazzar never knew what death was, but the bitter taste of defeat was well known to him. After the Cataclysm shook the world, he slew the Scarlet Crusaders in Stratholme and turned them into the undead they so hated. Now the dreadlord schemes to take his revenge on Azeroth. ]], 0.204918, 0.821721, 1, 892, 4828, 236, -1, 0, 6},
        {450, "The Unforgiven", [[ Lilian was a model of righteousness among her people. After Arthas ordered his troops to purge the city, she lost her mind, seeing so many innocents perish by her hand. She fell upon her own sword to escape madness. Now she is doomed to exist in the form of a ghost; for what she did, she is forever denied forgiveness. ]], 0.734973, 0.204918, 1, 892, 4833, 236, -1, 0, 7},
        {451, "Baroness Anastari", [[ In life, Anastari achieved what she desired by any means. Death did not change this. When her soul tore free of her body and she became a banshee, her craving for worldly goods gave way to more sinister desires. ]], 0.745902, 0.469262, 2, 892, 4841, 236, -1, 0, 8},
        {452, "Nerub'enkan", [[ Nerub'enkan was a skilled warrior of the time of the Spider War. In the end she perished from her wounds and was raised into undeath, becoming a submissive servant of the Scourge. Now she guards the ziggurat in Stratholme no less zealously than she defended her own home in life. ]], 0.572404, 0.461065, 2, 892, 4845, 236, -1, 0, 9},
        {453, "Maleki the Pallid", [[ Maleki was one of the first to join the Cult of the Damned, demonstrating incredible skill in wielding the chill of the grave. Driven by an endless thirst for power, the mage continues to hone his skills in dark magic, to prepare for the moment when he is reborn in the form of a lich. ]], 0.674864, 0.227459, 2, 892, 4851, 236, -1, 0, 10},
        {454, "Magistrate Barthilas", [[ Baron Bartilas... no. Bartilas was among the innocents whom Arthas and his troops slew during the Culling of Stratholme. Afterward the Lich King raised the former magistrate from his grave and ordered the dread undead to guard his ruined home. ]], 0.640000, 0.790000, 2, 892, 4855, 236, -1, 0, 11},
        {455, "Ramstein the Gorger", [[ Ramstein is one of the most renowned creations of the Scourge, a nightmarish creature fashioned from countless dead bodies and driven by an insatiable hunger. When the Scourge's forces seized Stratholme, this monster wrought unimaginable atrocities there, destroying thousands of innocent souls. ]], 0.456284, 0.198771, 2, 892, 4859, 236, -1, 0, 12},
        {456, "Baron Rivendare", [[ An instrument of the Scourge, the merciless Baron Rivendare, a rider of Naxxramas, betrayed humanity while still in life, trading his loyalty for the dark power of the Scourge. It was Rivendare who was responsible for the destruction of Stratholme and the hordes of undead that now reign there. ]], 0.386612, 0.200820, 2, 892, 4862, 236, -1, 0, 13},
        {749, "Commander Malor", [[ Malor, together with a handful of other brave warriors, risked everything to defend the bastion of the Scarlet Crusade from the hordes of undead. Alas, they were defeated. Balnazzar turned the fearless commander into one of his servants, and Malor became a terrible parody of his former self. ]], 0.299320, 0.411874, 1, 892, 6452, 236, -1, 0, 3},
    },
    [237] = {
        {11643, "Atal'alarion", [[ Atal'alarion is the sworn protector of the idol found on the lower level of the temple. To summon him, you must activate the statues in the correct order. ]], 0.243169, 0.459016, 1, 687, 20907, 237, -1, 0, 0},
        {11644, "Loro", [[ Loro is an undead troll dwelling in the Temple of Atal'Hakkar. He is a servant of Jammal'an the Prophet and will give his life to protect his master's secrets. ]], 0.243169, 0.459016, 1, 687, 20909, 237, -1, 0, 3},
        {11645, "Hukku", [[ Hukku is an undead troll dwelling in the Temple of Atal'Hakkar. Hukku is accompanied by his demonic guards. He, like his brothers, serves Jammal'an. ]], 0.243169, 0.459016, 1, 687, 20911, 237, -1, 0, 3},
        {11646, "Midnight", [[ Mijan is an undead troll dwelling in the Temple of Atal'Hakkar. A former healer of the Atal'ai clan who swore to serve his master. ]], 0.243169, 0.459016, 1, 687, 20913, 237, -1, 0, 3},
        {11647, "Zolo", [[ Zul'Lor is an undead troll dwelling in the Temple of Atal'Hakkar. Once one of the mightiest warriors of his clan, he now serves the Prophet and his ends. ]], 0.243169, 0.459016, 1, 687, 20917, 237, -1, 0, 3},
        {11648, "Zolo", [[ Zolo is an undead troll dwelling in the Temple of Atal'Hakkar. Once one of the mightiest warriors of his clan, he now serves the Prophet and his ends. ]], 0.243169, 0.459016, 1, 687, 20919, 237, -1, 0, 3},
        {11649, "Gasher", [[ Gasher... no. Ranok is an undead troll dwelling in the Temple of Atal'Hakkar. A skilled fighter of the Atal'ai clan, in life he was the swiftest warrior, and when he became undead he gained incredible endurance as well. ]], 0.243169, 0.459016, 1, 687, 20921, 237, -1, 0, 3},
        {457, "Avatar of Hakkar", [[ Hakkar was known for demanding blood sacrifices from his worshippers. In ancient times he commanded the Atal'ai tribe to worship his avatar, feeding it with the blood of victims. At present the Atal'ai priests are trying to resurrect the avatar of Hakkar through a renewed ritual, which calls for the sacrifice of green dragons. If the Atal'ai succeed, the hour of Hakkar's avatar's rebirth will be the last hour of Azeroth. ]], 0.243169, 0.459016, 0, 687, 4903, 237, -1, 0, 1},
        {458, "Jammal'an the Prophet", [[ Jammal'an the Prophet is the leader of the Atal'ai tribe, which unites the fanatical priests of Hakkar. Jammal'an had a vision in which it was revealed to him how to resurrect Hakkar with the blood of his enemies, the green dragons. Jammal'an and his undead bodyguard, Ogom the Wretched, are ready to repel any who would hinder Hakkar's return to this world, though that return may plunge Azeroth into a true nightmare... the Emerald Nightmare. ]], 0.760929, 0.459016, 0, 687, 4934, 237, -1, 0, 2},
        {459, "Dreamscythe", [[ Four young, promising dragons set out with Eranikus to the Temple of Atal'Hakkar, ready to prove their devotion to the mighty wyrm. One by one they fell into traps and found themselves in the Emerald Nightmare. Now they roam the halls of the Temple, lashing out at any who disturb their somnambulant wandering. ]], 0.499151, 0.870309, 0, 687, 6114, 237, -1, 0, 3},
        {463, "Shade of Eranikus", [[ Eranikus, the former consort of Ysera, was sent to the ruins of the Temple of Atal'Hakkar to prevent Hakkar's return. But no sooner had Eranikus and his retinue entered the temple than they fell victim to the dark powers dwelling there. In the waking world only a shadow of Eranikus remains, while he himself is trapped on the path to the Emerald Dream. Despite the misfortune that has befallen Eranikus, he can still fight off his foes, drenching them in corrosive venom or plunging them into a deep slumber. ]], 0.670765, 0.877049, 0, 687, 4950, 237, -1, 0, 7},
    },
    [238] = {
        {464, "Dextren Ward", [[ Rarely in a prison filled with scum and true monsters does one see a man like Dextren Ward. The first thought of one unfamiliar with this prisoner's history would be - 'And for what sins did this man end up here?' But it is not for nothing that the prisoners keep silent at such questions - for this man dug up corpses from the Raven Hill Cemetery and sold them to the necromancer Morbent Fel. ]], 0.218579, 0.262295, 0, 874, 4811, 238, -1, 0, 1},
        {465, "Frenzied Brittlebone", [[ One of the grimmest prisoners of the Stockade, a half-mad ogre armed with a butcher's cleaver - that is what Bazil Thredd... no. That is what Kam Deepfury is. Now that chaos reigns in the Stockade, he has resumed his bloody work. ]], 0.784153, 0.452869, 0, 874, 4814, 238, -1, 0, 2},
        {466, "Targorr the Dread", [[ A scion of an orc clan dwelling in Blackrock Mountain, Targorr earned the epithet 'the Dread' for his utter ruthlessness and his skill at striking with two swords at once. An orc in a human prison is a rare sight, so it is no wonder that all the prisoners fear Targorr. In any case, he now has a fine opportunity to put his cunning skill to use. ]], 0.497268, 0.221312, 0, 874, 4817, 238, -1, 0, 3},
    },
    [239] = {
        {467, "Revelosh", [[ Some luminaries of science in the prestigious Explorers' League, located in Ironforge, believe there is a blood bond between their people and the troggs. In their view, the proof of this is that the troggs' passion for the artifacts of the titans differs little from the dwarves' interest in those wondrous devices. If their theory is correct, then the trogg Revelosh may be considered an archaeologist, though any adventurers who happen upon him would sooner call him a thief. ]], 0.534153, 0.725410, 1, 876, 4820, 239, -1, 0, 1},
        {468, "The Lost Dwarves", [[ In search of glory and, more importantly, riches, three brothers - Eric, Olaf, and Baelog - signed a contract with the Explorers' League and set out for the halls of Uldaman to clear the way for the explorers who would come after them. Alas, for these three vrykul... dwarves, 'clearing the way' meant 'getting hopelessly lost in the ancient labyrinth.' But the proud dwarves tried to the very end to protect the secrets of the Explorers' League and Uldaman from the Horde. ]], 0.584699, 0.920082, 1, 876, 4869, 239, -1, 8, 2},
        {469, "Ironaya", [[ To raise the vast halls of Uldaman, the titans made use of servants. The Pantheon charged the watcher Ironaya with overseeing the construction and upkeep of Uldaman, but the years passed, and the once-beautiful place now lies in ruins. Ironaya spent a thousand years in stasis, analyzing the master plan drawn up by Khaz'goroth, in search of a way to restore the Uldaman complex. ]], 0.372951, 0.739754, 1, 876, 4876, 239, -1, 0, 3},
        {470, "Ancient Stone Keeper", [[ The Ancient Stone Keeper is one of the many golems that labored in the great vault of the titans. He was an intermediary between the watchers, who directed all the work, and their servants. After the corruption of the Obsidian Sentinel, the Ancient Stone Keeper remained the last golem created by the titans, and now he will guard their secrets until he ceases to exist. ]], 0.475410, 0.440574, 1, 876, 4879, 239, -1, 0, 5},
        {471, "Galgann Firehammer", [[ When the dwarves of the Bronzebeard clan discovered Uldaman, the Dark Iron clan invaded the vault to prevent their blood enemies from gaining access to the powerful artifacts stored there. Grawmug... no. Galgann Firehammer - a senator from Shadowforge - went personally to oversee how the excavation of Uldaman was proceeding, so that the emperor might use the destructive power of the artifacts against the enemies of the Dark Iron clan. ]], 0.267760, 0.327869, 1, 876, 4880, 239, -1, 0, 6},
        {472, "Grimlok", [[ Among the troggs, the largest, strongest, and fiercest becomes chief by proving his strength. But Grimlok's particular distinction is that he managed to control the troggs, keeping them in fear through psychological attacks. Having subdued a basilisk, he threatened to turn to stone any who dared cross him. ]], 0.219945, 0.256148, 1, 876, 4886, 239, -1, 0, 7},
        {473, "Archaedas", [[ Somewhere in the depths of Uldaman there is a hall that holds one of the most precious treasures of the titans, created by Norgannon himself. But to this day no one has managed to reach the relic, for it is guarded by the mighty Archaedas and his minions. Archaedas is hewn from ancient, hard stone quarried in the mines of Uldaman, and he is as formidable as he is old. ]], 0.553279, 0.504098, 2, 876, 4894, 239, -1, 0, 8},
        {748, "Obsidian Sentinel", [[ The Obsidian Sentinel kept unceasing watch over the secrets of Uldaman, until it was struck by a corruption of unknown origin. The Sentinel, created from the same stone as the halls of Uldaman, is composed almost entirely of dark glass that reflects spells. The source of the corruption that struck the obsidian sentinel was likely incredibly powerful - it is no easy matter to alter enchanted stone created by the titans. ]], 0.289425, 0.597403, 1, 876, 6448, 239, -1, 0, 4},
    },
    [240] = {
        {474, "Lady Anacondra", [[ Lady Anacondra was the first to volunteer to go with Naralex when he set out for the Barrens. After her mentor's nightmare damaged her mind, the young acolyte renounced her name and began foretelling a terrible future for Azeroth. ]], 0.281000, 0.318000, 0, 749, 4954, 240, -1, 0, 1},
        {475, "Lord Cobrahn", [[ Lord Cobrahn's gift for taking the forms of beasts earned him the respect of the druids of the Cenarion Circle. Unfortunately, the corruption of the Wailing Caverns twisted his ability, and he came to master only the power to transform into a serpent. Because of this new sinister form he chose for himself the name Cobrahn. ]], 0.166667, 0.567623, 0, 749, 4958, 240, -1, 0, 3},
        {476, "Lord Pythas", [[ Naralex's childhood friend, the warrior Arin, had a fine talent for the druidic arts. But despite this, the acolyte could not resist the corruption that robbed him of his mind. Arin took the name Lord Pythas, and uses his combat skills and druidic spells to destroy uninvited guests. ]], 0.856000, 0.293000, 0, 749, 4965, 240, -1, 0, 2},
        {477, "Kresh", [[ Through the Wailing Caverns roams one of its most ancient inhabitants - a giant turtle. Naralex's nightmares failed to alter its peaceable nature, and yet one should not place too much trust in its friendliness. Kresh has more than once driven off travelers who coveted its enormous shell. ]], 0.385246, 0.360656, 0, 749, 20008, 240, -1, 0, 4},
        {478, "Skum", [[ Skum went to the Wailing Caverns to rest from the hostility of the Barrens in which he lived. But, like many of the caverns' inhabitants, he quickly succumbed to the corruption. Now dark energy flows through his veins, having turned him into a strong and merciless beast that knows no remorse. ]], 0.932000, 0.795000, 0, 749, 4970, 240, -1, 0, 5},
        {479, "Lord Serpentis", [[ The leader of the druids of the fang was once one of Naralex's most brilliant students. But he turned to evil, and this kept him from realizing his cherished dream of becoming a shan'do, an 'honored teacher', like Naralex himself. Madness crept ever deeper into his soul, and Serpentis drew his kin to his side and created the order of the 'Druids of the Fang'. ]], 0.616120, 0.538935, 0, 749, 4971, 240, -1, 0, 6},
        {480, "Verdan the Everliving", [[ Little is known of this creature's fate before Naralex came to the Wailing Caverns. Although Verdan the Everliving was originally a protector of the caverns, he too fell under the influence of the corruption that struck his home. Verdan joined the mad druids, and is ready to destroy any who intrude upon their domain. ]], 0.554645, 0.465164, 0, 749, 4974, 240, -1, 0, 7},
        {481, "Mutanus the Devourer", [[ In the darkest recesses of Naralex's fevered mind, the corruption that has seized the Emerald Dream took the form of the druid's most terrible foe - a murloc. The monstrous creature, called Mutanus, appeared in this world to destroy any who would free Naralex from the grip of the Nightmare that has consumed him. ]], 0.345628, 0.137295, 0, 749, 4975, 240, -1, 0, 8},
    },
    [241] = {
        {483, "Gahz'rilla", [[ According to legend, Gahz'rilla was a favorite of the Old Gods, and perhaps even a demigod. Be that as it may, for a thousand years the trolls of the Sandfury clan worshipped this creature. Knowing well the nature of this beast, the trolls dare not show themselves before the insatiable Gahz'rilla without ample sacrifices. ]], 0.280942, 0.382783, 0, 871, 4981, 241, -1, 0, 2},
        {484, "Antu'sul", [[ Antu'sul wants his sul'lithuz basilisks to be strong and merciless. He treats them like members of his family, and no one, not even other trolls, is permitted to harm his precious hatchlings. Instead of burying his foes, Antu'sul lets the basilisks feed on those who dare cross him. ]], 0.646175, 0.276639, 0, 871, 4986, 241, -1, 0, 3},
        {485, "Theka the Martyr", [[ Long ago the martyr Theka was slain in the bloody war between the people of Ahn'Qiraj and the trolls. Zul'Farrak survived only thanks to his sacrifice. Even after death Theka watches over his beloved city. It is said that his slayers - a dozen swarm warriors - were turned into mindless scarabs, doomed to remain forever beside Theka. ]], 0.531421, 0.262295, 0, 871, 5005, 241, -1, 0, 4},
        {486, "Witch Doctor Zum'rah", [[ The mighty loa Bwonsamdi watches over the souls of the Darkspear trolls, but many trolls of the Sandfury tribe are denied this protection after death. Their tormented souls are bound to Zum'rah - a cruel witch doctor who uses dark magic to capture the souls of the dead. ]], 0.442623, 0.176230, 0, 871, 5011, 241, -1, 0, 5},
        {487, "Nekrum and Sezz'ziz", [[ By some mysterious means Nekrum Gutchewer continues to live after death, and his decaying body is still able to aid Shadowpriest Sezz'ziz. Together these trolls have gathered to offer sacrifices to the mythical beast Gahz'rilla, who sleeps in the heart of the city. Many trolls eagerly await the awakening of this creature and will do anything to see the ritual carried out. ]], 0.296448, 0.174180, 0, 871, 5019, 241, -1, 0, 6},
        {489, "Chief Ukorz Sandscalp", [[ Chief Ukorz Sandscalp is obsessed with the thought of restoring his tribe's former glory. He was raised on stories of the times when the trolls ruled these lands, unhindered by goblins, gnomes, pirates, ogres, and other foreigners. Sandscalp asked his faithful companion Ruuzlu to help him begin a new chapter in the history of the Sandfury clan in the only way he knows - through violence. ]], 0.422131, 0.329918, 0, 871, 5025, 241, -1, 0, 8},
    },
    [247] = {
        {523, "Shirrak the Dead Watcher", [[ Created by the exarch Maladaar himself, Shirrak was meant to defend the spirits of the dead draenei dwelling in the Auchenai Crypts. In appearance it is a horrid mass of eyes, teeth, and tentacles. This creation of the exarch ravenously devours arcane energy and will by no means tolerate the intrusion of mortals into its abode. ]], 0.463115, 0.680327, 2, 722, 5038, 247, -1, 0, 1},
        {524, "Exarch Maladaar", [[ Maladaar is the last surviving representative of a great people, whose proud sons once dwelt in the Auchenai halls. The sudden loss of everyone and everything that was ever dear to him drove him utterly mad. His mad desire to preserve the memory of his kin through the ages compelled him to take up dark magic. ]], 0.739071, 0.508196, 2, 722, 5042, 247, -1, 0, 2},
    },
    [248] = {
        {527, "Watchkeeper Gargolmar", [[ Having earned an ill name in Outland, Watchkeeper Gargolmar devours the hearts of those who fall into his clutches near the Hellfire Citadel, regardless of whether they were trying to get inside or not. Kargath Bladefist charged him with defending the fortress walls, and the watchkeeper Gargolmar carries out his duties without question. ]], 0.733000, 0.310000, 1, 848, 5049, 248, -1, 0, 1},
        {528, "Omor the Unscarred", [[ Omor the Unscarred was a student of Hakkar the Houndmaster, and so after his teacher's defeat during the War of the Ancients he took the legendary warrior's felhounds into his care. Since that time no one has yet managed to defeat Omor in combat. Now this venerable demon is Illidan's emissary to the fel orcs in the Hellfire Citadel. ]], 0.390710, 0.204918, 1, 848, 5057, 248, -1, 0, 2},
        {529, "Vazruden the Herald", [[ Vazruden guards the supply lines between the Hellfire Citadel and the Black Temple, along which reinforcements, provisions, and dispatches move. Vazruden rides upon the magnificent nether dragon Nazan: together they embody an unstoppable force, able to destroy the enemy with fire and claw, soaring through the skies with a piercing shriek. ]], 0.354000, 0.826000, 1, 848, 5064, 248, -1, 0, 1},
    },
    [250] = {
        {534, "Pandemonius", [[ The loathsome pit lord Pandemonius is also known as the Duke of Chaos, the Devourer of Nations, and the Doom of Worlds. He was one of the commanders under Dimensius when the ethereals' homeworld of K'aresh was destroyed. Later he was enslaved by Prince Kael... no, by Nexus-Prince Shaffar, and continued to sate his endless hunger in the service of the ethereals. ]], 0.479508, 0.297131, 1, 842, 5188, 250, -1, 0, 1},
        {535, "Tavarok", [[ By the command of Kael'thas Sunstrider, Pathaleon the Calculator summoned a mighty colossus, which was meant to gather the arcane energy flowing from beneath the Mana-Tombs. Tavarok was suddenly transformed under the influence of an unusual surge of energy - in this way it rid itself of Pathaleon's corrupting influence and lost its red hue. The white colossus gained a will of its own and is now ready to consume any who dare stand in its path. ]], 0.609289, 0.741804, 1, 842, 5191, 250, -1, 0, 2},
        {536, "Yor", [[ The voidhound Yor, a beast unmatched in fury and might, was a gift from Illidan Stormrage to Nexus-Prince Shaffar. His advisors tried to warn the prince, believing that a demonic creation was likely meant to betray Shaffar should he cease to be of use to Illidan. The prince fed his advisors to Yor... but ever since he has kept the beast in a stasis chamber - just in case. ]], 0.356557, 0.608607, 1, 732, 5194, 250, 2, 0, 3},
        {537, "Prince Shaffar", [[ Convinced that vast riches lay hidden in the depths of the Mana-Tombs, Nexus-Prince Shaffar spent enormous sums from his considerable fortune to bring an army into the gloomy halls of these ruins and to keep rival ethereals from getting inside. The prince's greed knew no bounds, and he swore that he would uncover the secrets of the Mana-Tombs or perish. ]], 0.323770, 0.491803, 1, 842, 5196, 250, -1, 0, 4},
    },
    [252] = {
        {541, "Darkweaver Syth", [[ Darkweaver Syth received orders from the raven lord Ikiss to defend the Sethekk Halls while the rebellious arakkoa sought their mysterious god. This shrewd, year-wise schemer is a master of dark magic, and the very elements bow to his will. ]], 0.487705, 0.680328, 1, 833, 5230, 252, -1, 0, 1},
        {542, "Anzu", [[ Anzu, the mysterious bird-deity worshipped by the wildest arakkoa, resembles no other god of Outland's pantheon, neither in origin nor in powers. The naaru say nothing of this malevolent being, for even they know nothing of Anzu's true purposes. ]], 0.326503, 0.545082, 2, 723, 5248, 252, 2, 0, 2},
        {543, "Talon King Ikiss", [[ The raven lord Ikiss was the charismatic spiritual leader of a band of brave arakkoa who left their home in the Terokkar Forest in search of the god promised to them. In his sleep visions of this god appeared to him, and he knew it could be found deep within the ruined halls of Auchindoun. Ikiss went mad from the visions, and now claims to be the resurrected Terokk, the divine hero of arakkoa myth. ]], 0.326503, 0.276639, 2, 833, 5256, 252, -1, 0, 3},
    },
    [253] = {
        {544, "Ambassador Hellmaw", [[ A mighty servant of demons and a minister of pain, Ambassador Hellmaw has devoted himself to the art of death. Nothing gives him greater pleasure than the taste of a mortal's blood with its rich bouquet of terror and despair. The fel orcs of the Shadow Labyrinth captured Hellmaw and now feed him prisoners, so that the demon may gather strength and better serve his dark masters. ]], 0.218579, 0.395492, 1, 834, 5261, 253, -1, 0, 1},
        {545, "Blackheart the Inciter", [[ When the Horde of orcs first invaded Azeroth through the Dark Portal, two members of the Shadow Council turned their gaze upon the ancient draenei burial ground, Auchindoun. The restless spirits of those lands proved excellent test subjects for the warlock Blackheart, and allowed him to develop his mind-control skills. ]], 0.267760, 0.704918, 1, 834, 5263, 253, -1, 0, 2},
        {546, "Grandmaster Vorpil", [[ In the days of the Horde's rise, the grand warlock Murmur... no. In the days of the Horde's rise, Grandmaster Vorpil convinced the orc warlock Gul'dan to allow him to explore the secrets of Auchindoun. He secretly desired to harness the energy of the frighteningly powerful cosmic entities with which this region was saturated. ]], 0.531421, 0.540983, 1, 834, 5266, 253, -1, 0, 3},
        {547, "Murmur", [[ Long, long ago... In a galaxy far, far away... No, that is no way to describe the origin of this elemental. He embodies destruction in its purest form. At the slightest whim he can shatter worlds into countless fragments. Only true madmen would dare summon this being. Perhaps there is still time to banish Murmur, before he has fully entered into Outland. ]], 0.808743, 0.391393, 1, 834, 5272, 253, -1, 0, 4},
    },
    [254] = {
        {548, "Zereketh the Unbound", [[ Most creatures of the Tempest Keep require the constant attention of their masters, but some void wraiths need no commands. Zereketh the Unbound stands guard at the entrance to the Arcatraz and is ready to slay any who dare to challenge him. ]], 0.592896, 0.243853, 1, 841, 5279, 254, -1, 0, 1},
        {549, "Dalliah the Doomsayer", [[ Before she was captured by the naaru, Dalliah was one of the cruelest and most bloodthirsty warriors in the Burning Legion. Sharing a cell with Wrath-Scryer Soccothrates clearly did nothing to improve her temperament either. ]], 0.363388, 0.782787, 2, 841, 5283, 254, -1, 0, 2},
        {550, "Wrath-Scryer Soccothrates", [[ Many thousands of years ago, Socrethar was held in high regard among the wrathguards and was considered one of the finest commanders of the Burning Legion. Imprisonment did nothing to humble his ego. The same can be said of his cellmate. ]], 0.199454, 0.786885, 2, 841, 5291, 254, -1, 0, 3},
        {551, "Harbinger Skyriss", [[ The naaru believed that the voice of Harbinger Skyriss, capable of making his victims believe anything, would be silenced forever once they captured him and plunged him into a deep, dreamless sleep. The unfortunate warden of the Arcatraz learned firsthand that the naaru were wrong. Skyriss had enough power to speak to Warden Mellichar in his soft, insinuating voice, and in time he achieved his goal. ]], 0.616120, 0.307377, 3, 841, 5298, 254, -1, 0, 4},
    },
    [256] = {
        {555, "The Maker", [[ All creatures who wield fel magic—whether willingly or not—gradually take on the appearance of demons. The Maker accelerates their corruption and conducts cruel experiments on any who try to resist. ]], 0.386612, 0.418033, 1, 835, 5356, 256, -1, 0, 1},
        {556, "Broggok", [[ Some occasionally come to doubt whether they should remain loyal to their terrible new masters. Broggok makes certain that any free thinking among the fel orcs is utterly stamped out. ]], 0.433060, 0.219262, 1, 835, 5367, 256, -1, 0, 2},
        {557, "Keli'dan the Breaker", [[ When Illidan overthrew the pit lord Magtheridon and established his rule in Outland, he imprisoned the demon leader within Hellfire Citadel. Only the strongest fighter in Illidan's army could keep him there, and the choice fell upon a ruthless orc named Keli'dan. ]], 0.583333, 0.411885, 1, 835, 5382, 256, -1, 0, 3},
    },
    [257] = {
        {558, "Commander Sarannis", [[ When the demonically influenced blood elf leader Kael'thas seized Tempest Keep, he immediately ordered Commander Sarannis to prepare to repel the warriors the naaru might send to retake the fortress. ]], 0.442623, 0.233607, 1, 839, 5401, 257, -1, 0, 1},
        {559, "High Botanist Freywinn", [[ Mere minutes after Freywinn arrived in the Botanica, he set about the dangerous experiments through which he hoped to master the power hidden within the plants of Outland. ]], 0.241803, 0.227459, 1, 839, 5418, 257, -1, 0, 2},
        {560, "Thorngrin the Tender", [[ Experiments require materials. Thorngrin the Tender must supply Kael'thas's botanists with enough essence and energy to unlock the secrets of the naaru, even if it means countless living creatures perish as a result of the experiments. ]], 0.073770, 0.481557, 1, 839, 5460, 257, -1, 0, 3},
        {561, "Laj", [[ The naaru gathered unusual wild creatures from across Outland. Their pens were destroyed during the seizure of the Botanica, allowing some of the most dangerous species to break free. ]], 0.340164, 0.862706, 1, 839, 5463, 257, -1, 0, 4},
        {562, "Warp Splinter", [[ The night elves of Darnassus asked for help restoring a tree of arcane magic that became trapped within Tempest Keep. Warp Splinter, frightened by the recent assault of Kael'thas Sunstrider's minions, cannot tell friend from foe and will attack anyone who disturbs it. ]], 0.342896, 0.368853, 1, 839, 5476, 257, -1, 0, 5},
    },
    [258] = {
        {563, "Mechano-Lord Capacitus", [[ Using the naaru's mana accumulators demands great dexterity and precision, and both of these qualities will prove most useful in defending against an invasion. ]], 0.513661, 0.315574, 1, 840, 5479, 258, -1, 0, 1},
        {564, "Nethermancer Sepethrea", [[ Thanks to her ability to swiftly summon creatures in battle against her foes, Sepethrea was chosen as an apprentice to a blood elf named Pathaleon the Calculator, who rules within the Mechanar. ]], 0.478142, 0.202869, 2, 840, 5484, 258, -1, 0, 2},
        {565, "Pathaleon the Calculator", [[ After the defiling of the Sunwell, the vain sorcerer Pathaleon saw an opportunity to win glory and to aid Kael'thas in his search for a cure for his race's addiction to magic. So he resolved to join the blood elf prince in Outland, to oversee the progress of the prince's terrible experiments. Recently, Pathaleon has taken to studying the enigmatic technologies within Tempest Keep, hoping to seize power and renown. ]], 0.271858, 0.610656, 2, 840, 5489, 258, -1, 0, 3},
    },
    [259] = {
        {566, "Grand Warlock Nethekurse", [[ The Voidblade was once a shaman of the Shadowmoon clan who renounced his mastery over the elements and chose to embrace fel magic. The demonic energy he came to wield left nothing of him but an empty shell, and now the former shaman delights only in torturing young fel orcs to test the limits of their spiritual and physical endurance. ]], 0.333333, 0.620902, 1, 843, 5497, 259, -1, 0, 1},
        {568, "Warbringer O'mrogg", [[ The ruthless and cunning ogre O'mrogg is considered one of the deadliest members of the Fel Horde. But this dangerous brute has a peculiar problem: the ogre's two heads have always argued over even the simplest of matters. Two years ago, O'mrogg considered enrolling in a rehabilitation program to reconcile the two halves of his personality, yet his heads have still not decided whether it's worth the trouble. ]], 0.542350, 0.342213, 1, 843, 5893, 259, -1, 0, 3},
        {569, "Warchief Kargath Bladefist", [[ Chieftain of the Shattered Hand clan and warchief of the Fel Horde, Kargath is one of the greatest orc heroes of recent memory. Long ago he severed both his own hands and replaced them with weapons, in keeping with a bloody ritual practiced only by his clan. Orcs tell legends of the joy he takes in inflicting pain upon those around him and upon himself. As the absolute ruler of the Fel Horde, he has bent all his malice and ferocity toward forging an unbeatable army within the iron walls of Hellfire Citadel. ]], 0.673497, 0.545082, 1, 843, 5898, 259, -1, 0, 4},
        {728, "Blood Guard Porung", [[ During the bloody siege of Shattrath, Porung fought against a handful of draenei paladins barricaded at the far end of the city. He single-handedly slew all who resisted, but the wounds he suffered in the battle prevented him from joining the Horde's march on Azeroth. Porung's wounds have long since healed, and now he serves Warchief Kargath Bladefist in Hellfire Citadel, hoping to claim in battle the glory he missed because of his injury. He believes his name in orc history should be written in the blood of his enemies. ]], 0.296846, 0.146568, 1, 710, 6216, 259, 2, 0, 2},
    },
    [260] = {
        {570, "Mennu the Betrayer", [[ Mennu is one of the Broken—the name given to draenei whose forms were twisted by the demonic energy the orcs unleashed. When the naga invaded Zangarmarsh, many of these wretched creatures fought desperately to flee. Mennu, however, chose a different path to freedom. In exchange for his own life, he betrayed his comrades to the serpentine invaders and agreed to rule over his own kind as a slave master. ]], 0.490437, 0.270492, 1, 838, 5902, 260, -1, 0, 1},
        {571, "Rokmar the Crackler", [[ After the destruction of Draenor, Rokmar fled to the remote reaches of Zangarmarsh. The energy that tore the world apart enveloped this giant and increased his strength and size, but the price of that power was eternal torment. When the naga first appeared in the region, they were shaken by Rokmar's ferocity. They did not slay the beast but instead enslaved him and used him to subjugate most of the native inhabitants of Zangarmarsh. ]], 0.580601, 0.405738, 1, 838, 5907, 260, -1, 0, 2},
        {572, "Quagmirran", [[ Quagmirran was once the leader of the fungal giants of Zangarmarsh. One day, while exploring the branching caverns of these lands, the naga took him captive and subjected him to terrible torture. Now this broken creature zealously serves his masters, subduing all who defy the will of Lady Vashj. ]], 0.821038, 0.768442, 1, 838, 5977, 260, -1, 0, 3},
    },
    [261] = {
        {573, "Hydromancer Thespia", [[ The highborne Thespia, who lived during the height of the elven empire, was a connoisseur of music and painting. But during the Great Sundering she lost her interest in all things beautiful, when she—along with many other elves—was dragged into the depths and transformed into a malice-filled naga. For the thousands of years that followed she served as a confidante to Lady Vashj, with whom she had been friends since childhood. Without hesitation she followed her into Zangarmarsh and swore to see that the naga's plan to drain the marshes of these lands was carried out. ]], 0.542350, 0.137295, 1, 837, 5982, 261, -1, 0, 1},
        {574, "Mekgineer Steamrigger", [[ As a result of the infestation of Gnomeregan, many of the city's residents were transformed into leper gnomes. Among the unfortunate was the talented engineer Mekgineer Steamrigger. Although he managed to leave Gnomeregan and keep his sanity, his former kindness and moral principles were lost forever. He wandered across Azeroth, selling his technical inventions to dubious clients like the Bloodsail pirates. Recently, Mekgineer Steamrigger has been working for the naga, operating the sophisticated machinery of the Steamvault in Zangarmarsh. ]], 0.341530, 0.819672, 1, 837, 5996, 261, -1, 0, 2},
        {575, "Warlord Kalithresh", [[ In the depths of the Steamvault, the naga conduct experiments with a mysterious substance, seeking to make their warriors stronger and to rid them of fear. Warlord Kalithresh was one of the first servants of Lady Vashj to volunteer to test the dark elixir on himself. As a reward for his zeal, he was charged with guarding the vast vault and ensuring that all its arcane mechanisms functioned properly. ]], 0.759563, 0.436475, 1, 837, 6001, 261, -1, 0, 3},
    },
    [262] = {
        {576, "Swamplord Musel'ek", [[ Unlike his kin Quagmirran, the enormous fungal giant named Hungarfen is not yet enslaved by the naga. Even so, he is hostile toward all outsiders who wander into the deepest caverns of Zangarmarsh. He is indifferent to the naga's schemes in the rest of the marsh: he spends his days tending to an underspore—an ancient plant that he considers the most precious thing he possesses. ]], 0.693989, 0.899590, 1, 836, 6006, 262, -1, 0, 1},
        {577, "Ghaz'an", [[ Historians have long debated whether the colossal hydras of Azeroth and Outland share a common ancestor. Either way, these ruthless creatures have undoubtedly existed in both worlds since ancient times. The Black Stalker is one of the most terrifying hydras in all of Outland. By the will of Lady Vashj, this insatiable monstrosity ravages the lower part of Zangarmarsh, spreading terror among the local inhabitants. ]], 0.786885, 0.288935, 1, 836, 6009, 262, -1, 0, 2},
        {578, "Swamplord Musel'ek", [[ To be one of the Broken is to be an outcast. Swamplord Musel'ek has come to know the full truth and weight of this fact. He belongs to the Darkcrest tribe, but he prefers to roam the caverns of Zangarmarsh alone. He is exceptionally skilled at taming beasts: during one such outing, he captured the windcaller Claw—a druid who was surveying the area in the form of a bear. Musel'ek bent him to his will and made him a faithful companion, one who would not be repelled by the corruption that has touched the swamplord. ]], 0.415300, 0.241803, 1, 836, 6013, 262, -1, 0, 3},
        {579, "The Black Stalker", [[ The marshwalkers of Outland are tall, large creatures that hunt smaller prey in the wilds of the marsh. The sporelings of Zangarmarsh tell tales of one such predator, the exceptionally ruthless Black Stalker. She is the progenitor of all marshwalkers, and it is believed she leaves her lair in the depths of the lower marsh only to hunt her favorite prey: sporelings. ]], 0.247268, 0.456967, 1, 836, 6036, 262, -1, 0, 4},
    },
    [271] = {
        {580, "Elder Nadox", [[ Hadronox—no, Anub'arak's people once revered Krik'thir— Elder Nadox was once a revered leader of the nerubians who taught the young the teachings of their ancestors. When the War of the Spider began in Azjol-Nerub, the hordes of undead defeated him. The Lich King returned his body to life and stripped Nadox of his former wisdom and nobility, forcing him to kill his own students, friends, and any other nerubians who dared rise against the might of the Scourge. ]], 0.696721, 0.270492, 1, 522, 6041, 271, -1, 0, 1},
        {581, "Prince Taldaram", [[ After Kael'thas's failed assault, the Lich King slew some of his most renowned followers and raised them into undeath to serve as warriors of the Scourge. Prince Taldaram is one of these cunning, ever-bloodthirsty vampires, forever seeking to please the Lich King. In search of nerubian relics meant to swell the Scourge's ranks, he descended into the depths of Ahn'kahet, ruined during the war. ]], 0.631147, 0.495901, 1, 522, 6050, 271, -1, 0, 2},
        {582, "Jedoga Shadowseeker", [[ Jedoga dreams of the end of the world. She is considered one of the most fanatical followers of the Twilight's Hammer cult. A ruthless ogre mage named Cho'gall taught her to turn the power of shamans to the service of the Old Gods. Not long ago, Jedoga journeyed to the very heart of Ahn'kahet to prepare for the glorious day when Yogg-Saron is freed and his darkness consumes all of Azeroth. ]], 0.482240, 0.725410, 1, 522, 6055, 271, -1, 0, 3},
        {583, "Amanitar", [[ For many years, fungi and other minor life forms thrived in the damp caverns of Ahn'kahet, where the rays of the sun never reach. Only recently did the dark influence of Yogg-Saron spread into this isolated ecosystem. With his monstrous power, the Old God twisted the essence of one of the native inhabitants of these depths and created a nightmarish creature named Amanitar: a reckless terror given form, whose very existence is sustained by the dark energy of its master. ]], 0.672131, 0.786885, 1, 522, 6060, 271, 2, 0, 4},
        {584, "Herald Volazj", [[ During the invasion of the Scourge into Azjol-Nerub, many inhabitants of the kingdom fled downward, digging passages to escape the minions of the Lich King. Alas, some of them dug too deep and brushed against the tentacles of Yogg-Saron. They awoke him, and the monstrous horror sent one of his warriors, who had fought at his side since ancient times—the herald Volazj—to destroy the trapped nerubians and slay any who dared threaten the Old God. ]], 0.236339, 0.504098, 1, 522, 6067, 271, -1, 0, 5},
    },
    [272] = {
        {585, "Krik'thir the Gatewatcher", [[ For centuries the gates of Azjol-Nerub were considered impregnable, until the Lich King came. In mockery of Krik'thir, who failed to halt his armies and defend his home, Arthas raised him into undeath and commanded him to guard the very gates he could not hold in life. ]], 0.501366, 0.450820, 3, 533, 6073, 272, -1, 0, 1},
        {586, "Hadronox", [[ When Azjol-Nerub fell, the nerubian viziers created a spider that would in time grow to wage war against the unstoppable army of the Lich King. Its creators instilled in Hadronox a hatred, along with a burning desire to avenge its fallen kin and reclaim its home from any who would encroach upon it. ]], 0.431694, 0.594262, 2, 533, 6351, 272, -1, 0, 2},
        {587, "Anub'arak", [[ The fates of Azjol-Nerub and Anub'arak have long been intertwined. In life he was the king of these lands, and in death—its conqueror. The Lich King commanded him to stand guard over the kingdom that was once his own, and the traitor king watches keenly over all who might pose a threat to these lands. ]], 0.621585, 0.487705, 1, 533, 6355, 272, -1, 0, 3},
    },
    [273] = {
        {588, "Trollgore", [[ The Drakkari are among the most bloodthirsty of trolls, and Drakkari Colossus is the most striking and untamed example of this tribe. The monstrous beast met the Lich King in battle and felt that its fury was nothing compared to the rage of Arthas. Now it serves as a warning to those who would dare defy the power of the Lich King. ]], 0.565574, 0.182377, 1, 534, 6370, 273, -1, 0, 1},
        {589, "Novos the Summoner", [[ Novos always strove by any means to rise above the mediocrities who surrounded him. This cultist tore out his own heart and offered it to his master while it still beat, mere seconds before his death. Such zeal impressed his master, and as a reward he made Novos a lich. ]], 0.702186, 0.479508, 1, 534, 6375, 273, -1, 0, 2},
        {590, "King Dred", [[ King Dred is a legend among the Drakkari. The legends tell of troll hunters who discovered a mighty beast dwelling in lands tainted by the corruption of the Scourge. The trolls tamed the devilsaur, believing it would help them find a cure for the terrible plague ravaging their lands. ]], 0.612022, 0.862705, 1, 534, 6390, 273, -1, 0, 3},
        {591, "The Prophet Tharon'ja", [[ Even the stolen power of the loa could not stay the hand of death that touched the trolls when the Scourge fell upon Drak'Tharon Keep. The prophecies of Tharon'ja are now filled only with visions of his new master's triumph, and countless trolls perish before the face of the Lich King. ]], 0.476776, 0.133197, 2, 534, 6396, 273, -1, 0, 4},
    },
    [274] = {
        {592, "Slad'ran", [[ Slad'ran felt no enthusiasm when he was forced to destroy the loa he had served all his life. When he was endowed with the power of a god, the high prophet swore that the Scourge would answer for all the atrocities the Drakkari trolls had been made to commit. ]], 0.539617, 0.485656, 1, 530, 6411, 274, -1, 0, 1},
        {593, "Drakkari Colossus", [[ The trolls have long used mojo in their voodoo rituals, but awakening a golem to life is an entirely new stage in the development of their magic. The success of this endeavor led the trolls to create many guardians with the aid of the colossus, their first creation. ]], 0.465847, 0.655737, 1, 530, 6418, 274, -1, 0, 2},
        {594, "Moorabi", [[ The Drakkari wished to sacrifice Mam'toth to gain his power, but the loa destroyed himself. Despite this, Moorabi undoubtedly possesses the power of the gods; the high prophet drank the blood of the loa, and now he is ready to do anything to keep Zul'Drak in the hands of the trolls. ]], 0.393442, 0.489754, 1, 530, 6980, 274, -1, 0, 3},
        {595, "Eck the Ferocious", [[ After ceasing their experiments on the gorlocs following countless attempts to make living weapons of them, the Drakkari locked them away. While the ice trolls fought the armies of the Scourge in defense of their homeland, Eck and his servants awaited their chance to break free. ]], 0.251366, 0.704918, 1, 530, 6664, 274, 2, 0, 4},
        {596, "Gal'darah", [[ The Drakkari turned to the loa when the forces of the Scourge attacked Zul'Drak. The ice trolls came to them not with pleas, but with swords. When the blood of the slain god, Akali, stained the earth, the high prophet Gal'darah and his treacherous followers absorbed the power of the loa. ]], 0.465847, 0.270492, 1, 530, 6989, 274, -1, 0, 5},
    },
    [275] = {
        {597, "General Bjarngrim", [[ The iron dwarves of Loken are without number, and their general, Bjarngrim, surpasses all the rest. He is the first to meet enemies who dare set foot in the Halls of Lightning: the iron commander ruthlessly punishes any who appear there uninvited. ]], 0.435792, 0.372951, 1, 525, 7724, 275, -1, 0, 1},
        {598, "Volkhan", [[ Loken's mighty warriors are the fruits of his smith Volkhan's labor. Never resting for a moment, he tirelessly forges soldiers to fight for the fallen Keeper. Only when the bodies of vanquished foes lie beneath the feet of his creations will his work be complete. ]], 0.377049, 0.209017, 2, 525, 7042, 275, -1, 0, 2},
        {599, "Ionar", [[ Loken himself is guarded not by iron soldiers: he prefers to choose stronger warriors for that task. The fallen Keeper is protected by lightning itself. Ionar and the servants of this creature were given refuge in the Halls of Lightning in exchange for a promise to serve faithfully, to obey without question, and to slay any who dare oppose their new master. ]], 0.614754, 0.774590, 2, 525, 7252, 275, -1, 0, 3},
        {600, "Loken", [[ Loken, appointed Prime Designate of Azeroth, was meant to ensure that Yogg-Saron remained imprisoned. No one could have imagined that the Keeper charged with protecting the world from the cunning of the Old God would himself help it gain its freedom. ]], 0.189891, 0.522541, 2, 525, 7258, 275, -1, 0, 4},
    },
    [276] = {
        {601, "Falric", [[ This mighty warrior of the Scourge was one of the first death knights created by Arthas after he found Frostmourne. Falric followed the prince to Northrend, but the campaign was doomed to fail, and Falric himself was betrayed by the master he had faithfully served all his life. ]], 0.352459, 0.750000, 1, 603, 7265, 276, -1, 0, 1},
        {602, "Marwyn", [[ Marwyn knew Arthas all his life and regarded him not only as a prince, but as a true friend. The knight followed Arthas without hesitation when he set out for Northrend. And though that friend drove a cursed blade into Marwyn's heart, it was already broken over what the prince had become. ]], 0.434426, 0.627049, 1, 603, 7269, 276, -1, 0, 2},
        {603, "Escape from Arthas", [[ The two lords wished to defeat the Lich King in battle, putting an end to his atrocities forever, but they quickly realized they could not stand against the true king. Seeking to escape a sorrowful fate, they tried to flee his domain. Arthas savored every second, watching the futility of their efforts: there is no escaping the inevitable. ]], 0.105191, 0.274590, 1, 603, 7273, 276, -1, 0, 3},
    },
    [277] = {
        {604, "Krystallus", [[ To win a war, strength alone is not enough—one also needs armies. This immutable truth inspired Loken to create faithful stone servants to swell the ranks of his soldiers. Krystallus's task is to oversee the work and ensure that nothing hinders it. ]], 0.401639, 0.604508, 1, 526, 7285, 277, -1, 0, 1},
        {605, "Maiden of Grief", [[ Loken commands the armies of Ulduar, but not all obey him willingly. The Maiden of Grief must destroy all who try to reclaim the Halls of Stone. She grieves, for she must fight her former allies, yet she carries out her orders fiercely and relentlessly. Even her grief has become a weapon. ]], 0.502732, 0.862705, 1, 526, 7290, 277, -1, 0, 2},
        {606, "Tribunal of Ages", [[ Abedneum, Kaddrak, and Marnak make up the Tribunal of Ages. They are the keepers of the knowledge gathered upon the titans' disk, which holds all the ancient history of Azeroth. The unmoving statues are not ready to part so easily with the secrets of the titans, but adventurers like the brave Brann Bronzebeard believe such a prize is worth the risk. ]], 0.845629, 0.760246, 1, 526, 7294, 277, -1, 0, 3},
        {607, "Sjonnir the Ironshaper", [[ Some opposed Loken, but Sjonnir the Ironshaper was only glad to taint the Forge of Will with darkness. He believes his new creations far surpass all other inhabitants of the world, and he will unleash his armies upon any who dare defy the will of Loken. ]], 0.497268, 0.137295, 1, 526, 7313, 277, -1, 0, 4},
    },
    [278] = {
        {608, "Forgemaster Garfrost", [[ Garfrost forged the most deadly weapons of all that the warriors of the Scourge ever turned against the living. He can swiftly forge from saronite nightmarish instruments of torture that bring an agonizing death, or he can simply hurl chunks of ore at his foes. ]], 0.680328, 0.553278, 0, 602, 7327, 278, -1, 0, 1},
        {609, "Ick and Krick", [[ The diminutive necromancer Krick oversees the workers in the Pit of Saron. He rides upon the back of the terrible Ick and hurls vials of poison, explosives, and bolts of dark energy at his enemies while staying out of their reach. From atop Ick's back, he can see much: he has managed to learn certain secrets that could be used to bring down the Lich King. ]], 0.475410, 0.397541, 0, 602, 7334, 278, -1, 0, 2},
        {610, "Scourgelord Tyrannus", [[ The death knight Tyrannus became a lord of the Scourge after slaying the giant Garfrost. He is strong, ruthless, and knows no hesitation, and he also has at his command the frost wyrm Rimefang. All of this makes him the perfect guardian of the Pit of Saron and the entrance to the Halls of Reflection. ]], 0.441257, 0.266394, 0, 602, 7340, 278, -1, 0, 3},
    },
    [280] = {
        {615, "Bronjahm", [[ Bronjahm served the Cult of the Damned from its founding. Kel'Thuzad personally taught Bronjahm how to handle souls in order to fuel the deadly instruments of the Scourge. Bronjahm can defile and tear apart the souls of his foes, which makes him the perfect guardian of the Lich King's Soulforge. ]], 0.435793, 0.495902, 1, 601, 7380, 280, -1, 0, 1},
        {616, "Devourer of Souls", [[ As a result of Bronjahm's dark deeds, tormented and shattered souls appear in the Soulforge. But the Lich King had need even of fragments of cursed souls, and to keep them from escaping, he created the Devourer of Souls. This monster hunts down the stray souls and slowly digests them in its loathsome belly. The consumed souls go mad from the monstrous torment, but the Devourer of Souls' hunger can never be sated. ]], 0.434426, 0.120902, 1, 601, 7387, 280, -1, 0, 2},
    },
    [281] = {
        {833, "Commander Kolurg", [[ Commander Kolurg was searching for dangerous artifacts that might be found within the Horde's vault. The failure that befell him in the Halls of Stone enraged him, and once freed from his icy bonds, he is unlikely to be pleased to see Alliance heroes stealing the very thing he came here for. ]], 0.187159, 0.506146, 1, 520, 7428, 281, 2, 6, 1},
        {617, "Commander Stoutbeard", [[ Commander Stoutbeard and his subordinates have fought many times against the most dangerous enemies of the Alliance. And though the Halls of Stone have cooled his ardor somewhat, nothing will hearten him more than Horde adventurers drawing near. ]], 0.187159, 0.506146, 1, 520, 6665, 281, 2, 10, 1},
        {618, "Grand Magus Telestra", [[ Rumor has it that Grand Magus Telestra was a mentor to Kael'thas. And although she considered the prince's alliance with the naga to be folly, she could not bring herself to support the mages of Dalaran, who kept her kin in captivity. Malygos did not have to plead with her long to make her the instructor of his spell-breakers: he needed only to remind her of that betrayal. ]], 0.275956, 0.399590, 1, 520, 7392, 281, -1, 0, 2},
        {619, "Anomalus", [[ Because Malygos sought to control the flows of Azeroth's arcane magic through the Nexus, a rift formed in the fabric of reality. The forces of Malygos try to hold back the onslaught of the creatures pouring into Azeroth, yet the chaotic arcane energy has taken the form of a being known as Anomalus. If this creature is not stopped, it will destroy everything it touches. ]], 0.620218, 0.221312, 1, 520, 7405, 281, -1, 0, 3},
        {620, "Ormorok the Tree-Shaper", [[ The arcane energy of the Nexus has greatly changed the Chamber of Aspects and its guardians. This fate also befell Ormorok: its simple mind was clouded by the energy that transformed it. It is unlikely to be talkative upon seeing those who interrupted its musings, but one thing is certain: a great deal of trouble awaits these bold ones. ]], 0.562842, 0.727459, 1, 520, 7416, 281, -1, 0, 4},
        {621, "Keristrasza", [[ No one can say for certain why Keristrasza was subjected to such torment: whether it was vengeance for the death of Saragosa, or a calculated attempt to make her an ally… The answer is known only to Malygos. Whatever his true intentions, Keristrasza's allies heard the cries of pain and the whispers of her fading mind. ]], 0.362022, 0.674180, 1, 520, 7422, 281, -1, 0, 5},
    },
    [282] = {
        {622, "Drakos the Interrogator", [[ Those who break the laws of Malygos fall straight into the clutches of Drakos. When there was no longer any need for him to guard Keristrasza in the Nexus, Drakos returned to the Oculus to become the overseer of the captive dragons who dared defy Malygos. Drakos is unfamiliar with the word 'redemption,' nor is he much for metaphor. His prisoners must be punished, and they cannot escape. ]], 0.491803, 0.762295, 1, 528, 7437, 282, -1, 0, 1},
        {623, "Varos Cloudstrider", [[ Varos Cloudstrider personally led the brutal assaults against the Wyrmrest Accord from the very start of the Nexus War. He was recalled from the front lines and charged with guarding the Oculus; Drakos has already given the necessary orders to his officers and dragons. Moreover, Varos has gained access to the power that permeates the entire Oculus, and now he is even more dangerous than before. ]], 0.461749, 0.192623, 2, 528, 7440, 282, -1, 0, 2},
        {624, "Mage-Lord Urom", [[ Urom renounced the Kirin Tor and swore loyalty to Malygos, who was simply delighted to have secured such a powerful ally. The turncoat mage is of enormous value to the blue dragons, for he knows all the strengths and weaknesses of the Kirin Tor and can think as they do. Urom will surely use this knowledge to destroy the mages of the Kirin Tor. ]], 0.707650, 0.274590, 0, 528, 7445, 282, -1, 0, 3},
        {625, "Ley-Guardian Eregos", [[ Even fearless heroes tremble before Eregos, the defender of the Oculus, the guardian of the flows of arcane magic and the slayer of intruders. He is convinced that he is following a prophecy, and he carries out his duties superbly. He will stop at nothing to protect the absolute power of the Spell-Weaver. ]], 0.469945, 0.209016, 0, 528, 7448, 282, -1, 0, 4},
    },
    [283] = {
        {626, "Erekem", [[ The Violet Hold contains the most dangerous criminals of Outland, and Erekem is no exception. The Kirin Tor managed to thwart Erekem's plans when he was about to destroy the Council of Six, but now the blue dragons have hired this cunning arakkoa to carry out a far grander scheme: they intend to destroy every mage in Dalaran. ]], 0.275956, 0.622951, 1, 536, 7457, 283, -1, 0, 1},
        {627, "Moragg", [[ Cyanigosa turned to Moragg to help her destroy the rebellious mages of Dalaran. In his time, this terrible demon served the Burning Legion, destroying the enemies of Sargeras with a single awe-inspiring glance from his seven eyes. And now he will show the heroes of Azeroth that one does not simply walk into the Violet Hold... ]], 0.678962, 0.528688, 1, 536, 7470, 283, -1, 0, 2},
        {628, "Ichoron", [[ A shortsighted apprentice summoned this monster from the Elemental Plane, but by the time he realized that the discontented warriors who served the Old Gods make rather unruly pets, it was already too late. Ichoron killed the one who summoned her, and now she rots in the dungeon of the Violet Hold, hoping one day to take revenge on her jailers. ]], 0.556011, 0.403688, 1, 536, 7475, 283, -1, 0, 3},
        {629, "Xevozz", [[ Xevozz dealt in weapons enhanced by arcane magic… until the wizards of the Kirin Tor discovered that he was selling arms to the Burning Legion. And now this most pragmatic ethereal has devised a three-part plan: destroy his foes, escape from prison, and re-establish the supply of weapons to his largest buyer. ]], 0.330601, 0.452869, 1, 536, 7482, 283, -1, 0, 4},
        {630, "Lavanthor", [[ In her time, the calculating Cyanigosa unleashed one of the most fearsome hounds of the Nether. In an attempt to curb the bloodlust of this two-headed monster, the mages imprisoned Lavanthor, and the years spent in captivity did nothing to improve his temperament. ]], 0.618852, 0.750000, 1, 536, 7488, 283, -1, 0, 5},
        {631, "Zuramat the Obliterator", [[ It took a hundred of Dalaran's finest mages to subdue Zuramat, and another two hundred wizards to clean up the aftermath of the bloody massacre he wrought. The Obliterator's bloodthirstiness repulses even the mad Malygos, who finds the void lord's hunger for magic loathsome. Even so, a bloody slaughter can sometimes bring together utter opposites. ]], 0.271858, 0.336066, 1, 536, 7492, 283, -1, 0, 6},
        {632, "Cyanigosa", [[ As the executor of his plans, Malygos chose Cyanigosa precisely because her loyalty had stood the test of time. Cyanigosa did not renounce Malygos when he lost his mind; she did not defy him when he seized the flows of Azeroth's arcane magic… and she will destroy anyone who dares oppose him. ]], 0.450820, 0.551229, 1, 536, 7497, 283, -1, 0, 7},
    },
    [285] = {
        {638, "Prince Keleseth", [[ The Lich King sent Keleseth to Utgarde Keep in hopes of harnessing the destructive might of the vrykul. Upon his arrival, the emissary found that many in this keep were eager to aid the Scourge. The keep proved to be an excellent stronghold from which to hold all of the Howling Fjord in terror, and Prince Keleseth has no intention of surrendering it without a fight to insolent outsiders. ]], 0.289618, 0.627049, 1, 523, 7601, 285, -1, 0, 1},
        {639, "Skarvald and Dalronn", [[ Forcing those who dislike one another to work together is one of the traditions of the vrykul. Some believe that in this way the antagonists' abilities complement each other; others think it is merely a whim of King Ymiron. But whatever the reason, Skarvald and Dalronn are a perfect example of this tradition. The brute strength of the vrykul and the art of human necromancy form a formidable duo, whose task is to destroy any who poke their nose into the affairs of the Scourge. ]], 0.587431, 0.620901, 2, 523, 7609, 285, -1, 0, 2},
        {640, "Ingvar the Plunderer", [[ Ingvar's incredible strength is considered legendary even among the vrykul. Rumor has it that he once defeated King Ymiron himself in a brawl. Whether this is true or not is unknown, but those who tell this tale usually do not live long. Ingvar promised the Lich King that he would resort to the cruelest measures to hold the keep, and he dares not break that promise. ]], 0.724043, 0.381148, 0, 523, 7619, 285, -1, 0, 3},
    },
    [286] = {
        {641, "Svala Sorrowgrave", [[ Svala was once a commander in the service of Ingvar the Plunderer, and to her credit are many scouting operations within the camps of the Horde and the Alliance. It was Svala who learned that enemies intended to infiltrate Utgarde Keep, and thanks to this the Lich King had time to prepare his defenses. As a reward for her loyal service, the Lich King transformed her into a val'kyr, a revered warrior of the Scourge. ]], 0.363388, 0.706967, 1, 524, 7660, 286, -1, 0, 1},
        {642, "Gortok Palehoof", [[ The vrykul keep many hunting trophies in Utgarde Keep, and Gortok is one of the most impressive. The cruel expression on the frozen magnataur's face serves as a reminder to King Ymiron that even the wildest beasts are nothing more than ornaments in a vrykul keep. If this monster is freed from its icy prison, it will unleash its wrath upon all who cross its path. ]], 0.606558, 0.688525, 2, 524, 7669, 286, -1, 0, 2},
        {643, "Skadi the Ruthless", [[ The epithets of the vrykul attest to past deeds. For slaying a family of Drakkari or beheading a taunka, one might earn the title 'the Zealous,' but to earn the name 'the Ruthless,' one must do something far more cruel. Skadi earned his epithet long ago, when he tirelessly tracked down and slew vrykul who sheltered sickly infants: King Ymiron passed a death sentence on any who dared show such compassion. ]], 0.684426, 0.362705, 2, 524, 7691, 286, -1, 0, 3},
        {644, "King Ymiron", [[ The proud King Ymiron ruled the northern wastes, but then the vrykul fell into a long slumber and was forgotten. Upon awakening, he found that his wife had been slain and his homeland besieged by enemies. Having gained immortality, he hungers passionately for vengeance, and those who stand in the path of the awakened giant face certain doom. ]], 0.415301, 0.534836, 2, 524, 7708, 286, -1, 0, 4},
    },
    [741] = {
        {1519, "Lucifron", [[ Lucifron is one of the four Lords of Fire and captains of Ragnaros, and the first boss in the Molten Core. The flamewakers are a race of ruthless serpentine creatures who serve Ragnaros the Firelord. Fierce and terrifying, the flamewakers are among the most fearsome elemental guardians in the Molten Core. ]], 0.658633, 0.374995, 0, 877, 20173, 741, -1, 0, 1},
        {1520, "Magmadar", [[ Magmadar is composed of volcanic rock and molten magma. Magmadar serves as the source of the core hounds that roam the earthen halls of the Molten Core. To Ragnaros, Magmadar is considered a pet. Magmadar is protected by the Lord of Fire Lucifron and surrounded by vicious packs of predatory hounds. It is said that while Ragnaros was imprisoned on the Elemental Plane, the Firelord fed the remains of his captured enemies to the eagerly waiting twin maws of Magmadar. As a result, the hound grew strong and loyal, and even now Magmadar's savage ferocity remains undisputed. Magmadar is the alpha male of all the core hounds. ]], 0.694339, 0.236793, 0, 877, 20177, 741, -1, 0, 2},
        {1521, "Gehennas", [[ Gehennas and his fellow flamewakers emerged from the elementals within the Molten Core. Unlike fire elementals, who are beings of pure flame, the flamewakers are elementals made of flesh and blood. Gehennas sits at the very bottom of the Firelord's elemental hierarchy and covets the power and standing of his superiors. He is trusted by none who serve alongside him, save for his two loyal guards, who believe they may benefit from their overseer's rise. Gehennas uses shadow magic and guards the Rune of Mion together with two flamewakers. ]], 0.330876, 0.485334, 0, 877, 20181, 741, -1, 0, 3},
        {1522, "Garr", [[ Garr is a creature of lava and earth. He is found in the Molten Core between Gehennas and Baron Geddon, guarding the Rune of Flame. He is a melee boss with 8 Firesworn guardians. ]], 0.315094, 0.689623, 0, 877, 20184, 741, -1, 0, 4},
        {1523, "Shazzrah", [[ Of all the flamewakers who followed Ragnaros into the world of Azeroth, Shazzrah is the most gifted in the realm of arcane magic. He knows that his colleague, Baron Geddon, suspects the elemental Garr of treachery. The conflict between Baron Geddon and Garr suits Shazzrah well, for it is in fact Shazzrah himself who seeks to claim both halves of the Talisman of Binding the Elementals, in order to find a way to siphon its energy for his own use. Most likely Ragnaros was aware of his subordinate's inclination toward duplicity when he split the talisman in two and entrusted the halves to Baron Geddon and Garr. Shazzrah guards the Rune of Mazj. ]], 0.558406, 0.852617, 0, 877, 20190, 741, -1, 0, 5},
        {1524, "Baron Geddon", [[ Baron Geddon is a fire elemental boss found in the Molten Core. He patrols near Shazzrah's spawn area, guarding the Rune of Zeth. ]], 0.523926, 0.776320, 0, 877, 20195, 741, -1, 0, 6},
        {1525, "Sulfuron Harbinger", [[ Among the flamewakers, Sulfuron Harbinger is a terrifying herald of Ragnaros. Sulfuron Harbinger answers only to Executus and guards the Rune of Kress, one of several runes that empower the servants of the Firelord. Sulfuron Harbinger keeps a close watch on Shazzrah, believing that Shazzrah seeks to betray Ragnaros. Accompanied by four of the Firelord's most fervent priests, the Harbinger prepares for the day when the Firelord will conquer the world of Azeroth. ]], 0.828302, 0.825472, 0, 877, 20199, 741, -1, 0, 7},
        {1526, "Golemagg the Incinerator", [[ The most feared of Ragnaros's elemental soldiers are the molten giants, and among them Golemagg the Incinerator has no equal in his cruelty and savage efficiency. The molten monster's strength is so boundless that he has cowed two of the chief core hounds—the offspring of the colossal beast Magmadar—whom he now keeps as pets. For this insult, he has earned the eternal and unwavering wrath of Magmadar, though the formidable creature has not yet acted upon his savage urges. Golemagg is a molten giant boss with two pet hounds, called Core Ragers, guarding the Rune of Teri. ]], 0.688680, 0.576416, 0, 877, 20208, 741, -1, 0, 8},
        {1527, "Majordomo Executus", [[ At the top of the elemental hierarchy, just beneath Ragnaros himself, resides Majordomo Executus. This flamewaker earned his exalted status by proving himself nearly invincible in the battles that raged on the Elemental Plane. Rumor has it that Executus supplanted Baron Geddon, and the two have been rivals ever since. Though this rumor has not yet been confirmed, there is no doubt that Ragnaros does not tolerate failure. Thus the lesser flamewakers (and Baron Geddon, of course) eagerly await a misstep from Executus, awaiting their chance to compete for the coveted attention of the Firelord. Executus will be aided in battle by four Flamewaker Healers and four Flamewaker Elites. ]], 0.841510, 0.652831, 0, 877, 20215, 741, -1, 0, 9},
        {1528, "Ragnaros", [[ Ragnaros the Firelord was an incredibly powerful leader of the fire elementals. After he was summoned to Azeroth by Emperor Thaurissan, he took control of Blackrock Mountain and ruled there for more than two hundred years over the Dark Iron dwarves from the deep core located deep within the mountain itself. ]], 0.562265, 0.533963, 0, 877, 20226, 741, -1, 0, 10},
    },
    [742] = {
        {1536, "Nefarian", [[ Nefarian experimented with the blood of all the dragonflights in order to create a chromatic dragonflight of unstoppable warriors. In this task he succeeded his father, and with the aid of his sister he plans to use them to rally the black dragons under his command.
Within Blackrock Mountain, with the help of his loyal dragonspawn, he wages a constant battle against Ragnaros and his forces for control of the mountain and, ultimately, the entire region. To this end, he has worked to bolster his forces, as his father Deathwing did in the past. Nefarian takes pleasure in capturing Ragnaros's minions and using them for his own insidious purposes.
He has forged an alliance with Rend Blackhand, though he uses him and his Dark Horde only to achieve his own ends. Nefarian's mad pursuit of dominance has even drawn the wrath of the red dragons—in the form of the red dragon Vaelastrasz—who have always been the greatest enemy of the black flight. Though Nefarian's intentions are known, the methods he uses to achieve them remain a mystery.
Now that the black dragons are once again under firm leadership and bolstered by these new chromatic dragons, he plans to strike back against the other dragons, as well as the mortal nations of the world. ]], 0.703746, 0.724620, 4, 885, 20068, 742, -1, 0, 8},
        {1529, "Razorgore the Untamed", [[ The Lord of Blackwing Lair, Nefarian, has charged Razorgore the Untamed with guarding the numerous and precious black dragon eggs located in the first chamber of the instance. To this end, Razorgore has been given command of a cohort of orcs and other forces, and he will stop at nothing to ensure that no harm comes to his clutch. ]], 0.419285, 0.602438, 1, 885, 20021, 742, -1, 0, 1},
        {1530, "Vaelastrasz the Corrupt", [[ Vaelastrasz the Corrupt is the second boss of Blackwing Lair. He was enslaved by Nefarian and now reluctantly serves him. ]], 0.332819, 0.275371, 1, 885, 20028, 742, -1, 0, 2},
        {1531, "Broodlord Lashlayer", [[ The dragonspawn leader Broodlord Lashlayer guards the Halls of Strife, blocking the path to Nefarian's inner sanctum. ]], 0.505751, 0.617476, 3, 885, 20033, 742, -1, 0, 3},
        {1532, "Firemaw", [[ Firemaw is the fourth boss in Blackwing Lair, patrolling the Crimson Laboratories after Broodlord Lashlayer and before Ebonroc. ]], 0.464398, 0.429507, 3, 885, 20037, 742, -1, 0, 4},
        {1533, "Ebonroc", [[ Ebonroc is the fifth boss in Blackwing Lair, patrolling the upper chamber of the Crimson Laboratories after Firemaw and before Flamegor. He is one of three powerful black dragons guarding the path to their master, Nefarian. ]], 0.349110, 0.209583, 3, 885, 20041, 742, -1, 0, 5},
        {1534, "Flamegor", [[ Flamegor is the third of the three dragons in Blackwing Lair, coming after Ebonroc and before Chromaggus. ]], 0.355376, 0.371237, 4, 885, 20045, 742, -1, 0, 6},
        {1535, "Chromaggus", [[ Chromaggus is a two-headed dragon minion of Nefarian who dwells in Blackwing Lair, coming after Flamegor and before Nefarian. ]], 0.394223, 0.726500, 4, 885, 20049, 742, -1, 0, 7},
    },
    [743] = {
        {1537, "Kurinnaxx", [[ Kurinnaxx is a creature, a sand reaver. Little is known about them, but they are found in areas infested with silithid. Kurinnaxx is a boss in the Ruins of Ahn'Qiraj. ]], 0.563507, 0.357434, 0, 881, 20076, 743, -1, 0, 1},
        {1538, "General Rajaxx", [[ During the War of the Shifting Sands, the monstrous, towering Rajaxx commanded the qiraji and silithid in battle, swinging his clawed limbs and shouting orders to his soldiers. ]], 0.584020, 0.491280, 0, 881, 20080, 743, -1, 0, 2},
        {1539, "Moam", [[ In preparation for the rebirth of the qiraji into the world, the dark lord of Ahn'Qiraj ordered Emperor Vek'lor to create a new obsidian statue, surpassing all other Destroyers. Vek'lor turned to his twin brother for aid in this task, and while Vek'nilash used his physical might to fashion a grand body of volcanic rock, Vek'lor reinforced the shell with powerful magic.
Emperor Vek'lor named the finished construct Moam and watched as the dark master filled it with life. He was pleased and surprised to find that the improved Obsidian Destroyer was far more versatile than its earlier counterparts. The Twin Emperors intended to use Moam as a colossal weapon, knowing that its strengths would help it survive in the thick of melee as well as magical combat, but they did not anticipate the construct's ability to advance further without their own aid. ]], 0.328635, 0.360511, 0, 881, 20083, 743, -1, 0, 3},
        {1540, "Buru the Gorger", [[ Buru the Gorger is an enormous creature of brutal strength. In each of the three hives of Silithus sleeps at least one silithid colossus, waiting to enter battle. After the Scarab Gong was struck and the ancient Gates of Ahn'Qiraj were opened, the horrors of the silithid and their qiraji masters were unleashed. The massive resonating crystals of the qiraji burst through the crust of Kalimdor, and the colossi of the Silithus hives emerged from their cocoons beneath the hives. They heard the call to battle and rose to serve their masters. They cast their immense shadow over all of Silithus and entered the war. ]], 0.697866, 0.620511, 0, 881, 20088, 743, -1, 0, 4},
        {1541, "Ayamiss the Hunter", [[ Ayamiss the Hunter is the leader of the flying silithid. They are highly aggressive and are often found in swarms. There is also a much smaller version of them, always flying near the nests. ]], 0.616841, 0.905126, 0, 881, 20093, 743, -1, 0, 5},
        {1542, "Ossirian the Unscarred", [[ Ossirian the Unscarred is the only known horusath; he was originally an anubisath who was granted this new form after defeating the bronze dragon Grakkarond. ]], 0.429149, 0.695895, 0, 881, 20099, 743, -1, 0, 6},
    },
    [744] = {
        {1543, "The Prophet Skeram", [[ The Prophet Skeram is an important religious leader in Ahn'Qiraj and the author of the Prophecy of C'Thun. He is the first boss in the Temple of Ahn'Qiraj, and he must be defeated to gain access to the rest of the zone. ]], 0.457866, 0.522049, 2, 893, 20105, 744, -1, 0, 0},
        {1544, "Battleguard Sartura", [[ Battleguard Sartura is another leader of the qiraji battleguards and the second boss in the Temple of Ahn'Qiraj. She is accompanied by 3 guards. They are very fast and maneuverable, but less armored than other types of qiraji. ]], 0.445559, 0.335896, 1, 893, 20124, 744, -1, 0, 2},
        {1545, "Fankriss the Unyielding", [[ Fankriss the Unyielding is a creature, a sand worm, and the elder brother of Kurinnaxx and the third boss of the Temple of Ahn'Qiraj. Little is known about them, but they are found in areas infested with silithid. ]], 0.622995, 0.218973, 1, 893, 20130, 744, -1, 0, 3},
        {1546, "Princess Huhuran", [[ Princess Huhuran is a large silithid wasp and the fourth boss of the Temple of Ahn'Qiraj. To defeat her, all players are required to have very high nature resistance. Silithid wasps are the flying attack troops of the silithid. They are highly aggressive and are often found in swarms. There is also a much smaller version of them, always flying near the nests. ]], 0.435303, 0.503588, 1, 893, 20138, 744, -1, 0, 5},
        {1547, "Silithid Royalty", [[ The Twin Emperors—no, the Silithid Royalty, also known as the Trinity or triumvirate, is an optional boss in the Temple of Ahn'Qiraj. It consists of the creatures Lord Kri, Princess Yauj, and Vem, all of whom must be fought at the same time. ]], 0.284533, 0.497434, 1, 893, 20110, 744, -1, 0, 1},
        {1548, "Viscidus", [[ Viscidus is an optional boss in the Temple of Ahn'Qiraj, a giant ooze that can be accessed after the death of Fankriss the Unyielding. This boss requires high nature resistance, as it uses poisonous AoE bolts that deal direct damage along with a DoT. ]], 0.721456, 0.178973, 1, 893, 20135, 744, -1, 0, 4},
        {1549, "The Twin Emperors", [[ The clever brothers Vek'lor and Vek'nilash are known as the Twin Emperors. They rule the qiraji from the sanctum of their temple. In this area, qiraji scarabs and qiraji scorpions are scattered across the floor, and if killed, they continuously respawn throughout the fight. They are initially neutral but become hostile if struck by any area-of-effect spell or mutated by Emperor Vek'nilash. ]], 0.606584, 0.697434, 1, 893, 20143, 744, -1, 0, 6},
        {1550, "Ouro", [[ An ancient sand worm, Ouro is a creature of legendary strength. Rumor has it that he was created by the Old God C'Thun himself as a mockery of life. He dwells in the Temple of Ahn'Qiraj. His hide is unnaturally thick, nearly impenetrable. It is supple and allows him to move with the speed and grace of a far smaller creature. ]], 0.301969, 0.818972, 1, 893, 20154, 744, -1, 0, 7},
        {1551, "C'Thun", [[ C'Thun is the Old God of madness and chaos, one of four ancient and powerful beings who ruled the world. C'Thun created the qiraji and dwells in the city of Ahn'Qiraj in Silithus. He is an incomprehensibly evil being whose pervasive power has filled Azeroth since time immemorial. In recent years C'Thun broke free. The defenders of the Alliance and the Horde chose not to wait for the Old God to gather his strength. They invaded the city-kingdom of Ahn'Qiraj, battling countless qiraji and silithid before finally facing the malevolent god and defeating him. Even so, it is unknown whether Azeroth has truly seen the last of C'Thun. ]], 0.570687, 0.625126, 3, 893, 20160, 744, -1, 0, 8},
    },
    [745] = {
        {11008, "Terestian Illhoof", [[ Satyrs are vile creatures. Fallen night elves, seduced by the power of demons, twisted and broken so that their outward form matches their inner state.
Terestian Illhoof has infiltrated Karazhan, hoping to open a portal there to the Twisting Nether, so that his demonic master might come into this world and, of course, reward him. But his plans are not destined to come to pass, for the heroes of Azeroth will thwart this ritual.
 Won't they?.. ]], 0.525638, 0.696924, 28, 867, 12265, 745, 4, 0, 7},
        {11009, "Netherspite", [[ A void dragon that, by some unknown means, found its way into Karazhan and took up residence in Medivh's observatory. A creature like this feels right at home in Karazhan, and it seems its might has only grown from its long proximity to this cursed castle. Opening portals to unknown reaches, Netherspite draws power from them, and it will surely attack with fury anyone who encroaches upon its lair. ]], 0.359484, 0.418462, 30, 867, 12240, 745, 4, 0, 9},
        {11010, "Nightbane", [[ Medivh's power was so great that with a mere effort of will he caused a blue dragon, Arcanagos, who had flown to the mage's tower, to literally burn from within. Now this unfortunate is known as Nightbane, a dragon skeleton forever wreathed in flame and bound to the place of his gruesome demise, doomed to return again and again.
The time has come to end his torment. ]], 0.472000, 0.925000, 23, 867, 12292, 745, 4, 0, 10},
        {11011, "Prince Malchezaar", [[ It is unknown how Prince Malchezaar, one of the highest eredar hierarchs, came to Karazhan, but it is plain what he was doing in this gloomy castle. The upper floor of Karazhan's tower, where Malchezaar can be found, is shrouded in darkness—reality itself has begun to change, merging with a strange place: the Nethervoid. Perhaps Malchezaar wished to turn Karazhan into an outpost for the further invasion of his legion into Azeroth; perhaps he was interested only in the dark secrets of the castle and the nature of its curse. In any case, the demon must be destroyed. ]], 0.514356, 0.309231, 34, 867, 12320, 745, 4, 0, 11},
        {1552, "Servant's Quarters", [[ Many dangerous creatures dwell throughout Karazhan. To summon the boss in the servants' quarters, the creatures present there must be slain. ]], 0.597000, 0.292000, 1, 867, 21153, 745, 1, 0, 1},
        {1553, "Attumen the Huntsman", [[ The Huntsman Attumen was a horse breeder renowned throughout the Alliance. Horses obeyed him as if he spoke their very language, and his steeds were bought for vast sums by the nobility of every kingdom. What ill fate brought the huntsman and his horse beneath the vaults of Karazhan, we will never know, for the cursed tower jealously guards its secrets, but what is beyond doubt is that Attumen has become far more bloodthirsty than he was in life. ]], 0.452819, 0.826154, 1, 867, 12041, 745, 1, 0, 2},
        {1554, "Moroes", [[ Moroes was an old man who lived in Karazhan, serving as Medivh's castellan. He knew of the visions shown by the castle's magic, but he sought to avoid them. Moroes perished at the hand of his maddened master and fell under the curse of Karazhan, which will forever raise him in undead form. He still tries to keep order in the castle and protect it from unwelcome guests. ]], 0.271280, 0.635385, 3, 867, 12060, 745, 1, 0, 3},
        {1555, "Maiden of Virtue", [[ A creation of the titans, embodying purity and strength of will, the Maiden of Virtue came to Karazhan, outraged by the vices and wickedness of its inhabitants. But the curse of this mysterious castle consumed her as well. Now the Maiden of Virtue is just as much a slave of Karazhan, forced to hopelessly root out vices only for them to appear anew. ]], 0.834384, 0.500042, 4, 867, 12109, 745, 1, 0, 4},
        {1556, "Opera Hall", [[ Karazhan is a vast castle, and what castle is complete without an opera hall? Barnes, the stage manager of the Opera, like the other inhabitants of Karazhan, is trapped in time, endlessly repeating his performances. But while the show is in progress, there is no passing through the opera hall. Perhaps one ought to take part in Barnes's production in order to proceed deeper into Karazhan?.. ]], 0.181023, 0.350770, 4, 867, 12123, 745, 1, 0, 5},
        {1557, "The Curator", [[ Karazhan is vast and full of treasures that thieves and adventurers of all kinds would surely love to lay their hands on. Arcane guardians, mighty golems brimming with magic, watch over the corridors of Karazhan, and the mightiest of them—the Curator—guards the gallery, barring further exploration of this cursed castle. ]], 0.494869, 0.366155, 9, 867, 12177, 745, 1, 0, 7},
        {1559, "Shade of Aran", [[ An echo of Medivh's father, the pale shadow of a once-great mage, wanders aimlessly through the library of Karazhan. The shade, having lost the last drops of its sanity in the eternal torment of the cursed castle, but having lost not a drop of its power, will readily take any uninvited guest of Karazhan to be the cause of its eternal suffering. ]], 0.716407, 0.260001, 10, 867, 12212, 745, 1, 0, 8},
        {1560, "Terestian Illhoof", [[ Satyrs are vile creatures. Fallen night elves, seduced by the power of demons, twisted and broken so that their outward form matches their inner state.
Terestian Illhoof has infiltrated Karazhan, hoping to open a portal there to the Twisting Nether, so that his demonic master might come into this world and, of course, reward him. But his plans are not destined to come to pass, for the heroes of Azeroth will thwart this ritual.
 Won't they?.. ]], 0.525638, 0.696924, 11, 867, 12265, 745, 1, 0, 9},
        {1561, "Netherspite", [[ A void dragon that, by some unknown means, found its way into Karazhan and took up residence in Medivh's observatory. A creature like this feels right at home in Karazhan, and it seems its might has only grown from its long proximity to this cursed castle. Opening portals to unknown reaches, Netherspite draws power from them, and it will surely attack with fury anyone who encroaches upon its lair. ]], 0.359484, 0.418462, 13, 867, 12240, 745, 1, 0, 10},
        {1562, "Nightbane", [[ Medivh's power was so great that with a mere effort of will he caused a blue dragon, Arcanagos, who had flown to the mage's tower, to literally burn from within. Now this unfortunate is known as Nightbane, a dragon skeleton forever wreathed in flame and bound to the place of his gruesome demise, doomed to return again and again.
The time has come to end his torment. ]], 0.471000, 0.923000, 6, 867, 12292, 745, 1, 0, 6},
        {1563, "Prince Malchezaar", [[ It is unknown how Prince Malchezaar, one of the highest eredar hierarchs, came to Karazhan, but it is plain what he was doing in this gloomy castle. The upper floor of Karazhan's tower, where Malchezaar can be found, is shrouded in darkness—reality itself has begun to change, merging with a strange place: the Nethervoid. Perhaps Malchezaar wished to turn Karazhan into an outpost for the further invasion of his legion into Azeroth; perhaps he was interested only in the dark secrets of the castle and the nature of its curse. In any case, the demon must be destroyed. ]], 0.514356, 0.309231, 17, 867, 12320, 745, 1, 0, 12},
        {11656, "Chess Event", [[ To begin the event, one must speak with the Shade of Medivh. As the game progresses, players can control various chess pieces representing the participants of the First War in Azeroth. Medivh sometimes does not play by the rules. If the raid wins the game, it may claim its loot after Medivh acknowledges his defeat. ]], 0.358000, 0.622000, 14, 867, 21159, 745, 1, 0, 11},
        {11002, "Attumen the Huntsman", [[ The Huntsman Attumen was a horse breeder renowned throughout the Alliance. Horses obeyed him as if he spoke their very language, and his steeds were bought for vast sums by the nobility of every kingdom. What ill fate brought the huntsman and his horse beneath the vaults of Karazhan, we will never know, for the cursed tower jealously guards its secrets, but what is beyond doubt is that Attumen has become far more bloodthirsty than he was in life. ]], 0.452819, 0.826154, 18, 867, 12041, 745, 4, 0, 1},
        {11003, "Moroes", [[ Moroes was an old man who lived in Karazhan, serving as Medivh's castellan. He knew of the visions shown by the castle's magic, but he sought to avoid them. Moroes perished at the hand of his maddened master and fell under the curse of Karazhan, which will forever raise him in undead form. He still tries to keep order in the castle and protect it from unwelcome guests. ]], 0.271280, 0.635385, 20, 867, 12060, 745, 4, 0, 2},
        {11004, "Maiden of Virtue", [[ A creation of the titans, embodying purity and strength of will, the Maiden of Virtue came to Karazhan, outraged by the vices and wickedness of its inhabitants. But the curse of this mysterious castle consumed her as well. Now the Maiden of Virtue is just as much a slave of Karazhan, forced to hopelessly root out vices only for them to appear anew. ]], 0.834384, 0.500042, 21, 867, 12109, 745, 4, 0, 3},
        {11005, "Opera Hall", [[ Karazhan is a vast castle, and what castle is complete without an opera hall? Barnes, the stage manager of the Opera, like the other inhabitants of Karazhan, is trapped in time, endlessly repeating his performances. But while the show is in progress, there is no passing through the opera hall. Perhaps one ought to take part in Barnes's production in order to proceed deeper into Karazhan?.. ]], 0.181023, 0.350770, 21, 867, 12123, 745, 4, 0, 4},
        {11006, "The Curator", [[ Karazhan is vast and full of treasures that thieves and adventurers of all kinds would surely love to lay their hands on. Arcane guardians, mighty golems brimming with magic, watch over the corridors of Karazhan, and the mightiest of them—the Curators—guard the gallery, barring further exploration of this cursed castle. ]], 0.494869, 0.366155, 26, 867, 12177, 745, 4, 0, 6},
        {11007, "Shade of Aran", [[ An echo of Medivh's father, the pale shadow of a once-great mage, wanders aimlessly through the library of Karazhan. The shade, having lost the last drops of its sanity in the eternal torment of the cursed castle, but having lost not a drop of its power, will readily take any uninvited guest of Karazhan to be the cause of its eternal suffering. ]], 0.716407, 0.260001, 27, 867, 12212, 745, 4, 0, 8},
    },
    [746] = {
        {11012, "King Mukla", [[ King Maulgar and his champions are the mightiest ogres of Outland and serve as Gruul's guard, watching over the lair. Each of these champions possesses their own unique abilities, and their combined strength can be matched only by the iron grip of Gruul. ]], 0.550255, 0.570769, 2, 864, 11981, 746, 8, 0, 0},
        {11013, "Gruul the Dragonkiller", [[ An enormous gronn, renowned as the Dragonkiller during the battle against Deathwing's black flight, who sought to hide the eggs of his flight in Blade's Edge Mountains. Dwelling within the vast cave of Gruul's Lair, he is himself a dire threat to any non-ogre in Blade's Edge Mountains. ]], 0.249486, 0.283077, 2, 864, 11960, 746, 8, 0, 1},
        {1564, "King Mukla", [[ King Maulgar and his champions are the mightiest ogres of Outland and serve as Gruul's guard, watching over the lair. Each of these champions possesses their own unique abilities, and their combined strength can be matched only by the iron grip of Gruul. ]], 0.550255, 0.570769, 1, 864, 11981, 746, 2, 0, 0},
        {1565, "Gruul the Dragonkiller", [[ An enormous gronn, renowned as the Dragonkiller during the battle against Deathwing's black flight, who sought to hide the eggs of his flight in Blade's Edge Mountains. Dwelling within the vast cave of Gruul's Lair, he is himself a dire threat to any non-ogre in Blade's Edge Mountains. ]], 0.199486, 0.283077, 1, 864, 11960, 746, 2, 0, 1},
    },
    [747] = {
        {11014, "Magtheridon", [[ Illidan helped Akama defeat the demons and orcs of Magtheridon, and together they stormed Hellfire Citadel. In the end, Magtheridon fell at the hand of Illidan. Or so it was believed… When Illidan struck down Magtheridon, the latter hovered on the threshold of life and death, but upon realizing this, Illidan decided to keep Magtheridon alive. He ordered his servants to hide Magtheridon's body in a cave, so that his burning blood could be used to sustain the demonic power of the orcs. Illidan's servants drain most of the demon's blood daily, which is why he lies in a coma. Should Magtheridon ever rise again, he would surely try to reclaim Outland for himself… ]], 0.691795, 0.743077, 1, 865, 11919, 747, 8, 0, 0},
        {1566, "Magtheridon", [[ Illidan helped Akama defeat the demons and orcs of Magtheridon, and together they stormed Hellfire Citadel. In the end, Magtheridon fell at the hand of Illidan. Or so it was believed… When Illidan struck down Magtheridon, the latter hovered on the threshold of life and death, but upon realizing this, Illidan decided to keep Magtheridon alive. He ordered his servants to hide Magtheridon's body in a cave, so that his burning blood could be used to sustain the demonic power of the orcs. Illidan's servants drain most of the demon's blood daily, which is why he lies in a coma. Should Magtheridon ever rise again, he would surely try to reclaim Outland for himself… ]], 0.691795, 0.743077, 1, 865, 11919, 747, 2, 0, 0},
    },
    [748] = {
        {1567, "Hydross the Unstable", [[ An enormous water elemental dwells in Serpentshrine Cavern, cleansing itself of the corruption that has afflicted it, as it has much of the elemental life of Outland, and helping to purify the lesser elementals. But despite all the naga's efforts, Hydross's condition remains unstable, and the moment he leaves the range of the machines built by the naga, the poison once again overwhelms him. ]], 0.363590, 0.847692, 1, 862, 700, 748, 2, 0, 0},
        {1568, "The Lurker Below", [[ Wondrous creatures inhabit Outland, and by no means do all of them dwell on the surface. In the deepest reaches of Serpentshrine Cavern lives a bizarre creature, akin to the krakens that dwell in the northern seas of Azeroth—the Lurker Below. Whoever disturbs the strange pool, the place where the naga feed the Lurker, awaits a most… unusual discovery. ]], 0.402564, 0.581538, 1, 862, 711, 748, 2, 0, 1},
        {1569, "Leotheras the Blind", [[ Leotheras was one of the five blood elves whom Illidan took as apprentices in order to make demon hunters of them. But the path of the demon hunter is not for the weak of body, and three of the five lost their lives. The weak-spirited Leotheras was destined for a far darker fate. Having passed through the ritual and gained an inner demon, Leotheras could not establish control over it and went mad. The spellbinders of Serpentshrine Cavern hold him in captivity, trying to restore his mind, but in vain, for two voices now forever sound in Leotheras's head—his own and the demon's. ]], 0.417949, 0.255385, 1, 862, 722, 748, 2, 0, 2},
        {1570, "Fathom-Lord Karathress", [[ Karathress leads the personal guard of Lady Vashj. A seasoned warrior and a cruel commander, Karathress has chosen three guards, each possessing unique abilities. Together they are the last line of defense of Serpentshrine Cavern, and they remain undefeated—for Karathress has a secret that one learns only just before death. ]], 0.504103, 0.176924, 1, 862, 738, 748, 2, 0, 3},
        {1571, "Morogrim Tidewalker", [[ Sea giants, mighty, malevolent, and as a rule dim-witted humanoids, are found on the forgotten isles of Azeroth, and they are typically hostile to all and sundry. Morogrim Tidewalker is an exception to this rule. It is unknown exactly how the naga convinced him to settle in Serpentshrine Cavern, but this giant now dwells here, along with the horde of murlocs that obey him. ]], 0.596410, 0.260001, 1, 862, 769, 748, 2, 0, 4},
        {1572, "Lady Vashj", [[ Azshara's chief handmaiden, who became a naga like her mistress, was sent to aid Illidan on his journey to destroy the Frozen Throne. And although her new master did not succeed, Lady Vashj followed him into Outland, where Illidan and the forces under his command hurried to fortify their positions in anticipation of the Legion's wrath. The mighty sea witch rules over Serpentshrine Cavern and is a fearsome foe even to the most seasoned of warriors. ]], 0.722563, 0.589231, 1, 862, 777, 748, 2, 0, 5},
        {11650, "Hydross the Unstable", [[ An enormous water elemental dwells in Serpentshrine Cavern, cleansing itself of the corruption that has afflicted it, as it has much of the elemental life of Outland, and helping to purify the lesser elementals. But despite all the naga's efforts, Hydross's condition remains unstable, and the moment he leaves the range of the machines built by the naga, the poison once again overwhelms him. ]], 0.359000, 0.799000, 2, 862, 20930, 748, 8, 0, 0},
        {11651, "Hydross the Unstable", [[ Deep at the bottom of the pool, in the mysterious branches of the underground caverns, fused with the rock, dwells a creature of monstrous size, made of spikes, venom, and chitin, known as Gorishi—no, Coilfang—known as Gor'lac. The most ancient creature of Zangarmarsh, whose mind has far surpassed the level of the primitive creatures inhabiting the reservoir. Only on rare occasions, lured by tempting prey, does the giant crab leave its lair and rise to the surface to drag its food down into the deep waters. Its appearance rouses the other predatory creatures of the underwater world—but a few of Lady Vashj's trusted overseers see to it that Gor'lac does not leave the depths for long.
Will there be a skilled fisherman with a rod strong enough to haul the ancient crab up from the depths? ]], 0.403000, 0.589000, 2, 862, 20998, 748, 8, 0, 1},
        {11652, "Leotheras the Blind", [[ Leotheras was one of the five blood elves whom Illidan took as apprentices in order to make demon hunters of them. But the path of the demon hunter is not for the weak of body, and three of the five lost their lives. The weak-spirited Leotheras was destined for a far darker fate. Having passed through the ritual and gained an inner demon, Leotheras could not establish control over it and went mad. The spellbinders of Serpentshrine Cavern hold him in captivity, trying to restore his mind, but in vain, for two voices now forever sound in Leotheras's head—his own and the demon's. ]], 0.417949, 0.255385, 2, 862, 20952, 748, 8, 0, 2},
        {11653, "Fathom-Lord Karathress", [[ Karathress leads the personal guard of Lady Vashj. A seasoned warrior and a cruel commander, Karathress has chosen three guards, each possessing unique abilities. Together they are the last line of defense of Serpentshrine Cavern, and they remain undefeated—for Karathress has a secret that one learns only just before death. ]], 0.504103, 0.176924, 2, 862, 21019, 748, 8, 0, 3},
        {11654, "Morogrim Tidewalker", [[ Sea giants, mighty, malevolent, and as a rule dim-witted humanoids, are found on the forgotten isles of Azeroth, and they are typically hostile to all and sundry. Morogrim Tidewalker is an exception to this rule. It is unknown exactly how the naga convinced him to settle in Serpentshrine Cavern, but this giant now dwells here, along with the horde of murlocs that obey him. ]], 0.596410, 0.260001, 2, 862, 21080, 748, 8, 0, 4},
        {11655, "Lady Vashj", [[ Azshara's chief handmaiden, who became a naga like her mistress, was sent to aid Illidan on his journey to destroy the Frozen Throne. And although her new master did not succeed, Lady Vashj followed him into Outland, where Illidan and the forces under his command hurried to fortify their positions in anticipation of the Legion's wrath. The mighty sea witch rules over Serpentshrine Cavern and is a fearsome foe even to the most seasoned of warriors. ]], 0.722563, 0.589231, 2, 862, 21113, 748, 8, 0, 5},
    },
    [749] = {
        {1573, "Al'ar", [[ A phoenix who traveled alongside Kael'thas, his faithful familiar, Al'ar has grown manifold in power since the day he and Kael'thas first laid eyes upon each other. Now he and his offspring serve their master, dwelling within Tempest Keep. ]], 0.501026, 0.587692, 1, 782, 806, 749, 2, 0, 0},
        {1574, "Void Reaver", [[ The Void Reaver, built by the demons of the Burning Legion subordinate to Kael'thas and improved by blood elf mechanics, uses tremendous physical strength and the might of arcane magic to guard the left wing of Tempest Keep. ]], 0.264075, 0.490686, 1, 782, 819, 749, 2, 0, 1},
        {1575, "High Astromancer Solarian", [[ A High Astromancer must possess a keen mind, knowledge of arcane magic, and the ability to gaze into the void without losing one's sanity. Solarian performs her duty flawlessly under the direction of Kael'thas, and over time the knowledge gained from the Void has been added to her abilities. Need it be said that this knowledge will be put to use in battle should the need arise? ]], 0.740000, 0.489230, 1, 782, 823, 749, 2, 0, 2},
        {1576, "Kael'thas Sunstrider", [[ The ruler of the blood elves, the last prince of this people, Kael'thas Sunstrider seized Tempest Keep and turned it into his stronghold with a single purpose—to gain control over the chaotic energies of the Twisting Nether, turning them into a power that will crush any foe and help his people slake their thirst for magic. ]], 0.500999, 0.138461, 1, 782, 836, 749, 2, 0, 3},
        {11573, "Al'ar", [[ A phoenix who traveled alongside Kael'thas, his faithful familiar, Al'ar has grown manifold in power since the day he and Kael'thas first laid eyes upon each other. Now he and his offspring serve their master, dwelling within Tempest Keep. ]], 0.501026, 0.587692, 1, 782, 1500, 749, 8, 0, 0},
        {11574, "Void Reaver", [[ The Void Reaver, built by the demons of the Burning Legion subordinate to Kael'thas and improved by blood elf mechanics, uses tremendous physical strength and the might of arcane magic to guard the left wing of Tempest Keep. ]], 0.264075, 0.490686, 1, 782, 1539, 749, 8, 0, 1},
        {11575, "High Astromancer Solarian", [[ A High Astromancer must possess a keen mind, knowledge of arcane magic, and the ability to gaze into the void without losing one's sanity. Solarian performs her duty flawlessly under the direction of Kael'thas, and over time the knowledge gained from the Void has been added to her abilities. Need it be said that this knowledge will be put to use in battle should the need arise? ]], 0.740000, 0.489230, 1, 782, 1559, 749, 8, 0, 2},
        {11576, "Kael'thas Sunstrider", [[ The ruler of the blood elves, the last prince of this people, Kael'thas Sunstrider seized Tempest Keep and turned it into his stronghold with a single purpose—to gain control over the chaotic energies of the Twisting Nether, turning them into a power that will crush any foe and help his people slake their thirst for magic. ]], 0.500999, 0.138461, 1, 782, 1604, 749, 8, 0, 3},
    },
    [753] = {
        {1597, "Archavon the Stone Watcher", [[ The weakest of the guardians in the Vault, Archavon the Stone Watcher is an enormous stone giant who commands the powers of earth. ]], 0.493350, 0.168738, 1, 532, 11475, 753, 3, 0, 0},
        {1598, "Emalon the Storm Watcher", [[ Emalon the Storm Watcher is a giant endowed with the powers of the storm. He and his tempest minions guard the Vault of Archavon. ]], 0.627193, 0.553059, 1, 532, 11489, 753, 3, 0, 1},
        {1599, "Koralon the Flame Watcher", [[ Koralon the Flame Watcher is one of the guardians of the Vault of Archavon, a mighty stone giant endowed with the powers of fire. ]], 0.363289, 0.551625, 1, 532, 11479, 753, 3, 0, 2},
        {1600, "Toravon the Ice Watcher", [[ Toravon the Ice Watcher is the mightiest of the guardians of the Vault of Archavon, a stone giant endowed with the powers of ice. ]], 0.627151, 0.363767, 1, 532, 11484, 753, 3, 0, 3},
    },
    [754] = {
        {1601, "Anub'Rekhan", [[ Anub'Rekhan is one of the nerubian lords, serving as the guardian of the Spider Wing in Naxxramas. ]], 0.306925, 0.469885, 2, 535, 11497, 754, 3, 0, 0},
        {1602, "Grand Widow Faerlina", [[ Once a talented alchemist, Grand Widow Faerlina is now one of the high-ranking members of the Cult of the Damned. Dwelling in the Spider Wing of Naxxramas, she instructs her acolytes in the dark arts. ]], 0.441725, 0.360899, 2, 535, 11504, 754, 3, 0, 1},
        {1603, "Maexxna", [[ A giant spider who has woven her web in one of the chambers of the Spider Wing of Naxxramas. As the object of worship of Faerlina and her cult, Maexxna increases the number of her brood day by day, keeping her venom just as deadly as before. ]], 0.686466, 0.152964, 2, 535, 11511, 754, 3, 0, 2},
        {1604, "Noth the Plaguebringer", [[ Just as Arthas heard the call of the Lich King, so too did Noth in his time join the Scourge in pursuit of power and might. During the Third War, however, Noth began to doubt what he had done, and the Lich King, without a second thought, froze the heart in his chest. Since then, Noth has known neither doubt nor mercy, and only death can stop him. ]], 0.346122, 0.564531, 4, 535, 11518, 754, 3, 0, 3},
        {1605, "Heigan the Unclean", [[ Heigan the Unclean, one of the necromancers who has devoted himself to the study and manipulation of the deadly plague itself, dwells in Naxxramas, improving and developing this new form of battle sorcery. In his arsenal are deadly spells, weakening curses, and surely a few more aces up his sleeve. ]], 0.498172, 0.456978, 4, 535, 11525, 754, 3, 0, 4},
        {1606, "Loatheb", [[ Sporewalkers are an exceptionally interesting species of creature, born of the marshes. But Loatheb is a singular specimen even among them. Strange mutations have led to his very presence spreading a necrotic aura that prevents any healing.
It was not long before the Cult of the Damned took an interest in him, and now Loatheb dwells in the Plague Wing of Naxxramas. ]], 0.760165, 0.283523, 4, 535, 11530, 754, 3, 0, 5},
        {1607, "Instructor Razuvious", [[ One of the senior death knights who remained loyal to the Lich King even after the rebellion of the Knights of the Ebon Blade. He now trains a new generation of death knights in the Military Wing of Naxxramas. ]], 0.427469, 0.459909, 3, 535, 11537, 754, 3, 0, 6},
        {1608, "Gothik the Harvester", [[ Gothik the Harvester is an expert in necromancy and dark magic, one of the few necromancers who can raise from the dead not only the body but also the soul, turning the deceased into spectral warriors. After the rebellion of the Knights of the Ebon Blade, he resides in the Military Wing of Naxxramas, instructing neophytes in the art of shadow magic. ]], 0.675078, 0.596142, 3, 535, 11545, 754, 3, 0, 7},
        {1609, "The Four Horsemen", [[ The mightiest death knights in Naxxramas are the Four Horsemen. They represent the pinnacle of Kel'Thuzad's guard. The first, Thane Korth'azz, wields the power of flame. The next, Lady Blaumeux, calls upon the power of shadow, drawing the souls of the living into an insatiable embrace. Sir Zeliek, a paladin loyal in life, so strong in his faith that even in undeath the power of the Light still heeds his call, smiting his foes in battle. The last death knight, Highlord Mograine, was the finest warrior the death knights had ever seen. However, after the events of Azeroth, he vanished without a trace. Kel'Thuzad appointed Baron Rivendare in his place. ]], 0.301273, 0.768225, 3, 535, 11606, 754, 3, 0, 8},
        {1610, "Patchwerk", [[ Patchwerk wants to play!
One of the most monstrous abominations ever created by the Scourge. Having survived the rebellion of the Knights of the Ebon Blade, Patchwerk proudly bears the title 'the Embodiment of War.' He now guards the corridors of the Construct Wing of Naxxramas. ]], 0.541192, 0.416887, 1, 535, 11622, 754, 3, 0, 9},
        {1611, "Grobbulus", [[ One of the would-be army of flesh giants, Grobbulus dwells in the Construct Wing of Naxxramas. A ghastly monster created by the army of the Scourge. The product of the twisted minds of the Scourge's brilliant engineers and surgeons. An enormous walking mutagen, steeped in poison, death, fear, and slime... vile slime. ]], 0.615762, 0.531547, 1, 535, 11626, 754, 3, 0, 10},
        {1612, "Gluth", [[ A colossal undead hound that devours the surplus zombies, dwelling in Naxxramas. The countless corpses consumed by this monster have endowed it with supernatural, unholy might. It now dwells in a sealed-off section of the Construct Wing of Naxxramas, and the only way to reach it is through the sewer pipes. ]], 0.462924, 0.438272, 1, 535, 11633, 754, 3, 0, 11},
        {1613, "Thaddius", [[ A monstrous giant of flesh, sealed with suffering, agonized souls that cry out for help even now, dwells in the Construct Quarter of Naxxramas. Necromancy and experiments with electricity turned this abomination to unlife, and woe to any who clash with a monster capable of incinerating its foes with a flash of lightning. ]], 0.265857, 0.145792, 1, 535, 11639, 754, 3, 0, 12},
        {1614, "Sapphiron", [[ Once a mighty servant of Malygos, a keeper of artifacts and an undefeated dragon of the blue flight, Sapphiron joined battle with Arthas during his journey to the Frozen Throne, and lost. Arthas sacrificed a significant portion of his power at the time to raise Sapphiron as a mighty frost wyrm, and broke through to Azjol-Nerub with his aid. Now this dragon guards the chambers of Kel'Thuzad, dwelling in the frost wyrm's lair in the Upper Necropolis of Naxxramas. ]], 0.565133, 0.675014, 6, 535, 11652, 754, 3, 0, 13},
        {1615, "Kel'Thuzad", [[ Kel'Thuzad is one of the Lich King's chief servants, responsible for spreading the plague of undeath across Lordaeron. After being slain by Arthas during the Third War, he was reborn as a lich. With Arthas's help he summoned Archimonde the Defiler, leader of the Burning Legion. Even so, Kel'Thuzad was truly loyal to the Lich King, and not at all to the Burning Legion. When Arthas departed for Northrend during the events surrounding the Frozen Throne, he left Kel'Thuzad behind as his deputy to command the Scourge in Lordaeron. Previously he ruled the Plaguelands from the necropolis Naxxramas, hovering above Stratholme, but now Naxxramas and, accordingly, Kel'Thuzad are located in the eastern part of Dragonblight, where he once again serves the Lich King. ]], 0.365324, 0.223293, 6, 535, 11660, 754, 3, 0, 14},
    },
    [755] = {
        {1616, "Sartharion", [[ The Guardian of the Obsidian Sanctum, whose task is to protect the clutch of the new generation of Deathwing's flight. ]], 0.505736, 0.477055, 0, 531, 11419, 755, 3, 0, 0},
    },
    [756] = {
        {1617, "Malygos", [[ Malygos, the Aspect of Magic, driven mad by grief and pain, has waged war against all who use magic, seeing in spellcasters only a source of chaos and ruin. In the Eye of Eternity, within the Nexus, he gathers the energy of Azeroth's ley lines, wishing to put an end once and for all to the threat of magic's excessive use. Your goal is to stop him. ]], 0.384321, 0.498566, 1, 527, 11449, 756, 3, 0, 0},
    },
    [757] = {
        {1618, "The Beasts of Northrend", [[  ]], 0.511514, 0.527373, 1, 543, 2450, 757, -1, 0, 0},
        {1619, "Lord Jaraxxus", [[  ]], 0.463713, 0.405480, 1, 543, 11000, 757, -1, 0, 1},
        {1620, "Champions of the Alliance", [[ The Alliance demands justice, and challenges you, champions of the Horde. Your opponents will be among the finest warriors of the Alliance to have fought in this tournament, but those who challenged the Horde shall fall. Lok'tar ogar! ]], 0.428340, 0.527373, 1, 543, 11059, 757, -1, 8, 2},
        {1621, "Champions of the Horde", [[ The Horde has dared to accuse the Alliance of scheming connected to the summoning of an eredar lord, and now demands justice, challenging you, champions of the Alliance. Your opponents will be the fiercest and most skilled warriors of the Horde, but they are no match for you, and must be destroyed. Glory to the Alliance! ]], 0.428340, 0.527373, 1, 543, 11201, 757, -1, 4, 2},
        {1622, "The Twin Val'kyr", [[  ]], 0.463713, 0.649266, 1, 543, 11016, 757, -1, 0, 3},
        {1623, "Anub'arak", [[  ]], 0.532546, 0.355289, 2, 543, 11038, 757, -1, 0, 4},
    },
    [758] = {
        {1624, "Lord Marrowgar", [[ The Lich King created Rebrad from the bones of thousands of lost adventurers, and now he guards the Frozen Throne at the foot of the Spire, filled with the power of the throne itself. ]], 0.391055, 0.593338, 1, 604, 11677, 758, -1, 0, 0},
        {1625, "Lady Deathwhisper", [[ Lady Deathwhisper fully replaced Kel'Thuzad after the fall of Naxxramas, becoming the rightful leader of the Cult of the Damned. Within Icecrown Citadel, she trains the most gifted and ambitious of the cultists, preparing from them a new magical guard for the Scourge. ]], 0.391055, 0.869980, 1, 604, 11683, 758, -1, 0, 1},
        {1626, "Icecrown Gunship Battle", [[  ]], 0.219927, 0.550191, 2, 604, 0, 758, -1, 4, 2},
        {1627, "Icecrown Gunship Battle", [[  ]], 0.690500, 0.550191, 2, 604, 0, 758, -1, 8, 2},
        {1628, "Deathbringer Saurfang", [[ A brave and powerful orc who fell at the hand of the Lich King at the Wrathgate, he was turned into a death knight and now guards the entrance to the inner sanctum of Icecrown Citadel. The Lich King granted him special power - the strength of Saurfang's blood possesses an incredible healing effect, allowing him to single-handedly hold back even an army, fighting to victory. ]], 0.515422, 0.216060, 0, 604, 11713, 758, -1, 0, 3},
        {1629, "Festergut", [[ One of the two giant abominations created by Professor Putricide. Endowed with significant physical strength and manipulating noxious gas, Festergut is a dangerous instrument of the Scourge. ]], 0.198978, 0.654874, 0, 604, 11726, 758, -1, 0, 4},
        {1630, "Rotface", [[ Professor Putricide's favorite. An abomination oozing corrosive, at times animated slime, and possessing significant physical strength, Rotface is a dangerous instrument of the Scourge. ]], 0.198978, 0.418259, 0, 604, 11733, 758, -1, 0, 5},
        {1631, "Professor Putricide", [[ They say genius sometimes borders on madness. Professor Putricide is a vivid example of this. A mad genius who created many strains of plague, the maker of abominations, the greatest alchemist who ever lived, Putricide dwells in the Plagueworks within Icecrown Citadel, and his ingenuity knows no end. ]], 0.131101, 0.532982, 0, 604, 11747, 758, -1, 0, 6},
        {1632, "Blood Prince Council", [[ Valanar, Keleseth, and Taldaram - the San'layn, three Blood Princes who were defeated at the hands of Azeroth's heroes, former blood elves who replaced the power of the Sunwell with the power of blood. Their bodies were carefully preserved and brought to the Crimson Hall of Icecrown Citadel, where they are destined to be resurrected and continue their eternal service. ]], 0.520160, 0.141491, 0, 604, 11779, 758, -1, 0, 7},
        {1633, "Blood-Queen Lana'thel", [[ During the battles on the frozen wastes of Northrend, Arthas triumphed over Illidan and Kael'thas, and the few survivors tried to flee from the Scourge. But the Lich King was determined to find every elf who had dared to challenge him. Then Lana'thel was driven into a corner and in desperation attacked Arthas, but could not withstand Frostmourne.

The Lich King raised Lana'thel and made her the leader of the San'layn - blood elves who oversaw the success of the Scourge's operation across the northern continent. Now Lana'thel resides in the Crimson Hall of Icecrown Citadel, and her power fuels the seal to the teleport atop the Frozen Throne. ]], 0.511599, 0.435467, 0, 604, 11792, 758, -1, 0, 8},
        {1634, "Valithria Dreamwalker", [[ One of the daughters of Ysera, a mighty dragon who fell captive to the Scourge. Held prisoner deep within the Frostwing Halls of Icecrown Citadel, Valithria is subjected to torture and will surely not be left alive if there is any risk of her release. Help her before it is too late! ]], 0.766814, 0.736678, 0, 604, 11808, 758, -1, 0, 9},
        {1635, "Sindragosa", [[ Sensing her approaching death, the blinded Sindragosa desperately wished for one thing - to reach Dragonblight and meet her end there, as many dragons had done before her. But the dragon's strength did not last long. Exhausted, she fell to the ground on the glacier of Icecrown. With her last strength, in a cry full of despair, Sindragosa called for her mate Malygos. The cold arctic winds were her only listeners. But she did not give up and called once more. The distance was too great. Realizing that her soul would never find peace in Dragonblight, she resigned herself to her fate. Life slowly drained from her, and her mind clouded.

In her delirium her final thoughts were filled with disappointment and hatred: hatred for the Legion, hatred for Neltharion, even hatred for Malygos. But more than all she came to hate the world of mortals...

And before her death Sindragosa swore vengeance.

The place where the mighty dragon met her end came to be called the Sindragosa's Fall.

Such was the life's journey of the Blue Dragon. However, as we all know, the story does not end there. Thousands of years later the mighty Lich King found Sindragosa and granted her the chance to fulfill her deadly oath. He made her the queen of the frost wyrms and settled her in the Frostwing Halls. Now Sindragosa carries out Arthas's bidding. In the Pit of Saron you may have witnessed her present might with your own eyes. ]], 0.366325, 0.231898, 0, 604, 11829, 758, -1, 0, 10},
        {1636, "The Lich King", [[ Upon awakening, the Lich King first removed his own heart, believing that everything that bound him to mortals made him weaker. He went to the Sindragosa's Fall and raised the ancient dragon Sindragosa, who had been Malygos's first consort, as a frost wyrm. After this he watched over his vast army of undead, ready for war. While their ruler slept, the death knights were trained within Icecrown. Upon awakening, he ordered them to march to the Chapel of the Last Hope, where thousands of Alliance heroes were buried, each of whom he wished to raise to his side, and then to seize these lands for the Scourge. Now he sits upon the Frozen Throne within Icecrown Citadel, and only his death can stop the Scourge's war machine from destroying all living things. ]], 0.499296, 0.528743, 0, 604, 11855, 758, -1, 0, 11},
        {1637, "Lady Jaina Proudmoore", [[ Atop Icecrown Citadel, a moment before the Lich King was to receive his killing blow, the history of this world changed. Lady Jaina Proudmoore cast aside the voice of reason and rose to defend the one she had once so loved. Arthas's fate now depends on whether the heroes of Azeroth can strike down not an embodiment of evil, but a fallen comrade. ]], 0.499296, 0.568743, 0, 604, 900, 758, 8, 0, 12},
    },
    [760] = {
        {1651, "Onyxia", [[ On the edge of the Dustwallow Marsh stands a cave that has become the final refuge of the cursed line of black dragons. Onyxia's Lair is the name of this refuge, and the number of black dragons grows slowly but surely with each passing day. This threat cannot be ignored. ]], 0.672370, 0.309886, 0, 718, 11400, 760, 3, 0, 0},
    },
    [761] = {
        {1652, "Halion", [[  ]], 0.491354, 0.535788, 0, 609, 1000, 761, -1, 0, 0},
    },
    [762] = {
        {11585, "Oggleflint", [[ Oggleflint and the troggs once ruled unchallenged in the depths of the Ragefire Chasm, until the cultists of the Burning Blade arrived there. Too weak to drive off the Burning Blade, Oggleflint and the troggs retreated to the upper levels of Ragefire Chasm, where they now wait patiently for their unwelcome guest. ]], 0.566000, 0.385000, 0, 680, 20001, 762, -1, 0, 1},
        {11586, "Taragaman the Hungerer", [[ Believed to be the leader of the Burning Blade, he hides in the fiery depths of Ragefire Chasm, using his demonic influence to corrupt the citizens of Orgrimmar. In truth the leaders of the Burning Blade are Bazzalan and Jergosh, and this Felguard is an expendable lure, meant to entice young Horde adventurers to their deaths. ]], 0.410000, 0.574000, 0, 680, 20002, 762, -1, 0, 2},
        {11587, "Bazzalan", [[ Bazzalan leads the cultists of the Burning Blade together with Jergosh the Invoker. His motives are unclear, but like all satyrs he is a swift and cunning foe.  ]], 0.420000, 0.861000, 0, 680, 20004, 762, -1, 0, 3},
        {11588, "Jergosh the Invoker", [[ Jergosh the Invoker rejected the ideals of the orcs and practices the dark and demonic arts of the warlock. The leader of the cultists of the Burning Blade, Jergosh dwells in the Ragefire Chasm, devising a scheme dangerous enough to draw the attention of Thrall himself. He guards a blood-filled orb that is needed to summon the most dangerous of demons. ]], 0.343000, 0.817000, 0, 680, 20006, 762, -1, 0, 7},
    },
    [763] = {
        {11589, "Interrogator Vishas", [[ Interrogator Vishas is a knight of the Scarlet Crusade and the order's leading interrogator. He delights in torturing any captured undead and takes pride in his work. Vishas is known for his relentless sadism, cruel experiments, and high-pitched voice. Interrogator Vishas tormented Vorrel Sengutz for weeks. Vishas took Sengutz's wedding ring and gave it to his own wife, Nancy Vishas. Nancy lives with Grandpa Vishas, who is presumably James's father, though this is not mentioned, in a cottage on the eastern shore of Lordamere Lake in the Alterac Mountains. ]], 0.719000, 0.594000, 0, 889, 20272, 763, -1, 0, 1},
        {11590, "Ironspine", [[ Ironspine is an elite rare skeleton mob of level 31 that dwells in the graveyard of the Scarlet Monastery. Lanky and seemingly fragile, these skeletons possess superhuman strength and are highly resistant to most physical attacks. ]], 0.517000, 0.675000, 0, 889, 20274, 763, -1, 0, 1},
        {11591, "Fallen Champion", [[ Once a holy paladin of the Scarlet Monastery, the Fallen Champion was a champion of the Scarlet Crusade, later slain and then raised as a servant of the Lich King. He wanders the graveyard, still wielding the armor and weapons he used in life, but since the undead cannot wield the powers of the Holy Light, he became a warrior. ]], 0.355000, 0.664000, 0, 889, 20276, 763, -1, 0, 1},
        {11592, "Bloodmage Thalnos", [[ Bloodmage Thalnos is an elite skeleton mini-boss, found in the graveyard of the Scarlet Monastery, right beneath the stairs at the far end of the graveyard itself. ]], 0.243000, 0.560000, 0, 889, 20278, 763, -1, 0, 1},
    },
    [764] = {
        {11593, "High Inquisitor Fairbanks", [[ Fairbanks was a trusted advisor to Highlord Mograine and was present at the meeting in Southshore that led to the creation of the Ashbringer.

Fairbanks and Highlord Mograine were betrayed by his son Renault in Stratholme, where the legions of the Scourge awaited them. Fairbanks fell first but did not die, finding himself trapped, hidden beneath the corpses of the undead. He was a silent witness to Renault's betrayal, hearing Mograine's agonized cries as the Ashbringer pierced his heart and grazed the blade. Kel'Thuzad later raised Mograine as a death knight.

Returning to the Scarlet Monastery, Fairbanks told the tale of the betrayal to all who would listen. Those who believed him left the Crusade to found the Argent Dawn. Afterward Fairbanks was killed by the remaining crusaders for blasphemy and, possibly, for showing symptoms of the plague. His body was cast into a secret room of the Scarlet Cathedral. ]], 0.553000, 0.256000, 0, 940, 20282, 764, -1, 0, 1},
        {11594, "Scarlet Commander Mograine", [[ Scarlet Commander Mograine is a young commander of the Scarlet Crusade's armed forces at the Scarlet Monastery. He is an elite level 40 paladin boss, found in the Crusaders' Chapel within the Cathedral of the Scarlet Monastery. ]], 0.492000, 0.271000, 0, 940, 20288, 764, -1, 0, 1},
        {11595, "High Inquisitor Whitemane", [[ High Inquisitor Sally Whitemane is a priestess of the Light and High Inquisitor of the Scarlet Crusade. She directs their activities from the cathedral of the Scarlet Monastery. At a young age Sally witnessed her family perish to the horrific plague of undeath. From that day the dread priestess found satisfaction and pleasure in only one thing: in purging and destroying the undead. ]], 0.490000, 0.168000, 0, 940, 20292, 764, -1, 0, 1},
    },
    [765] = {
        {11596, "Houndmaster Loksey", [[ Houndmaster Loksey is one of the four leaders of the Scarlet Monastery and the captain in charge of training the hounds that the Scarlet Crusade uses to track down its enemies. Loksey commands fearsome dogs that can tear their prey apart in mere minutes. ]], 0.293000, 0.837000, 0, 938, 20298, 765, -1, 0, 1},
        {11597, "Arcanist Doan", [[ He is the keeper of the monastery's library, the guardian of a secret that, rumor has it, the Scarlet Crusade does not trust him with. Nevertheless, he is indeed a trusted figure of the Crusade, holding a vital key that grants access to the Scarlet Crusade's operations in the Plaguelands. Arcanist Doan believes that arcane magic is the only way to rid Lordaeron of the Scourge. ]], 0.833000, 0.742000, 0, 938, 20300, 765, -1, 0, 1},
    },
    [766] = {
        {11598, "Herod", [[ The Scarlet Crusade has a great many tools at its disposal for combating the undead. The novices must first be taught to handle blades and hammers, arrows and shields. Herod has devoted his whole life to the art of fighting with these devastating instruments, and is eager to demonstrate his mastery to the order's unholy foes. ]], 0.786000, 0.104000, 0, 939, 20305, 766, -1, 0, 1},
    },
    [767] = {
        {11599, "Kirtonos the Herald", [[ He has long been a master of the Scholomance. Responsible for many atrocities during Krastinov's reign over the Scholomance, Kirtonos fed on the blood of his innocent victims. To appease his master, Doctor Krastinov had to supply the gargoyle with ever-greater quantities of blood. ]], 0.497000, 0.101000, 2, 890, 20309, 767, -1, 0, 0},
        {11600, "Jandice Barov", [[ Jandice Barov is a human ghost mini-boss found in the Scholomance in a secret room. She is a member of the ill-fated Barov family. They were an extremely wealthy family in Lordaeron, owning land that included Caer Darrow and many others. ]], 0.541000, 0.144000, 3, 890, 20317, 767, -1, 0, 1},
        {11601, "Rattlegore", [[ Rattlegore is a bone golem boss in the Scholomance. After being defeated by the Alliance during the battle for Andorhal, he was recreated from bones within the Scholomance in the main crypt.  ]], 0.321000, 0.650000, 3, 890, 20319, 767, -1, 0, 2},
        {11602, "Ras Frostwhisper", [[ Ras Frostwhisper is a lich of the Scourge and overseer of all that takes place in the Scholomance. He observed and taught all who rose to the rank of Dark Master. He was a lieutenant and favored pupil of Kel'Thuzad. Ras Frostwhisper was once a human mage from Stromgarde. He was a hedge mage, a self-taught wizard who never received formal training in Dalaran. ]], 0.405000, 0.815000, 4, 890, 20322, 767, -1, 0, 5},
        {11603, "Doctor Theolen Krastinov", [[ Known as "the Butcher," Krastinov was a servant of Kirtonos the Herald and the chief torturer and supplier of bodies and body parts for the necromantic experiments in the Scholomance. His first victims were recruited from the family of Caer Darrow. ]], 0.888000, 0.462000, 3, 890, 20328, 767, -1, 0, 7},
        {11604, "Marduk Blackpool", [[ Marduk Blackpool, also known as Marduk the Black, was a notorious death knight of the Scourge. He was perhaps best known for his role in the battle of Darrowshire during the Third War, where he sealed the humans' defeat by corrupting the spirit of Joseph Redpath. Some time later Marduk retired to the Scholomance. ]], 0.442000, 0.644000, 2, 890, 20331, 767, -1, 0, 3},
        {11605, "Vectus", [[ Vectus is a skeletal mage mini-boss and one of the chief teachers of necromancy in the Scholomance. Vectus raised the tortured flight of dragons dwelling in the Scholomance, which he obtained by paying coin to Tinkee Steamboil in the Burning Steppes for eggs from Blackrock Spire. ]], 0.486000, 0.658000, 2, 890, 20335, 767, -1, 0, 4},
        {11606, "Lorekeeper Polkelt", [[ Polkelt is one of the six mini-bosses needed to summon Gandling. As we can judge from his name, he was once a keeper of lore, lore that, sadly, has been lost, for now he is a clumsy, mindless monster. ]], 0.723000, 0.220000, 3, 890, 20339, 767, -1, 0, 8},
        {11607, "Instructor Malicia", [[ Instructor Malicia is a high elf instructor who trains the cultists in the Scholomance. ]], 0.726000, 0.700000, 3, 890, 20343, 767, -1, 0, 6},
        {11608, "Lady Illucia Barov", [[ Lady Illucia Barov is a ghost mini-boss found in the Scholomance. She was the wife of Lord Alexei Barov and one of the six mini-bosses who must be killed to summon the Darkmaster Gandling. ]], 0.675000, 0.141000, 4, 890, 20348, 767, -1, 0, 11},
        {11609, "Lord Alexei Barov", [[ Lord Alexei Barov was the lord of Caer Darrow, Brill, Tarren Mill, and Southshore. He was the father of Alexi, Weldon, and Jandice Barov and the husband of Lady Illucia Barov. Like Jandice and Illucia, he is now an agent of the Scourge in the Scholomance. Alexei Barov is one of the six bosses who must be defeated to summon the Darkmaster Gandling. He also guards the deeds to Caer Darrow. ]], 0.791000, 0.300000, 4, 890, 20353, 767, -1, 0, 10},
        {11610, "The Ravenian", [[ The Ravenian is an unusual kind of undead. It is unknown how this transformation came about. There is a rumor that the Ravenian devours the students of the Scholomance who do not show diligence in their studies. In addition, the Ravenian is one of the six bosses who must be defeated to summon the Darkmaster Gandling. ]], 0.673000, 0.477000, 4, 890, 20356, 767, -1, 0, 9},
        {11611, "Darkmaster Gandling", [[ Darkmaster Gandling is the final boss in the Scholomance. His teacher of necromancy was Ras Frostwhisper. Gandling is the headmaster of the School of Necromancy at Caer Darrow, appointed personally by Kel'Thuzad. ]], 0.681000, 0.302000, 4, 890, 20360, 767, -1, 0, 12},
    },
    [771] = {
        {11623, "\"Flame Leviathan\"", [[ The entrance to the inner courtyard of Ulduar is guarded by a huge armored tank. Keeper Mimiron built the "Flame Leviathan" as part of the weapons platform "V-0-7 TR0N". ]], 0.491000, 0.389000, 1, 529, 20484, 771, -1, 0, 0},
        {11624, "Ignis the Furnace Master", [[ Like the other titan creations in Ulduar, Ignis now bends to the will of the Old God Yogg-Saron. This imposing fire giant dwells in the Colossal Forge and crafts armies of iron warriors meant to subjugate Azeroth, in the name of Yogg-Saron. ]], 0.383000, 0.266000, 1, 529, 20534, 771, -1, 0, 1},
        {11625, "Razorscale", [[ Veranus, mother of the proto-dragon flight of the Storm Peaks, served the keeper Thorim until Loken captured her, turning her into a fearsome weapon. Ignis the Forgemaster reinforced the dragon's scales with iron plating, making Razorscale even deadlier. ]], 0.541000, 0.268000, 1, 529, 20545, 771, -1, 0, 2},
        {11626, "XT-002 Deconstructor", [[ Mimiron designed this autonomous mechanism to guard Ulduar's scrapyard and endowed it with the rudiments of intelligence needed to carry out its simple duties. XT-002 considers itself the keeper's son and, as befits a petulant child, sometimes throws a tantrum. ]], 0.485000, 0.145000, 1, 529, 20566, 771, -1, 0, 3},
        {11627, "The Assembly of Iron", [[ At the head of Loken's iron legions stand three stern generals, each representing one of the titan-forged races. Stormcaller Brundir, runemaster Molgeim, and the giant Steelbreaker serve the one who truly commands the keeper - the sinister Yogg-Saron. ]], 0.154000, 0.568000, 2, 529, 20587, 771, -1, 0, 4},
        {11628, "Kologarn", [[ Loken ordered Ignis the Forgemaster to forge this giant to defend the Antechamber. With his enormous arms Kologarn can crush any who attempt to enter the inner sanctum of Ulduar. ]], 0.373000, 0.126000, 2, 529, 20607, 771, -1, 0, 5},
        {11629, "Auriaya", [[ The archivist of Ulduar wanders the Observation Ring in the company of feral cats. The long years spent in solitude broke Auriaya, and the growing influence of the Old God ultimately robbed her of her sanity. ]], 0.511000, 0.569000, 3, 529, 20619, 771, -1, 0, 6},
        {11630, "Hodir", [[ Hodir once presided over the Temple of Winter, commanding the snow giants of the Storm Peaks. Now this keeper dwells in an icy cavern in the Halls of Winter, and his mind is subject to the will of Yogg-Saron. ]], 0.667000, 0.637000, 3, 529, 20632, 771, -1, 0, 7},
        {11631, "Thorim", [[ For years Thorim believed that the giants had killed his beloved wife Sif. Loosing his wrath upon his allies, he fell into despair. When Thorim learned that his brother Loken stood behind the crime, Loken imprisoned the keeper in Ulduar, where the Old God clouded his mind. ]], 0.718000, 0.484000, 3, 529, 20656, 771, -1, 0, 8},
        {11632, "Freya", [[ Keeper Freya was the protector of all living things, and three faithful Elders aided her in this. And although her conservatory is still overrun by rampant growth, her mind could not withstand the whispers of the Old God. ]], 0.533000, 0.230000, 3, 529, 20711, 771, -1, 0, 9},
        {11633, "Mimiron", [[ A brilliant inventor, Mimiron throughout the history of Azeroth designed many mechanisms that to this day inspire awe and admiration. But having fallen under Loken's influence, this keeper of Ulduar began to create only machines of war. ]], 0.436000, 0.414000, 5, 529, 20752, 771, -1, 0, 10},
        {11634, "General Vezax", [[ Strange beings called the faceless dwell in the depths of Ulduar. One of their overlords, General Vezax, guards the winding corridors that lead to Yogg-Saron's prison. ]], 0.569000, 0.605000, 4, 529, 20793, 771, -1, 0, 11},
        {11635, "Yogg-Saron", [[ A waking dream, the Beast of your nightmares, the Demon with a thousand faces.
All must bow before the will of the master. Your pitiful efforts only make him stronger... ]], 0.681000, 0.401000, 4, 529, 20805, 771, -1, 0, 12},
        {11636, "Algalon the Observer", [[ After Loken's death, a warning was sent to the Pantheon that Azeroth had lost its Prime Designate. Soon Algalon the Observer arrived on Azeroth, whose task was to detect signs of the planet's corruption. If necessary, the constellar would initiate the re-origination process, as a result of which all the world's inhabitants would perish. ]], 0.788000, 0.466000, 2, 529, 20863, 771, -1, 0, 13},
    },
}
