    [1539] = {1539, "Phase 1: Warden of the Void", [[ The Void Reaver enters battle protected by the defensive "Void Matrix" system. Periodically it must recharge, and during this time it is vulnerable. The phase continues until all "Void Crucibles" are discharged, or until the Void Reaver's health drops to 50%. ]], 0, 0, 0, 11574, 1549, 1540, 0, 0, 0, 1, 2, 12, 0},
