    [1541] = {1541, "Arcane Sphere", [[ The void crucible generator vents excess energy as an orb that pursues the most distant enemy. The orb explodes upon contact with any enemy or another orb. ]], 0, 0, 308466, 11574, 1545, 1542, 1539, 0, 0, 3, 2, 12, 0},
