    [1546] = {1546, "Arcane Mark", [[ Marks 4 enemies with an arcane sign. After 8 sec., the sign activates, dealing $[4 49469$]$[2 46560$]$[1 12000$] Arcane damage, and attempts to spread to all enemies within 15 yards. ]], 0, 0, 308471, 11574, 1547, 0, 1539, 0, 0, 8, 2, 12, 0},
    [1547] = {1547, "Recharge", [[ The Void Reaver rushes to the nearest Void Crucible and begins recharging from it. While in this state, it cannot move but can attack. The damage it takes is increased by 50%, and every 2 sec. it releases a wave of arcane energy dealing $[4 4946$]$[2 4656$]$[1 1200$] Arcane damage to all enemies. ]], 0, 0, 308473, 11574, 0, 1548, 1539, 0, 0, 9, 2, 12, 0},
    [1548] = {1548, "Arcane Cannon", [[ The Void Reaver activates its built-in armament, striking an enemy with a shot from its arcane cannon, dealing $[4 32980$]$[2 31040$]$[1 8000$] Arcane damage and increasing the Arcane damage the target takes by 50%. Stacks up to 10 times. ]], 0, 0, 308475, 11574, 0, 0, 1547, 0, 0, 10, 2, 12, 0},
    [1549] = {1549, "Phase 2: Protocol of Retribution", [[ The Void Matrix shuts down due to system overload, triggering the "Retaliation Protocol", which empowers the Void Reaver as it takes damage. Overloaded "Void Crucibles" empower all subsequent "Arcane Orbs". ]], 0, 0, 0, 11574, 0, 1550, 0, 0, 0, 11, 2, 12, 0},
