    [1559] = {1559, "Phase 1: High Astromancer", [[ Solarian enters battle, attacking enemies with arcane and holy magic. The High Astromancer holds her position and does not pursue enemies. Phase 1 ends after the High Astromancer's health drops to 30% or after gaining 100 stacks of the "Power of the Void" effect. ]], 0, 0, 0, 11575, 1587, 1560, 0, 0, 0, 1, 2, 12, 0},
    [1560] = {1560, "Void Gate", [[ The chaotic energy of the Twisting Nether seeping into the Tempest Keep leads to the opening of a portal to the Void, from which dark energy begins to flow toward Solarian. The energy flow focuses on any being with sufficient willpower that stands in the path between the Gate and Solarian. The Void Gate grants its target 1 stack of "Power of the Void" every 2 sec. ]], 0, 0, 308540, 11575, 1570, 1561, 1559, 0, 0, 2, 2, 12, 0},
