    [12123] = {12123, "\"Red Riding Hood\\\"", [[ The performances in the Opera of Karazhan change.

Let us imagine for a moment that this quiet old woman is awaiting a visit from her granddaughter... Surely the sight of this sweet gray-haired lady would not frighten you? ]], 0, 0, 0, 1556, 12128, 12124, 0, 1, 0, 1, 0, 3, 0},
