    [21054] = {21054, "Tidal Surge", [[ The Power of the Waters crashes down on enemies within 8 yards, dealing $[4 5400$]$[2 23280$]$[1 6000$] Frost damage and slowing their movement speed by 50% for 6 sec, as well as creating a "Pure Water" area that deals $[4 9000$]$[2 38800$]$[1 10000$] Frost damage every 2 sec. The size of the area grows with the number of targets struck by "Tidal Wrath". ]], 0, 0, 309281, 11653, 21057, 21055, 0, 0, 34, 2, 2, -1, 0},
