    [21063] = {21063, "Ruinous Strike", [[ Karathress ends his series of "World Breaker" attacks with a monstrous blow to his current enemy, dealing 105000 physical damage and reducing the effectiveness of healing received by the target by 95% for 80 sec. This blow always hits the target; it cannot be dodged or parried. ]], 0, 0, 309288, 11653, 0, 0, 0, 0, 17, 2, 2, -1, 0},
