    [21066] = {21066, "Gliding Charge", [[ Karathress becomes fully invulnerable, increasing his movement speed by 100% and beginning to pursue the most distant enemy. Any foe in his path is struck by a "Glancing Blow". Upon reaching his target, Karathress rushes toward the next most distant enemy. ]], 0, 0, 309292, 11653, 21067, 0, 0, 0, 32, 2, 2, -1, 0},
