    [21080] = {21080, "Phase 1: \\\"May the depths of the waves swallow you!\\\"", [[ The giant begins the fight fighting in melee, defending himself with his sturdy scales and using area-of-effect attacks. ]], 0, 0, 0, 11654, 21093, 21081, 0, 0, 0, 2, 2, -1, 0},
    [21081] = {21081, "Giant's Cunning", [[ The sea giant keeps a close watch on all his enemies besides his main target. Melee attacks trigger the "Watchful Gaze" effect. ]], 0, 0, 310135, 11654, 21083, 21082, 0, 1, 32, 2, 2, -1, 0},
    [21082] = {21082, "Piercing Gaze", [[ The giant watches you closely. At 10 stacks, Morogrim will perform a "Monstrous Blow" on another player rather than his current target. ]], 0, 0, 310136, 11654, 0, 0, 0, 1, 32, 2, 2, -1, 0},
