    [21085] = {21085, "Tough Hide", [[ The sea giant's hide is resistant to most forms of magical and ranged attacks. The damage he takes from enemies specializing in ranged combat or from enemy casters is reduced by 30%. ]], 0, 0, 310139, 11654, 21086, 0, 0, 1, 0, 2, 2, -1, 0},
    [21086] = {21086, "Crushing Stomp", [[ The sea giant shakes the ground, dealing 16000 physical damage to enemies within 10 yards, as well as 10000 Frost damage to all enemies beyond 10 yards, every 1 sec for 3 sec. ]], 0, 0, 310140, 11654, 21087, 0, 0, 1, 4, 2, 2, -1, 0},
    [21087] = {21087, "Giant's Grasp", [[ Morogrim seizes the enemy that is his current target, squeezing it in an attempt to crush it, dealing 50000 physical damage every 1 sec for 3 sec, after which he hurls it (or its remains) toward the water pool. If the target reaches the water's surface, it will summon Blind Murlocs at the point of landing. Completely resets the threat the target generates toward Morogrim. ]], 0, 0, 310143, 11654, 21089, 21088, 0, 1, 5, 2, 2, -1, 0},
