    [21089] = {21089, "Deep Murloc", [[ A small but dangerous melee fighter who is blind and attacks only those enemies who are a short distance from it.
Capable of smelling blood and finding enemies this way. When enraged, it sharpens its perception and attacks the nearest foe, wherever it may be. ]], 31538, 0, 0, 11654, 0, 21090, 0, 1, 0, 2, 2, -1, 200034},
